CREATE OR REPLACE FUNCTION "app_auth"."app_metadata"() RETURNS "jsonb"
    LANGUAGE "sql"
    SET "search_path" TO 'app_auth', 'public'
    AS $$
  select (current_setting('request.jwt.claims')::jsonb ->> 'app_metadata')::jsonb
$$;


ALTER FUNCTION "app_auth"."app_metadata"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "app_auth"."user_metadata"() RETURNS "jsonb"
    LANGUAGE "sql"
    SET "search_path" TO 'app_auth', 'public'
    AS $$
  select (current_setting('request.jwt.claims')::jsonb ->> 'user_metadata')::jsonb
$$;


ALTER FUNCTION "app_auth"."user_metadata"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."delete_users_data"("uid" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'private'
    AS $$
    BEGIN
        update auth.users set raw_user_meta_data = null where id = uid;
        return 'OK';
    END;
$$;


ALTER FUNCTION "private"."delete_users_data"("uid" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."generate_auth_users_insert_from_existing"("test_email" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'private', 'auth', 'public', 'pg_catalog'
    AS $$
DECLARE
    user_record auth.users%ROWTYPE;
BEGIN
    SELECT * INTO user_record 
    FROM auth.users 
    WHERE email = test_email;

    RETURN format(
        'INSERT INTO auth.users (
            instance_id, id, aud, "role", email, encrypted_password, 
            email_confirmed_at, invited_at, confirmation_token, 
            confirmation_sent_at, recovery_token, recovery_sent_at,
            email_change_token_new, email_change, email_change_sent_at,
            last_sign_in_at, raw_app_meta_data, raw_user_meta_data,
            is_super_admin, created_at, updated_at, phone,
            phone_confirmed_at, phone_change, phone_change_token,
            phone_change_sent_at, email_change_token_current,
            email_change_confirm_status, banned_until,
            reauthentication_token, reauthentication_sent_at,
            is_sso_user, deleted_at, is_anonymous
        ) VALUES (
            %L::uuid, %L::uuid, %L, %L, %L, %L,
            %L, %L, %L,
            %L, %L, %L,
            %L, %L, %L,
            %L, %L::jsonb, %L::jsonb,
            %L, %L, %L, %L,
            %L, %L, %L,
            %L, %L,
            %L, %L,
            %L, %L,
            %L, %L, %L
        );',
        user_record.instance_id,
        user_record.id,
        user_record.aud,
        user_record.role,
        user_record.email,
        user_record.encrypted_password,
        user_record.email_confirmed_at,
        user_record.invited_at,
        user_record.confirmation_token,
        user_record.confirmation_sent_at,
        user_record.recovery_token,
        user_record.recovery_sent_at,
        user_record.email_change_token_new,
        user_record.email_change,
        user_record.email_change_sent_at,
        user_record.last_sign_in_at,
        user_record.raw_app_meta_data,
        user_record.raw_user_meta_data,
        user_record.is_super_admin,
        user_record.created_at,
        user_record.updated_at,
        user_record.phone,
        user_record.phone_confirmed_at,
        user_record.phone_change,
        user_record.phone_change_token,
        user_record.phone_change_sent_at,
        user_record.email_change_token_current,
        user_record.email_change_confirm_status,
        user_record.banned_until,
        user_record.reauthentication_token,
        user_record.reauthentication_sent_at,
        user_record.is_sso_user,
        user_record.deleted_at,
        user_record.is_anonymous
    );
END;
$$;


ALTER FUNCTION "private"."generate_auth_users_insert_from_existing"("test_email" "text") OWNER TO "postgres";


