CREATE OR REPLACE FUNCTION "private"."generate_user_inserts"("email_list" "text"[]) RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'private', 'public'
    AS $$
DECLARE
    result text := '';
    user_record record;
BEGIN
    -- Drop trigger command
    result := 'DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;';

    FOR user_record IN 
        SELECT 
            l.id, 
            l.email, 
            l.encrypted_password,
            l.raw_user_meta_data,
            (l.raw_user_meta_data->>'principaladdresssiteoid')::integer as principaladdresssiteoid,
            p.property_address_street,
            p.property_address_suburb,
            p.property_address_postcode,
            p.property_rented,
            p.sign_posted,
            p.phone,
            p.mobile_reception,
            p.residents0_18,
            p.residents19_50,
            p.residents51_70,
            p.residents71_,
            p.vulnerable_residents,
            p.number_dogs,
            p.number_cats,
            p.number_birds,
            p.number_other_pets,
            p.live_stock_present,
            p.live_stock_safe_area,
            p.share_livestock_safe_area,
            p.static_water_available,
            p.have_stortz,
            p.stortz_size,
            p.fire_fighting_resources,
            p.site_hazards,
            p.other_site_hazards,
            p.fire_hazard_reduction,
            p.land_adjacent_hazard,
            p.other_hazards,
            p.truck_access_other_information,
            p.truck_access,
            p.other_essential_assets,
            EXISTS (
                SELECT 1 
                FROM public.property_profile pp 
                WHERE pp.principaladdresssiteoid = (l.raw_user_meta_data->>'principaladdresssiteoid')::integer
            ) as property_exists
        FROM private.load_users l
        LEFT JOIN private.load_profile p ON p.id = l.id
        WHERE l.email = ANY(email_list)
    LOOP
        -- If property doesn't exist, create it
        IF NOT user_record.property_exists THEN
            result := result || format(
                'WITH spatial_data AS (
                    SELECT 
                        c.id as community_id,
                        k.id as kyng_id
                    FROM 
                        public.community_areas c,
                        public.kyng_areas k
                    WHERE 
                        extensions.ST_Intersects(
                            (SELECT extensions.ST_Collect(geom) 
                             FROM public.project_addresspoints 
                             WHERE principaladdresssiteoid = %L),
                            c.geom
                        )
                        AND
                        extensions.ST_Intersects(
                            (SELECT extensions.ST_Collect(geom) 
                             FROM public.project_addresspoints 
                             WHERE principaladdresssiteoid = %L),
                            k.geom
                        )
                )
                INSERT INTO public.property_profile (
                    id,
                    property_address_street,
                    property_address_suburb,
                    property_address_postcode,
                    property_rented,
                    sign_posted,
                    phone,
                    mobile_reception,
                    residents0_18,
                    residents19_50,
                    residents51_70,
                    residents71_,
                    vulnerable_residents,
                    number_dogs,
                    number_cats,
                    number_birds,
                    number_other_pets,
                    live_stock_present,
                    live_stock_safe_area,
                    share_livestock_safe_area,
                    static_water_available,
                    have_stortz,
                    stortz_size,
                    fire_fighting_resources,
                    site_hazards,
                    other_site_hazards,
                    fire_hazard_reduction,
                    land_adjacent_hazard,
                    other_hazards,
                    truck_access_other_information,
                    truck_access,
                    other_essential_assets,
                    created_at,
                    last_updated,
                    principaladdresssiteoid,
                    kyng,
                    community
                )
                SELECT
                    public.gen_random_uuid(),
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, %L, %L,
                    %L, NOW(), NOW(),
                    %L,
                    kyng_id,
                    community_id
                FROM spatial_data;',
                user_record.principaladdresssiteoid,
                user_record.principaladdresssiteoid,
                user_record.property_address_street,
                user_record.property_address_suburb,
                user_record.property_address_postcode,
                user_record.property_rented,
                user_record.sign_posted,
                user_record.phone,
                user_record.mobile_reception,
                user_record.residents0_18,
                user_record.residents19_50,
                user_record.residents51_70,
                user_record.residents71_,
                user_record.vulnerable_residents,
                user_record.number_dogs,
                user_record.number_cats,
                user_record.number_birds,
                user_record.number_other_pets,
                user_record.live_stock_present,
                user_record.live_stock_safe_area,
                user_record.share_livestock_safe_area,
                user_record.static_water_available,
                user_record.have_stortz,
                user_record.stortz_size,
                user_record.fire_fighting_resources,
                user_record.site_hazards,
                user_record.other_site_hazards,
                user_record.fire_hazard_reduction,
                user_record.land_adjacent_hazard,
                user_record.other_hazards,
                user_record.truck_access_other_information,
                user_record.truck_access,
                user_record.other_essential_assets,
                user_record.principaladdresssiteoid
            );
        END IF;

        -- Insert into auth.users
        result := result || format(
            'INSERT INTO auth.users (
                instance_id, id, aud, role, email, encrypted_password,
                email_confirmed_at, invited_at, confirmation_token, confirmation_sent_at,
                recovery_token, recovery_sent_at, email_change_token_new, email_change,
                email_change_sent_at, last_sign_in_at, raw_app_meta_data, raw_user_meta_data,
                is_super_admin, created_at, updated_at, phone, phone_confirmed_at,
                phone_change, phone_change_token, phone_change_sent_at,
                email_change_token_current, email_change_confirm_status,
                banned_until, reauthentication_token, reauthentication_sent_at,
                is_sso_user, deleted_at, is_anonymous
            ) VALUES (
                %L, %L, %L, %L, %L, %L,
                NOW(), NULL, %L, NOW(),
                %L, NULL, %L, %L,
                NULL, NOW(),
                %L::jsonb,
                %L::jsonb,
                NULL, NOW(), NOW(),
                NULL, NULL, %L, %L, NULL,
                %L, 0, NULL, %L, NULL,
                false, NULL, false
            );',
            '00000000-0000-0000-0000-000000000000'::uuid,
            user_record.id,
            'authenticated',
            'authenticated',
            user_record.email,
            user_record.encrypted_password,
            '',
            '',
            '',
            '',
            '{"provider": "email", "providers": ["email"]}'::jsonb,
            jsonb_build_object(
                'sub', user_record.id,
                'email', user_record.email,
                'email_verified', true,
                'phone_verified', false,
                'principaladdresssiteoid', user_record.principaladdresssiteoid
            ),
            '',
            '',
            '',
            ''
        );

        -- Insert into auth.identities with provider_id
        result := result || format(
            'INSERT INTO auth.identities (
                id, user_id, provider_id, identity_data, provider, created_at, updated_at
            ) VALUES (
                %L, %L, %L, %L, %L, NOW(), NOW()
            );',
            user_record.id,
            user_record.id,
            user_record.id,
            jsonb_build_object('sub', user_record.id),
            'email'
        );
    END LOOP;

    -- Recreate trigger command
    result := result || 'CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION private.handle_new_user();';

    RETURN result;
END;
$$;


ALTER FUNCTION "private"."generate_user_inserts"("email_list" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."get_app_data"("uid" "uuid", "item" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'private'
    AS $$
    DECLARE retval jsonb;
    BEGIN
        select coalesce(raw_app_meta_data->item, null) from auth.users into retval where id = uid::uuid;
        return retval;
    END;
$$;


ALTER FUNCTION "private"."get_app_data"("uid" "uuid", "item" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$


DECLARE
    var_community_uuid uuid;
    var_community text;
    var_kyng_uuid uuid;
    var_kyng text;
    var_principaladdresssiteoid integer := (new.raw_user_meta_data->'principaladdresssiteoid')::integer;
    var_community_profile_uuid uuid := gen_random_uuid();
    var_property_uuid uuid := gen_random_uuid();
    var_valid_address_street text := new.raw_user_meta_data->>'validaddressstreet';
    var_valid_address_suburb text := new.raw_user_meta_data->>'validaddresssuburb';
    var_valid_address_postcode text := new.raw_user_meta_data->>'validaddresspostcode';
    var_search_address_street text := new.raw_user_meta_data->>'searchaddressstreet';
    var_search_address_suburb text := new.raw_user_meta_data->>'searchaddresssuburb';

BEGIN
	SELECT id, community INTO var_community_uuid, var_community
    FROM public.community_areas
    WHERE extensions.ST_Intersects((SELECT extensions.ST_Collect(geom) FROM public.project_addresspoints WHERE principaladdresssiteoid = var_principaladdresssiteoid), geom);
	SELECT id, kyng INTO var_kyng_uuid, var_kyng
    FROM public.kyng_areas
    WHERE extensions.ST_Intersects((SELECT extensions.ST_Collect(geom) FROM public.project_addresspoints WHERE principaladdresssiteoid = var_principaladdresssiteoid), geom);
    CASE var_community
        WHEN 'BCYCA' THEN
		-- Create new user_profile
			INSERT INTO public.user_profile (id, bcyca_profile_id)
			VALUES (new.id, var_community_profile_uuid);
			INSERT INTO public.community_bcyca_profile (bcyca_profile_id)
			VALUES (var_community_profile_uuid);
        WHEN 'Mondrook' THEN
			INSERT INTO public.user_profile (id, mondrook_profile_id)
			VALUES (new.id, var_community_profile_uuid);
			INSERT INTO public.community_mondrook_profile (mondrook_profile_id)
			VALUES (var_community_profile_uuid);
        WHEN 'Tinonee' THEN
			INSERT INTO public.user_profile (id, tinonee_profile_id)
			VALUES (new.id, var_community_profile_uuid);
			INSERT INTO public.community_tinonee_profile (tinonee_profile_id)
			VALUES (var_community_profile_uuid);
        WHEN 'External' THEN
			INSERT INTO public.user_profile (id, external_profile_id)
			VALUES (new.id, var_community_profile_uuid);
			INSERT INTO public.community_external_profile (external_profile_id)
			VALUES (var_community_profile_uuid);
    END CASE;
    IF NOT EXISTS (SELECT 1 FROM public.property_profile WHERE principaladdresssiteoid = var_principaladdresssiteoid) THEN
		INSERT INTO property_profile (id,
			principaladdresssiteoid, property_address_street, property_address_suburb, property_address_postcode, 
			community, kyng
		)
		VALUES (
			var_property_uuid, var_principaladdresssiteoid, var_valid_address_street, var_valid_address_suburb, 
			var_valid_address_postcode, var_community_uuid, var_kyng_uuid
		);
		INSERT INTO public.property_geometry (id, principaladdresssiteoid, address_point, way_point, property)
		VALUES (
			var_property_uuid, var_principaladdresssiteoid, 
				(SELECT geom from public.project_addresspoints where principaladdresssiteoid = var_principaladdresssiteoid),
				(SELECT geom from public.project_waypoints where principaladdresssiteoid = var_principaladdresssiteoid),
				(SELECT geom from public.project_properties where principaladdresssiteoid = var_principaladdresssiteoid)
			);
	ELSE
		SELECT id from property_profile WHERE principaladdresssiteoid = var_principaladdresssiteoid into var_property_uuid;
    END IF;
	INSERT INTO user_property_profile_join (user_id, property_id, search_address_street, search_address_suburb)
	VALUES (new.id, var_property_uuid, var_search_address_street, var_search_address_suburb);
	UPDATE auth.users SET raw_app_meta_data =
    raw_app_meta_data || 
	json_build_object('principaladdresssiteoid', var_principaladdresssiteoid)::jsonb || 
	json_build_object('kitdate', null)::jsonb
	WHERE id = new.id;
	 UPDATE auth.users SET raw_user_meta_data = null  WHERE id = new.id;

 RETURN NEW;
END;
$$;


ALTER FUNCTION "private"."handle_new_user"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."hook_failed_login"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'private', 'public'
    AS $$
DECLARE
BEGIN
  INSERT INTO private.failed_login_attempts (user_id, attempt_time)
  VALUES ((event->>'user_id')::uuid, now());

  RETURN jsonb_build_object('decision', 'continue');
END;
$$;


