CREATE OR REPLACE FUNCTION "private"."set_app_data"("uid" "uuid", "item" "text", "value" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'private'
    AS $$
