CREATE OR REPLACE FUNCTION "private"."set_survey_responses"("user_id" "uuid", "email" "text", "var_property_valence" integer, "user_metadata" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'private'
    AS $$
declare
    var_survey_id integer;
BEGIN
    select survey_id from public.survey_responses where email_address = email into var_survey_id;
    raise log 'Did 1';
    if var_survey_id is not null then
        PERFORM set_survey_responses_to_user_profile(user_id, var_survey_id);
        raise log 'Did 1.1';
       PERFORM set_survey_responses_to_user_bcyca_profile(user_id, var_survey_id);
        raise log 'Did 1.2';
        if var_property_valence = 1 then
            PERFORM set_survey_responses_to_user_property_profile(user_id, var_survey_id, var_property_valence);
            raise log 'Did 1.3';
        end if;
    end if;
    PERFORM set_app_metadata_for_user(user_id, user_metadata, var_survey_id);
    raise log 'Did all';

END;
$$;


