CREATE OR REPLACE FUNCTION "private"."set_survey_responses_to_user_bcyca_profile"("id" "uuid", "var_survey_id" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'private'
    AS $$
BEGIN
    with srq as
    (
        SELECT
			CASE WHEN "communityWorkshopChoices" is null then '{}'::smallint[]
				else jsonb_array_to_smallint_array("communityWorkshopChoices")
			END	as community_workshop_choices,
			"otherCommunityWorkshop" as other_community_workshop,
			"willRunCommunityWorkshops" as will_run_community_workshops,
			CASE WHEN "communityMeetingChoices" is null then '{}'::smallint[]
				else jsonb_array_to_smallint_array("communityMeetingChoices")
			END as community_meeting_choices,
			"communityMeeting" as other_community_meeting,
			CASE WHEN "informationSheetChoices" is null then '{}'::smallint[]
			else jsonb_array_to_smallint_array("informationSheetChoices")
			END as information_sheet_choices,
			"otherInformationSheet" as other_information_sheet
        FROM survey_responses WHERE survey_id = var_survey_id
    )
    UPDATE public.user_bcyca_profile SET (community_workshop_choices, other_community_workshop, will_run_community_workshops, community_meeting_choices, other_community_meeting, information_sheet_choices, other_information_sheet) =
    (SELECT community_workshop_choices, other_community_workshop, will_run_community_workshops, community_meeting_choices, other_community_meeting, information_sheet_choices, other_information_sheet from srq)
    WHERE user_id = id;
END;
$$;


ALTER FUNCTION "private"."set_survey_responses_to_user_bcyca_profile"("id" "uuid", "var_survey_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."set_survey_responses_to_user_profile"("user_id" "uuid", "var_survey_id" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'private'
    AS $$
BEGIN
    with srq as
    (
        SELECT mobile, "residencyProfile"::integer as residency_profile, "rfsSurvivalPlan" as rfs_survival_plan, 	"planToLeaveBeforeFire" as plan_to_leave_before_fire, "planToLeaveBeforeFlood" as plan_to_leave_before_flood, "fireFightingExperience" as fire_fighting_experience,
        CASE WHEN "stayInTouchChoices" is null then '{}'::smallint[]
            else jsonb_array_to_smallint_array("stayInTouchChoices")
        END as stay_in_touch_choices,
        "otherComments" as other_comments
        FROM survey_responses WHERE survey_id = var_survey_id
    )
    UPDATE public.user_profile SET (mobile, residency_profile, rfs_survival_plan, plan_to_leave_before_fire, plan_to_leave_before_flood, fire_fighting_experience, stay_in_touch_choices, other_comments) =
    (SELECT srq.mobile, srq.residency_profile, srq.rfs_survival_plan, srq.plan_to_leave_before_fire, srq.plan_to_leave_before_flood, srq.fire_fighting_experience, srq.stay_in_touch_choices, srq.other_comments from srq)
    WHERE user_id = id;
END;
$$;


ALTER FUNCTION "private"."set_survey_responses_to_user_profile"("user_id" "uuid", "var_survey_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."set_survey_responses_to_user_property_profile"("id" "uuid", "var_survey_id" integer, "var_property_valence" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'private'
    AS $$
BEGIN
    with srq as
    (
        SELECT phone, "mobileReception" as mobile_reception, "signPosted" as sign_posted, "truckAccess" as truck_access, "truckAccessOther" as truck_access_other_information, residents0_18, residents19_50, residents51_70, residents71_, "vulnerableResidents"::boolean as vulnerable_residents, "numberDogs"::smallint as number_dogs, "numberCats"::smallint as number_cats, "numberBirds"::smallint as number_birds, "numberOtherPets"::smallint as number_other_pets, "liveStockPresent" as live_stock_present, "liveStockSafeArea" as live_stock_safe_area, "shareLiveStockSafeArea" as share_livestock_safe_area,
		CASE WHEN "staticWaterAvailable" is null then '{}'::smallint[]
			else jsonb_array_to_smallint_array("staticWaterAvailable")
		END as static_water_available,
		CASE WHEN "fireFightingResources" is null then '{}'::smallint[]
			else jsonb_array_to_smallint_array("fireFightingResources")
		END as fire_fighting_resources,
		"haveStortz" as have_stortz, "stortzSize" as stortz_size,
		CASE WHEN "explosiveHazards" is null then '{}'::smallint[]
			else jsonb_array_to_smallint_array("explosiveHazards")
		END as site_hazards,
		"otherSiteHazards" as other_site_hazards,
		CASE WHEN "fireHazardReduction" is null then '{}'::smallint[]
			else jsonb_array_to_smallint_array("fireHazardReduction")
		END as fire_hazard_reduction,
		"landAdjacentHazard" as land_adjacent_hazard, "otherHazards" as other_hazards
        FROM survey_responses WHERE survey_id = var_survey_id
    )
    UPDATE public.property_profile SET (phone, mobile_reception, sign_posted, truck_access, truck_access_other_information, residents0_18, residents19_50, residents51_70, residents71_, vulnerable_residents, number_dogs, number_cats,
    number_birds, number_other_pets, live_stock_present, live_stock_safe_area, share_livestock_safe_area, static_water_available, fire_fighting_resources, have_stortz, stortz_size, site_hazards, other_site_hazards, fire_hazard_reduction, land_adjacent_hazard, other_hazards) = (SELECT phone, mobile_reception, sign_posted, truck_access, truck_access_other_information, residents0_18, residents19_50, residents51_70, residents71_, vulnerable_residents, number_dogs, number_cats,
    number_birds, number_other_pets, live_stock_present, live_stock_safe_area, share_livestock_safe_area, static_water_available, fire_fighting_resources, have_stortz, stortz_size, site_hazards, other_site_hazards, fire_hazard_reduction, land_adjacent_hazard, other_hazards from srq)
    WHERE public.property_profile.id in
        (SELECT property_id FROM user_property_profile_join WHERE user_id = user_id);
END;
$$;


