CREATE OR REPLACE FUNCTION "private"."x_handle_property_profile"("new_user_id" "uuid", "user_metadata" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$

DECLARE
  var_property_id uuid;
  var_property_valence integer;
  var_principaladdresssiteoid integer;
  var_srid integer;
  var_addresspoint geometry;
  var_waypoint geometry;
  var_property geometry;
  var_street text;
  var_suburb text;
  var_postcode text;
BEGIN
  select (user_metadata->'principaladdresssiteoid')::integer into var_principaladdresssiteoid;
  select p.id from property_geometry p
  where p.principaladdresssiteoid = (user_metadata->'principaladdresssiteoid')::integer into var_property_id;
  if var_property_id is NULL then
    select
        concat(user_metadata->'searchaddress'->>0, ' ', user_metadata->'searchaddress'->>1),
        user_metadata->'searchaddress'->>2,   user_metadata->'searchaddress'->>3
    into var_street, var_suburb, var_postcode;
    select rtrim(split_part(((user_metadata->>'addresspoint')::json#>'{crs,properties,name}')::text, ':', 2), '"')::integer into var_srid;
    select ST_SetSRID(ST_Force3D(ST_GeomFromGeoJSON((user_metadata->>'addresspoint')::json)), var_srid) into var_addresspoint;
    select waypoint, property into var_waypoint, var_property from private.get_property_data(var_principaladdresssiteoid,var_srid);
    insert into property_profile (principaladdresssiteoid, property_address_street, property_address_suburb, property_address_postcode)
      values (var_principaladdresssiteoid, var_street, var_suburb, var_postcode) returning id into var_property_id;
    insert into property_geometry
      values (var_property_id, var_principaladdresssiteoid, var_addresspoint, var_waypoint, var_property);
  end if;
  update auth.users set raw_app_meta_data =
    raw_app_meta_data || json_build_object('property_id', var_property_id)::jsonb where id = new_user_id;
  insert into user_property_profile_join (user_id, property_id) values (new_user_id, var_property_id);
  SELECT Count(property_id) from user_property_profile_join where property_id = var_property_id into var_property_valence;
  return var_property_valence;
END;
$$;


ALTER FUNCTION "private"."x_handle_property_profile"("new_user_id" "uuid", "user_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_community_bcyca_profile"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
