    INSERT INTO public.community_bcyca_profile (bcyca_profile_id)
    VALUES (NEW.bcyca_profile_id);
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."add_community_bcyca_profile"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_community_bcyca_profile"("user_id_param" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    new_bcyca_profile_id uuid;
BEGIN
    -- Check if bcyca_profile_id is already set for the user
    IF (SELECT bcyca_profile_id FROM public.user_profile WHERE id = user_id_param) IS NOT NULL THEN
        RAISE NOTICE 'bcyca_profile_id is already set for the user';
        RETURN;
    END IF;

    -- Insert a new row into community_bcyca_profile
    INSERT INTO public.community_bcyca_profile (
        bcyca_profile_id,
        created_at,
        last_updated
    ) VALUES (
        DEFAULT,
        NOW(),
        NOW()
    ) RETURNING bcyca_profile_id INTO new_bcyca_profile_id;

    -- Update user_profile to set the bcyca_profile_id
    UPDATE public.user_profile
    SET bcyca_profile_id = new_bcyca_profile_id
    WHERE id = user_id_param;

END;
$$;


