CREATE OR REPLACE FUNCTION "public"."add_role_to_enum"("new_role" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    -- Verify user has the exact required permission
    IF NOT EXISTS (
        SELECT 1 
        FROM role_permissions rp
        JOIN user_roles ur ON ur.role = rp.role
        WHERE ur.user_id = auth.uid()
        AND rp.permission LIKE '%admin.site.roles%'
    ) THEN
        RAISE EXCEPTION 'Requires admin.site.roles permission';
    END IF;

    EXECUTE format(
        'ALTER TYPE public.app_role ADD VALUE IF NOT EXISTS %L',
        new_role
    );
END;
$$;


ALTER FUNCTION "public"."add_role_to_enum"("new_role" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."build_parcel_polygon"("input_text" "text", "max_features" integer DEFAULT 10000) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_temp'
    AS $$
DECLARE
  admin_base text := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer';
  land_base text := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme/FeatureServer';
  pairs text[];
  pair text;
  street text;
  suburb text;
  suburb_geoms geometry[];
  corridor_geoms geometry[];
  parcel_geoms geometry[];
  total_corridor geometry;
  interior_poly geometry;
  final_poly geometry;
  feature jsonb;
  response jsonb;
  result_offset integer;
  limit_per_query integer := 200;  -- FeatureServer max
  exceeded boolean;
  fetched integer;
  total_fetched integer;
  suburb_esri_json text;
  interior_esri_json text;
  base_url text;
BEGIN
  RAISE NOTICE 'Function start: build_parcel_polygon(input_text=%, max_features=%)', input_text, max_features;
  RAISE LOG 'Function start: build_parcel_polygon(input_text=%, max_features=%)', input_text, max_features;

  -- Parse input robustly
  IF input_text IS NULL OR trim(input_text) = '' THEN
    RAISE NOTICE 'Empty input provided';
    RETURN jsonb_build_object('error', 'Empty input');
  END IF;

  pairs := regexp_split_to_array(regexp_replace(input_text, '\|+', '|'), '\|');
  RAISE NOTICE 'Parsed % pairs from input', array_length(pairs, 1);

  -- Collect suburb geometries
  suburb_geoms := '{}';
  FOREACH pair IN ARRAY pairs LOOP
    IF pair ~ ',' THEN
      street := trim(split_part(pair, ',', 1));
      suburb := trim(split_part(pair, ',', 2));
      RAISE NOTICE 'Processing pair: street="%", suburb="%"', street, suburb;

      IF street = '' OR suburb = '' THEN
        RAISE NOTICE 'Skipping invalid pair: "%" (missing street/suburb)', pair;
        CONTINUE;
      END IF;

      base_url := admin_base || '/2/query?where=suburbname=''' || replace(upper(suburb), '''', '''''') || '''&returnGeometry=true&outFields=*&f=geojson&outSR=4326&resultRecordCount=' || limit_per_query;
      result_offset := 0;
      total_fetched := 0;
	  RAISE NOTICE 'Base url: "%"', base_url;
      LOOP
        RAISE NOTICE 'Fetching suburb batch: offset=%', result_offset;
        response := http_get(base_url || '&resultOffset=' || result_offset) ->> 'content';
        response := response::jsonb;
        exceeded := response ->> 'exceededTransferLimit' = 'true';
        fetched := COALESCE(jsonb_array_length(response -> 'features'), 0);
        total_fetched := total_fetched + fetched;
        RAISE NOTICE 'Fetched % suburb features (total so far=%)', fetched, total_fetched;

        IF fetched > 0 THEN
          FOR feature IN SELECT * FROM jsonb_array_elements(response -> 'features') LOOP
            suburb_geoms := array_append(suburb_geoms, ST_GeomFromGeoJSON(feature ->> 'geometry'));
          END LOOP;
        END IF;

        EXIT WHEN NOT exceeded OR total_fetched >= max_features;
        result_offset := result_offset + limit_per_query;
      END LOOP;

      RAISE NOTICE 'Total suburb features fetched for %: %', suburb, total_fetched;
    END IF;
  END LOOP;

  IF array_length(suburb_geoms, 1) = 0 THEN
    RAISE NOTICE 'No suburb geometries collected';
    RETURN jsonb_build_object('error', 'No suburbs found');
  END IF;

  RAISE NOTICE 'Unioning suburb geometries';
  total_corridor := ST_MakeValid(ST_Union(suburb_geoms));

  RAISE NOTICE 'Converting suburb union to Esri JSON';
  suburb_esri_json := replace(ST_AsGeoJSON(total_corridor)::jsonb #> '{coordinates}'::text[], 'type', 'rings')::text;

  -- Collect corridors
  corridor_geoms := '{}';
  FOREACH pair IN ARRAY pairs LOOP
    IF pair ~ ',' THEN
      street := trim(split_part(pair, ',', 1));
      IF street = '' THEN CONTINUE; END IF;
      RAISE NOTICE 'Fetching corridors for street=%', street;

      base_url := land_base || '/5/query?where=roadnamelabel ILIKE ''' || replace(street, '''', '''''') ||
                   '''&geometry=' || http_uriencode(suburb_esri_json) ||
                   '&geometryType=esriGeometryPolygon&spatialRel=esriSpatialRelIntersects&returnGeometry=true&f=geojson&outSR=4326&resultRecordCount=' || limit_per_query;
      result_offset := 0;
      total_fetched := 0;

      LOOP
        RAISE NOTICE 'Fetching corridor batch: offset=%', result_offset;
        response := http_get(base_url || '&resultOffset=' || result_offset) ->> 'content';
        response := response::jsonb;
        exceeded := response ->> 'exceededTransferLimit' = 'true';
        fetched := COALESCE(jsonb_array_length(response -> 'features'), 0);
        total_fetched := total_fetched + fetched;
        RAISE NOTICE 'Fetched % corridor features (total so far=%)', fetched, total_fetched;

        IF fetched > 0 THEN
          FOR feature IN SELECT * FROM jsonb_array_elements(response -> 'features') LOOP
            corridor_geoms := array_append(corridor_geoms, ST_GeomFromGeoJSON(feature ->> 'geometry'));
          END LOOP;
        END IF;

        EXIT WHEN NOT exceeded OR total_fetched >= max_features;
        result_offset := result_offset + limit_per_query;
      END LOOP;

      RAISE NOTICE 'Total corridor features fetched for %: %', street, total_fetched;
    END IF;
  END LOOP;

  IF array_length(corridor_geoms, 1) = 0 THEN
    RAISE NOTICE 'No corridor geometries collected';
    RETURN jsonb_build_object('error', 'No corridors found');
  END IF;

  RAISE NOTICE 'Unioning corridor geometries';
  total_corridor := ST_MakeValid(ST_Union(corridor_geoms));

  -- Extract interior
  RAISE NOTICE 'Extracting interior geometry';
  IF ST_NumInteriorRings(total_corridor) > 0 THEN
    RAISE NOTICE 'Detected interior ring';
    interior_poly := ST_MakePolygon(ST_InteriorRingN(total_corridor, 1));
  ELSE
    RAISE NOTICE 'No interior ring; using concave hull fallback';
    interior_poly := ST_ConcaveHull(ST_Boundary(total_corridor), 0.99, true);
  END IF;

  interior_poly := ST_SetSRID(ST_MakeValid(interior_poly), 4326);

  IF ST_IsEmpty(interior_poly) THEN
    RAISE NOTICE 'Interior polygon is empty';
    RETURN jsonb_build_object('error', 'No enclosed area detected');
  END IF;

  RAISE NOTICE 'Converting interior polygon to Esri JSON';
  interior_esri_json := replace(ST_AsGeoJSON(interior_poly)::jsonb #> '{coordinates}'::text[], 'type', 'rings')::text;

  -- Fetch parcels
  RAISE NOTICE 'Fetching parcels inside interior polygon';
  parcel_geoms := '{}';
  base_url := land_base || '/8/query?geometry=' || http_uriencode(interior_esri_json) ||
               '&geometryType=esriGeometryPolygon&spatialRel=esriSpatialRelWithin&returnGeometry=true&f=geojson&outSR=4326&resultRecordCount=' || limit_per_query;
  result_offset := 0;
  total_fetched := 0;

  LOOP
    RAISE NOTICE 'Fetching parcel batch: offset=%', result_offset;
    response := http_get(base_url || '&resultOffset=' || result_offset) ->> 'content';
    response := response::jsonb;
    exceeded := response ->> 'exceededTransferLimit' = 'true';
    fetched := COALESCE(jsonb_array_length(response -> 'features'), 0);
    total_fetched := total_fetched + fetched;
    RAISE NOTICE 'Fetched % parcel features (total so far=%)', fetched, total_fetched;

    IF fetched > 0 THEN
      FOR feature IN SELECT * FROM jsonb_array_elements(response -> 'features') LOOP
        parcel_geoms := array_append(parcel_geoms, ST_GeomFromGeoJSON(feature ->> 'geometry'));
      END LOOP;
    END IF;

    EXIT WHEN NOT exceeded OR total_fetched >= max_features;
    result_offset := result_offset + limit_per_query;
  END LOOP;

  RAISE NOTICE 'Total parcel features fetched: %', total_fetched;

  -- Union parcels
  IF array_length(parcel_geoms, 1) > 0 THEN
    RAISE NOTICE 'Unioning parcel geometries';
    final_poly := ST_MakeValid(ST_Union(parcel_geoms));
    final_poly := ST_Simplify(final_poly, 0.00001);
  ELSE
    RAISE NOTICE 'No parcels found; returning empty polygon';
    final_poly := ST_GeomFromText('POLYGON EMPTY', 4326);
  END IF;

  RAISE NOTICE 'Function completed successfully';
  RETURN jsonb_build_object('geometry', ST_AsGeoJSON(final_poly)::text);

EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'ERROR: %', SQLERRM;
  RETURN jsonb_build_object('error', SQLERRM);
END;
$$;


ALTER FUNCTION "public"."build_parcel_polygon"("input_text" "text", "max_features" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_address_match"("delimited_string" "text") RETURNS TABLE("id" integer, "address" "text", "community" "text", "principaladdresssiteoid" bigint, "startdate" timestamp without time zone, "enddate" timestamp without time zone, "lastupdate" timestamp without time zone, "createdby" "uuid")
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    -- Check if any of the delimited strings match the address field of the table
    RETURN QUERY SELECT *
    FROM public.custom_address ca
    WHERE ca.address IN (SELECT regexp_split_to_table(delimited_string, ','));
    -- If there is no match, execute a different query
    IF NOT FOUND THEN
        RETURN QUERY SELECT *
        FROM public.custom_address ca
        WHERE ca.address = '449 NOWENDOC ROAD KILLAWARRA';
    END IF;
END;
$$;


ALTER FUNCTION "public"."check_address_match"("delimited_string" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_admin_permission"("required_permission" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 
    FROM auth.users u
    JOIN user_roles ur ON u.id = ur.user_id
    JOIN role_permissions rp ON ur.role = rp.role
    WHERE u.id = auth.uid() 
    AND rp.permission LIKE '%' || required_permission || '%'
  );
END;
$$;


ALTER FUNCTION "public"."check_admin_permission"("required_permission" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_gnaf_address_match"("input_number" "text", "input_street" "text", "input_street_type" "text", "input_locality" "text", "api_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
    api_response jsonb;
    address_string text;
    match_codes jsonb;
    locality_info jsonb;
    filtered_response jsonb;
    street_locality_response jsonb;
BEGIN
    -- Construct address string
    address_string := input_number || ' ' || input_street || ' ' || input_street_type || ', ' || input_locality;
    
    -- Make direct HTTP call to geocoder API
    SELECT content INTO api_response
    FROM http((
        'GET',
        'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(address_string) || '&stateFilter=NSW&additionalProperties=parcelBundle',
        ARRAY[http_header('Authorization', api_key)],
        NULL,
        NULL
    )::http_request);
    
    -- Extract match codes from the first feature
    match_codes := api_response->'features'->0->'matchCode';
    
    -- Create filtered response with only required fields
    filtered_response := jsonb_build_object(
        'formattedAddress', api_response->'features'->0->'properties'->>'formattedAddress',
        'cadastralIdentifier', api_response->'features'->0->'properties'->>'cadastralIdentifier',
        'geometry', api_response->'features'->0->'geometry'
    );
    
    -- Rest of the function remains the same...
    -- Case 1: Check for exact match of all components
    IF match_codes->>'streetNumber1' = 'exact' AND
       match_codes->>'streetName' = 'exact' AND
       match_codes->>'streetType' = 'exact' AND
       match_codes->>'localityName' = 'exact' THEN
        
        RETURN jsonb_build_object(
            'is_match', true,
            'geojson', filtered_response
        );
    END IF;
    
    -- Case 2: Check for exact street components with locality alias/neighbor
    IF match_codes->>'streetNumber1' = 'exact' AND
       match_codes->>'streetName' = 'exact' AND
       match_codes->>'streetType' = 'exact' THEN
        
        -- Make additional API call to check locality relationships
        SELECT content INTO locality_info
        FROM http((
            'GET',
            'https://api.psma.com.au/v2/addresses/localities/' || urlencode(input_locality),
            ARRAY[http_header('Authorization', api_key)],
            NULL,
            NULL
        )::http_request);
        
        IF jsonb_path_exists(locality_info, '$.features[*].properties.aliases[*] ? (@.name == $matched_locality)', 
            jsonb_build_object('matched_locality', api_response->'features'->0->'properties'->>'localityName'))
        OR
        jsonb_path_exists(locality_info, '$.features[*].properties.neighbours[*] ? (@.name == $matched_locality)', 
            jsonb_build_object('matched_locality', api_response->'features'->0->'properties'->>'localityName')) THEN
            
            RETURN jsonb_build_object(
                'is_match', true,
                'geojson', filtered_response
            );
        END IF;
    END IF;
    
    -- If no match found, try with streetLocality matchType
    SELECT content INTO street_locality_response
    FROM http((
        'GET',
        'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(address_string) || '&stateFilter=NSW&additionalProperties=parcelBundle&matchType=streetLocality',
        ARRAY[http_header('Authorization', api_key)],
        NULL,
        NULL
    )::http_request);
    
    -- Return the street locality results
    RETURN jsonb_build_object(
        'is_match', false,
        'geojson', jsonb_build_object(
            'formattedAddress', street_locality_response->'features'->0->'properties'->>'formattedAddress',
            'cadastralIdentifier', street_locality_response->'features'->0->'properties'->>'cadastralIdentifier',
            'geometry', street_locality_response->'features'->0->'geometry'
        )
    );
END;
$_$;


ALTER FUNCTION "public"."check_gnaf_address_match"("input_number" "text", "input_street" "text", "input_street_type" "text", "input_locality" "text", "api_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cleanup_orphaned_attributes"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_count integer;
BEGIN
    WITH deleted AS (
        DELETE FROM feature_attributes fa
        WHERE NOT EXISTS (
            SELECT 1 
            FROM spatial_features sf 
            WHERE sf.id = fa.feature_id
        )
        RETURNING *
    )
    SELECT COUNT(*) INTO v_count FROM deleted;
    
    RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."cleanup_orphaned_attributes"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cleanup_orphaned_spatial_features"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_count integer;
BEGIN
    WITH deleted AS (
        DELETE FROM spatial_features sf
        WHERE NOT EXISTS (
            SELECT 1 FROM feature_templates ft WHERE ft.id = sf.template_id
        )
        OR NOT EXISTS (
            SELECT 1 FROM property_profile pp WHERE pp.id = sf.property_id
        )
        OR NOT EXISTS (
            SELECT 1 FROM user_profile up WHERE up.id = sf.user_id
        )
        RETURNING *
    )
    SELECT COUNT(*) INTO v_count FROM deleted;
    
    RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."cleanup_orphaned_spatial_features"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_kyng_property_fragment_views"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
    rec RECORD;
    view_name TEXT;
    kyng_name TEXT;
BEGIN
    FOR rec IN
        SELECT DISTINCT ka.kyng
        FROM kyng_areas ka
        ORDER BY ka.kyng
    LOOP
        kyng_name := rec.kyng;
        view_name := left(
            'kyng_' ||
            replace(replace(replace(replace(lower(kyng_name), ' - ', '_'), '(', ''), ')', ''), ' ', '_') ||
            '_property_fragment_view',
            63
        );

        RAISE NOTICE 'Recreating view: %  (kyng: %)', view_name, kyng_name;

        EXECUTE format('DROP VIEW IF EXISTS %I CASCADE', view_name);

        EXECUTE format($view$
            CREATE VIEW %I AS
            WITH this_kyng AS MATERIALIZED (
                SELECT extensions.ST_Union(geom) AS geom
                FROM kyng_areas
                WHERE kyng = %L
            ),
            primary_props AS (
                SELECT DISTINCT ON (gurasid)
                    gurasid,
                    address AS primary_address,
                    valnetpropertystatus,
                    valnetpropertytype,
                    geom
                FROM project_properties
                WHERE principaladdresstype = 'Primary'
            ),
            parts AS (
                SELECT
                    pp.gurasid,
                    pp.primary_address,
                    pp.valnetpropertystatus,
                    pp.valnetpropertytype,
                    (extensions.ST_Dump(pp.geom)).geom AS part_geom
                FROM primary_props pp
            ),
            parts_in_this_kyng AS (
                SELECT pt.*
                FROM parts pt
                WHERE extensions.ST_Covers(
                    (SELECT geom FROM this_kyng),
                    extensions.ST_PointOnSurface(pt.part_geom)
                )
            ),
            parent_kyng_for_property AS (
                SELECT
                    pp.gurasid,
                    ka.kyng AS parent_kyng
                FROM primary_props pp
                LEFT JOIN kyng_areas ka
                  ON extensions.ST_Covers(ka.geom, extensions.ST_PointOnSurface(pp.geom))
            ),
            secondary_aggr AS (
                SELECT
                    gurasid,
                    string_agg(DISTINCT address, E'\n' ORDER BY address) AS secondary_addresses
                FROM project_properties
                WHERE principaladdresstype = 'Secondary'
                GROUP BY gurasid
            ),
            alternate_aggr AS (
                SELECT
                    gurasid,
                    string_agg(DISTINCT address, E'\n' ORDER BY address) AS alternate_addresses
                FROM project_properties
                WHERE principaladdresstype = 'Alternate'
                GROUP BY gurasid
            ),
            collected AS (
                SELECT
                    pit.gurasid,
                    pit.primary_address,
                    pit.valnetpropertystatus,
                    pit.valnetpropertytype,
                    extensions.ST_Multi(extensions.ST_Collect(pit.part_geom)) AS geom,
                    SUM(extensions.ST_Area(extensions.ST_Transform(pit.part_geom, 3577)))::integer AS fragments_area_m2,
                    COUNT(*)::integer AS part_count
                FROM parts_in_this_kyng pit
                GROUP BY pit.gurasid, pit.primary_address, pit.valnetpropertystatus, pit.valnetpropertytype
            )
            SELECT
                (row_number() OVER (ORDER BY c.gurasid))::integer AS rowid,
                c.gurasid,
                c.part_count,
                c.primary_address       AS parent_primary_address,
                pk.parent_kyng,
                COALESCE(sa.secondary_addresses, '') AS secondary_addresses,
                COALESCE(aa.alternate_addresses, '') AS alternate_addresses,
                c.valnetpropertystatus,
                c.valnetpropertytype,
                c.fragments_area_m2,
                c.geom
            FROM collected c
            JOIN parent_kyng_for_property pk USING (gurasid)
            LEFT JOIN secondary_aggr sa      USING (gurasid)
            LEFT JOIN alternate_aggr aa      USING (gurasid)
            WHERE pk.parent_kyng IS DISTINCT FROM %L
        $view$, view_name, kyng_name, kyng_name);

    END LOOP;

    RAISE NOTICE 'Done: kyng_<slug>_property_fragment_view created for all KYNG areas.';
END;
$_$;


ALTER FUNCTION "public"."create_kyng_property_fragment_views"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_kyngs_views"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    kyng_name_value text;
    kyng_row record;
    addressspoint_fields text := 'addresssitename,address,housenumber,principaladdresstype,addresspointtype,addresstype,' ||
                                'addressstringtype,roadside,deliverypointid, contributororigin,contributoralignment,' ||
                                'gnafprimarysiteid,addresspointoid,principaladdresssiteoid,geom';
    property_fields text := 'p.gurasid,p.address,p.housenumber,p.principaladdresstype,p.propertytype,p.valnetpropertystatus,' ||
                             'p.valnetpropertytype,p.dissolveparcelcount,p.valnetlotcount,p.principaladdresssiteoid,' ||
                             'p.geom';
BEGIN
    FOR kyng_row IN
        SELECT kyng, geom FROM kyng_areas
        LOOP
            kyng_name_value := replace(
                lower(
                    replace(
                        regexp_replace(trim(kyng_row.kyng), '\s+', ' ', 'g'),
                        ' - ',
                        '-'
                    )
                ),
                ' ',
                '_'
            );

            EXECUTE format(
                'CREATE OR REPLACE VIEW %I AS
                   SELECT CAST(ROW_NUMBER() OVER () AS INTEGER) AS rowid, *
                   FROM kyng_areas WHERE kyng = %L',
                'kyng_' || kyng_name_value || '_area_view',
                kyng_row.kyng
            );

            EXECUTE format(
                'CREATE OR REPLACE VIEW %I AS
                   SELECT CAST(ROW_NUMBER() OVER () AS INTEGER) AS rowid, ' || addressspoint_fields || '
                   FROM project_addresspoints
                   WHERE ST_Within(geom, (SELECT st_union(geom) FROM kyng_areas WHERE kyng = %L))',
                'kyng_' || kyng_name_value || '_addresspoint_view',
                kyng_row.kyng
            );

            EXECUTE format(
                'CREATE OR REPLACE VIEW %I AS
                   SELECT CAST(ROW_NUMBER() OVER () AS INTEGER) AS rowid,
                          wp.id, wp.waypointoid,
                          addr.address, addr.housenumber,
                          wp.gurasid, wp.principaladdresssiteoid, wp.addressstringoid,
                          wp.addresspointoid, wp.roadnameextentoid, wp.principaladdresstype,
                          wp.contributororigin, wp.contributorid, wp.derivedby,
                          wp.startdate, wp.lastupdate, wp.enddate,
                          wp.geom, wp.refresh_date
                   FROM project_waypoints wp
                   INNER JOIN %I addr ON wp.addresspointoid = addr.addresspointoid',
                'kyng_' || kyng_name_value || '_waypoint_view',
                'kyng_' || kyng_name_value || '_addresspoint_view'
            );

            EXECUTE format(
                'CREATE OR REPLACE VIEW %I AS
                   SELECT CAST(ROW_NUMBER() OVER () AS INTEGER) AS rowid, prow.*
                   FROM project_proways prow
                   INNER JOIN %I addr ON prow.addresspointoid = addr.addresspointoid
                                     AND prow.waypointoid    = addr.waypointoid',
                'kyng_' || kyng_name_value || '_proway_view',
                'kyng_' || kyng_name_value || '_waypoint_view'
            );

            EXECUTE format(
                'CREATE OR REPLACE VIEW %I AS
                  WITH this_kyng AS MATERIALIZED (
                      SELECT ST_Union(geom) AS geom
                      FROM public.kyng_areas
                      WHERE kyng = %L
                  ),
                  other_kyngs AS MATERIALIZED (
                      SELECT ST_Union(geom) AS geom
                      FROM public.kyng_areas
                      WHERE kyng <> %L
                  ),
                  unique_gurasid AS (
                      SELECT DISTINCT ON (gurasid) gurasid, address, valnetpropertystatus, valnetpropertytype, geom
                      FROM public."project_properties"
                      WHERE principaladdresstype = ''Primary''
                  )
                SELECT
                    CAST(ROW_NUMBER() OVER () AS INTEGER) AS rowid,
                    ug.gurasid,
                    ug.address,
                    COUNT(ug.address) OVER (PARTITION BY ug.address) AS address_count,
                    ug.valnetpropertystatus,
                    ug.valnetpropertytype,
                    ''Primary'' AS principaladdresstype,
                    COALESCE(string_agg(DISTINCT alternate_subquery.alternate_address, E''\n''), '''') AS alternate_addresses,
                    COALESCE(string_agg(DISTINCT secondary_subquery.secondary_address, E''\n''), '''') AS secondary_addresses,
                    ug.geom,
                    ST_Area(
                        ST_Intersection(
                            ST_Difference(ug.geom, (SELECT geom FROM this_kyng)),
                            (SELECT geom FROM other_kyngs)
                        )::geography
                    ) > 100 AS crosses_boundary
                FROM
                    unique_gurasid ug
                  LEFT JOIN (
                        SELECT gurasid,
                            address AS alternate_address
                        FROM public."project_properties"
                        WHERE principaladdresstype = ''Alternate''
                  ) alternate_subquery ON ug.gurasid = alternate_subquery.gurasid
                  LEFT JOIN (
                        SELECT gurasid,
                            address AS secondary_address
                        FROM public."project_properties"
                        WHERE principaladdresstype = ''Secondary''
                  ) secondary_subquery ON ug.gurasid = secondary_subquery.gurasid
                  CROSS JOIN LATERAL (
                      SELECT DISTINCT ON (p.gurasid) p.*
                      FROM public."project_properties" p
                      WHERE ST_Covers(%L, st_pointonsurface(p.geom))
                  ) AS filtered
                WHERE ug.gurasid = filtered.gurasid
                GROUP BY ug.gurasid, ug.address, ug.valnetpropertystatus, ug.valnetpropertytype, ug.geom;',
                'kyng_' || kyng_name_value || '_property_view',
                kyng_row.kyng,
                kyng_row.kyng,
                kyng_row.geom
            );
        END LOOP;

    RAISE NOTICE 'Views for polygons and points created successfully.';
END;
$$;


ALTER FUNCTION "public"."create_kyngs_views"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_property_for_user"("user_id" "uuid", "var_principaladdresssiteoid" integer, "var_valid_address_street" "text", "var_valid_address_suburb" "text", "var_valid_address_postcode" "text", "var_search_address_street" "text", "var_search_address_suburb" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    var_property_uuid UUID;
BEGIN
    -- Check if user already has this property
    IF NOT EXISTS (
        SELECT 1 
        FROM user_property_profile_join upj
        JOIN property_profile pp ON pp.id = upj.property_id
        WHERE upj.user_id = create_property_for_user.user_id 
        AND pp.principaladdresssiteoid = var_principaladdresssiteoid
    ) THEN
        -- Rest of the function remains the same
        IF NOT EXISTS (
            SELECT 1 
            FROM property_profile 
            WHERE principaladdresssiteoid = var_principaladdresssiteoid
        ) THEN
            var_property_uuid := gen_random_uuid();
            
            INSERT INTO property_profile (
                id,
                principaladdresssiteoid, 
                property_address_street, 
                property_address_suburb, 
                property_address_postcode
            )
            VALUES (
                var_property_uuid,
                var_principaladdresssiteoid, 
                var_valid_address_street, 
                var_valid_address_suburb, 
                var_valid_address_postcode
            );

            INSERT INTO property_geometry (
                id, 
                principaladdresssiteoid, 
                address_point, 
                way_point, 
                property
            )
            VALUES (
                var_property_uuid,
                var_principaladdresssiteoid,
                (SELECT geom FROM project_addresspoints WHERE principaladdresssiteoid = var_principaladdresssiteoid),
                (SELECT geom FROM project_waypoints WHERE principaladdresssiteoid = var_principaladdresssiteoid),
                (SELECT geom FROM project_properties WHERE principaladdresssiteoid = var_principaladdresssiteoid)
            );
        ELSE
            SELECT id INTO var_property_uuid 
            FROM property_profile 
            WHERE principaladdresssiteoid = var_principaladdresssiteoid;
        END IF;

        INSERT INTO user_property_profile_join (
            user_id, 
            property_id, 
            search_address_street, 
            search_address_suburb
        )
        VALUES (
            create_property_for_user.user_id,
            var_property_uuid,
            var_search_address_street,
            var_search_address_suburb
        );
    END IF;
END;
$$;


ALTER FUNCTION "public"."create_property_for_user"("user_id" "uuid", "var_principaladdresssiteoid" integer, "var_valid_address_street" "text", "var_valid_address_suburb" "text", "var_valid_address_postcode" "text", "var_search_address_street" "text", "var_search_address_suburb" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."custom_access_token_hook"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  claims jsonb;
  user_role text;
  user_permissions text[];
  property_ids uuid[];
  community_slugs text[];
  coordinates_kyng jsonb;
BEGIN
  claims := event->'claims';
  
  -- Get primary role from user_roles_primary
  SELECT role INTO user_role 
  FROM public.user_roles_primary 
  WHERE user_id = (event->>'user_id')::uuid;
  
  -- Get permissions array from user_permissions
  SELECT array_agg(DISTINCT permission) INTO user_permissions
  FROM public.user_permissions
  WHERE user_id = (event->>'user_id')::uuid;
  
  -- Get property IDs
  SELECT array_agg(property_id) INTO property_ids
  FROM public.user_properties
  WHERE user_id = (event->>'user_id')::uuid;
  
  -- Get community slugs
  SELECT array_agg(community_slug) INTO community_slugs
  FROM public.user_communities
  WHERE user_id = (event->>'user_id')::uuid;
  
  -- Get KYNG area details (keep if still needed)
  SELECT jsonb_agg(
    jsonb_build_object(
      'kyngAreaId', k.id,
      'kyngName', k.kyng
    )
  ) INTO coordinates_kyng 
  FROM public.kyng_area_users_join j
  JOIN public.kyng_areas k ON k.id = j.kyng_area_id
  WHERE j.end_date IS NULL AND j.user_id = (event->>'user_id')::uuid;
  
  -- Set claims
  claims := jsonb_set(claims, '{user_role}', to_jsonb(COALESCE(user_role, 'user')));
  claims := jsonb_set(claims, '{permissions}', to_jsonb(COALESCE(user_permissions, ARRAY[]::text[])));
  claims := jsonb_set(claims, '{property_ids}', to_jsonb(COALESCE(property_ids, ARRAY[]::uuid[])));
  claims := jsonb_set(claims, '{community_slugs}', to_jsonb(COALESCE(community_slugs, ARRAY[]::text[])));
  
  IF coordinates_kyng IS NOT NULL THEN
    claims := jsonb_set(claims, '{coordinates_kyng}', coordinates_kyng);
  END IF;
  
  -- Update the event
  event := jsonb_set(event, '{claims}', claims);
  
  RETURN event;
END;
$$;


ALTER FUNCTION "public"."custom_access_token_hook"("event" "jsonb") OWNER TO "postgres";


