CREATE OR REPLACE FUNCTION "public"."delete_claim_for_email_array"("emails" "text"[], "claim" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare 
	email text[];
    BEGIN
		FOR email IN SELECT emails
			LOOP
				perform delete_email_claim(email::text, claim);
			END LOOP;
		return 'OK';
    END;
$$;


