CREATE OR REPLACE FUNCTION "public"."delete_email_claim"("email_input" "text", "claim" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    declare
		var_uuid uuid;
    BEGIN
		select id from auth.users where email = email_input into var_uuid;
		update auth.users set raw_app_meta_data = 
		  raw_app_meta_data - claim where id = var_uuid;
		return 'OK';
    END;
$$;


ALTER FUNCTION "public"."delete_email_claim"("email_input" "text", "claim" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_spatial_feature"("p_feature_id" "uuid", "p_user_id" "uuid", "p_property_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    -- Verify user has access to the property and feature exists
    IF NOT EXISTS (
        SELECT 1 
        FROM spatial_features sf
        WHERE sf.id = p_feature_id 
        AND sf.property_id = p_property_id
        AND sf.user_id = p_user_id
    ) THEN
        RETURN false;
    END IF;

    -- Delete the feature (cascade will handle attributes)
    DELETE FROM spatial_features 
    WHERE id = p_feature_id;

    RETURN true;
END;
$$;


ALTER FUNCTION "public"."delete_spatial_feature"("p_feature_id" "uuid", "p_user_id" "uuid", "p_property_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_unused_property_profile"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
 var_debug_property_profile_id uuid;
 var_debug_user_property_profile_join_property_id uuid;
BEGIN
	SELECT id FROM public.property_profile INTO var_debug_property_profile_id;
	SELECT property_id FROM public.user_property_profile_join INTO var_debug_user_property_profile_join_property_id;
	RAISE LOG '++++++++++++++++++++++var_debug_property_profile_id %', var_debug_property_profile_id;
	RAISE LOG '++++++++++++++++++++++var_debug_user_property_profile_join_property_id %', var_debug_user_property_profile_join_property_id;
    DELETE FROM public.property_profile
    WHERE id NOT IN (
        SELECT property_id
        FROM public.user_property_profile_join
    );
    RETURN OLD;
END;
$$;


ALTER FUNCTION "public"."delete_unused_property_profile"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dev_process_downloads"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$

DECLARE
  var_boundary_rings text;
  var_custom_principaladdresssiteoids text;
  var_debug1 text;
  var_debug text;
begin
  truncate table project_addresspoints;
  WITH boundary AS (
    SELECT ST_AsGeoJSON(ST_Transform(ST_Union(project_area.geom), 4326)) AS project_boundary from project_area
  )
  SELECT project_boundary::json -> 'coordinates' FROM boundary into var_boundary_rings;
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with addresspoints_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
      'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || 
      '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS addresspoints_json
  ),
  result_addresspoints AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS addresspointoid,
      feature::json -> 'properties' ->> 'address'::TEXT AS address,
      feature::json -> 'properties' ->> 'housenumber'::TEXT AS housenumber,
      CASE
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '2' THEN 'Unit/Strata'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '3' THEN 'Building'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '4' THEN 'Homestead'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '5' THEN 'Monument'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '10' THEN 'Other'
      END AS addresspointtype,
      CASE
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
      END AS containment,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM addresspoints_query
  ),
  addresstrings_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/3/query',
      'where=' || urlencode('msoid in (' || (SELECT string_agg(addressstringoid::text, ',') FROM result_addresspoints) || ')') || 
      '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS addressstrings_json
  ),
  result_addressstrings AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS addressstringoid,
      (feature::json -> 'properties' ->> 'addresssitename')::text as addresssitename,
      (feature::json -> 'properties' ->> 'buildingname')::text as buildingname,
      (feature::json -> 'properties' ->> 'locationdescription')::text as locationdescription,
      (feature::json -> 'properties' ->> 'roadname')::text as roadname,
      (feature::json -> 'properties' ->> 'roadtype')::text as roadtype,
      (feature::json -> 'properties' ->> 'roadsuffix')::text as roadsuffix,
      (feature::json -> 'properties' ->> 'suburbname')::text as suburbname,
      'NSW' as state,
      (feature::json -> 'properties' ->> 'postcode')::text as postcode,
      (feature::json -> 'properties' ->> 'council')::text as council,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '1' THEN 'Property Address'
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '2' THEN 'Delivery Address'
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '3' THEN 'Correspondence Address'
	  END AS addresstype,
      CASE
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '1' then 'Rural'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '2' then 'Urban'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '3' then 'Unknown'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '4' then 'Waterway'
      END AS ruraladdress,
      CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '1' THEN 'Official Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '2' THEN 'Alias Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '3' THEN 'Unchecked Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '4' THEN 'Verified Address'
	  END AS addressstringtype,  
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
	  END AS roadside,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
	  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'officialaddressstringoid')::INT AS officialaddressstringoid,
      (feature::json -> 'properties' ->> 'deliverypointid')::INT AS deliverypointid,
      (feature::json -> 'properties' ->> 'routeoid')::INT AS routeoid,
      (feature::json -> 'properties' ->> 'gnafprimarysiteid')::INT AS gnafprimarysiteid,
      (feature::json -> 'properties' ->> 'propid')::INT AS propid,
      (feature::json -> 'properties' ->> 'sppropid')::INT AS sppropid,
      CASE
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '0' THEN 'No other data source matches'
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '1' THEN 'One data source matches'
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '2' THEN 'Two data sources match'
      END AS addressconfidence,
      CASE
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
      END AS containment,
      (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
		  ELSE 'Unknown'
	  END AS contributororigin,  
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '0' THEN 'GURAS != Valnet'
		  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '1' THEN 'GURAS = Valnet'
	  END AS contributoralignment,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate
    FROM addresstrings_query
  )
  INSERT INTO project_addresspoints(addresspointoid,addresssitename,buildingname,locationdescription,address,housenumber,
	roadname,roadtype,roadsuffix,suburbname,state,postcode,council,addresstype,ruraladdress,principaladdresstype,addressstringtype,
	roadside,officialaddressstringoid,deliverypointid,routeoid,gnafprimarysiteid,propid,sppropid,addressconfidence,contributorid, 
	contributororigin,contributoralignment,addresspointtype,containment,gurasid,principaladdresssiteoid,addressstringoid,startdate,
	lastupdate,enddate,geom)
  SELECT rap.addresspointoid,ras.addresssitename,ras.buildingname,ras.locationdescription,rap.address,rap.housenumber,
	ras.roadname,ras.roadtype,ras.roadsuffix,ras.suburbname,ras.state,ras.postcode,ras.council,ras.addresstype,ras.ruraladdress,
	ras.principaladdresstype,ras.addressstringtype,ras.roadside,ras.officialaddressstringoid,ras.deliverypointid,ras.routeoid,
	ras.gnafprimarysiteid,ras.propid,ras.sppropid,ras.addressconfidence,ras.contributorid,ras.contributororigin,
	ras.contributoralignment,rap.addresspointtype,rap.containment,rap.gurasid,rap.principaladdresssiteoid,rap.addressstringoid,rap.startdate,
	rap.lastupdate,rap.enddate,rap.geom 
	FROM result_addresspoints rap left join result_addressstrings ras on rap.addressstringoid = ras.addressstringoid;
  PERFORM http_reset_curlopt();
  truncate table project_waypoints;
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with waypoints_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/0/query',
      'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || 
      '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS waypoints_json
  ),
  result_waypoints AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS waypointoid,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
      (feature::json -> 'properties' ->> 'roadnameextentoid')::INT AS roadnameextentoid,
      CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
		  ELSE 'Unknown'
	  END AS contributororigin,
     (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
      CASE
		when (feature::json -> 'properties' ->> 'derivedby')::text = '1' then 'Urban Calculated'
		when (feature::json -> 'properties' ->> 'derivedby')::text = '2' then 'Rural Calculated'
		when (feature::json -> 'properties' ->> 'derivedby')::text = '3' then 'Rural Derived'
      END AS derivedby,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM waypoints_query
  )
  INSERT INTO project_waypoints(waypointoid,address,housenumber,gurasid,principaladdresssiteoid,addressstringoid,addresspointoid,
	roadnameextentoid,principaladdresstype,contributororigin,contributorid,derivedby,startdate,lastupdate,enddate,geom)
  SELECT rwp.waypointoid,pap.address,pap.housenumber,rwp.gurasid,rwp.principaladdresssiteoid,rwp.addressstringoid,rwp.addresspointoid,
  	rwp.roadnameextentoid,rwp.principaladdresstype,rwp.contributororigin,rwp.contributorid,rwp.derivedby,rwp.startdate,rwp.lastupdate,
  	rwp.enddate,rwp.geom 
	FROM result_waypoints rwp left join project_addresspoints pap on rwp.addresspointoid = pap.addresspointoid;  
  PERFORM http_reset_curlopt();
  truncate table project_proways;
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with proways_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/2/query',
      'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || 
      '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS proways_json
  ),
  result_proways AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS prowayoid,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'waypointoid')::INT AS waypointoid,
      (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
	  END AS roadside,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM proways_query
  )
  INSERT INTO project_proways(prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
	lastupdate,enddate,geom)
  SELECT prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
	lastupdate,enddate,geom 
	FROM result_proways;
  PERFORM http_reset_curlopt();
  truncate table project_properties;
  raise log '--DEBUG--- This works 1';
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  raise log '--DEBUG--- This works 2';
  select '{"rings": ' || var_boundary_rings || '}' into var_debug1;
  raise log 'Query is [ % ]', var_debug1;
  with properties_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme_multiCRS/FeatureServer/12/query',
      'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || 
      '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS properties_json
  ),
  result_properties AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS propertyoid,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '1' THEN 'All property Lots found in VALNET'
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '5' THEN 'One property Lot not found in VALNET'
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '6' THEN 'One or more property Lot not found in VALNET'
	  END AS propertytype,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '1' THEN 'CANCELLED'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '2' THEN 'CURRENT'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '3' THEN 'PROFORMA'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '4' THEN 'SKELETON'
	  END AS valnetpropertystatus,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '1' THEN 'Rural'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '2' THEN 'Urban'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '3' THEN 'Unknown'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '4' THEN 'Waterway'
	  END AS valnetpropertytype,
	  (feature::json -> 'properties' ->> 'dissolveparcelcount')::INT AS dissolveparcelcount,
	  (feature::json -> 'properties' ->> 'valnetlotcount')::INT AS valnetlotcount,
	  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
	  (feature::json -> 'properties' ->> 'superlot')::text AS superlot,
	  (feature::json -> 'properties' ->> 'housenumber')::text AS housenumber,
	  (feature::json -> 'properties' ->> 'address')::text AS address,
	  CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_Multi(ST_GeomFromGeoJSON(feature::json -> 'geometry'))), 7844) AS geom
    FROM properties_query
  )
  INSERT INTO project_properties(propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,
	valnetlotcount,propid,superlot,housenumber,address,principaladdresstype,gurasid,principaladdresssiteoid,
	addressstringoid,startdate,lastupdate,enddate,geom)
  SELECT propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,valnetlotcount,propid,superlot,housenumber,
  			address,principaladdresstype,gurasid,principaladdresssiteoid,addressstringoid,startdate,lastupdate,enddate,geom 
  FROM result_properties;
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with custom_addresses_query as
  (
  	SELECT ca.principaladdresssiteoid from custom_address ca where ca.principaladdresssiteoid NOT IN
	  (
	  	SELECT pap.principaladdresssiteoid from project_addresspoints pap
	  )
  )
  SELECT string_agg(principaladdresssiteoid::text, ',') FROM custom_addresses_query INTO var_custom_principaladdresssiteoids; 
  SELECT 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') into var_debug;
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with custom_addresspoints_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
      'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
      '&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS custom_addresspoints_json
  ),
  result_custom_addresspoints AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS addresspointoid,
      feature::json -> 'properties' ->> 'address'::TEXT AS address,
      feature::json -> 'properties' ->> 'housenumber'::TEXT AS housenumber,
      CASE
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '2' THEN 'Unit/Strata'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '3' THEN 'Building'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '4' THEN 'Homestead'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '5' THEN 'Monument'
        WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '10' THEN 'Other'
      END AS addresspointtype,
      CASE
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
      END AS containment,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM custom_addresspoints_query
  ),
  custom_addresstrings_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/3/query',
      'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
      '&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS custom_addressstrings_json
  ),
  result_custom_addressstrings AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS addressstringoid,
      (feature::json -> 'properties' ->> 'addresssitename')::text as addresssitename,
      (feature::json -> 'properties' ->> 'buildingname')::text as buildingname,
      (feature::json -> 'properties' ->> 'locationdescription')::text as locationdescription,
      (feature::json -> 'properties' ->> 'roadname')::text as roadname,
      (feature::json -> 'properties' ->> 'roadtype')::text as roadtype,
      (feature::json -> 'properties' ->> 'roadsuffix')::text as roadsuffix,
      (feature::json -> 'properties' ->> 'suburbname')::text as suburbname,
      'NSW' as state,
      (feature::json -> 'properties' ->> 'postcode')::text as postcode,
      (feature::json -> 'properties' ->> 'council')::text as council,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '1' THEN 'Property Address'
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '2' THEN 'Delivery Address'
		  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '3' THEN 'Correspondence Address'
	  END AS addresstype,
      CASE
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '1' then 'Rural'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '2' then 'Urban'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '3' then 'Unknown'
		when (feature::json -> 'properties' ->> 'ruraladdress')::text = '4' then 'Waterway'
      END AS ruraladdress,
      CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '1' THEN 'Official Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '2' THEN 'Alias Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '3' THEN 'Unchecked Address'
		  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '4' THEN 'Verified Address'
	  END AS addressstringtype,  
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
	  END AS roadside,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
	  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'officialaddressstringoid')::INT AS officialaddressstringoid,
      (feature::json -> 'properties' ->> 'deliverypointid')::INT AS deliverypointid,
      (feature::json -> 'properties' ->> 'routeoid')::INT AS routeoid,
      (feature::json -> 'properties' ->> 'gnafprimarysiteid')::INT AS gnafprimarysiteid,
      (feature::json -> 'properties' ->> 'propid')::INT AS propid,
      (feature::json -> 'properties' ->> 'sppropid')::INT AS sppropid,
      CASE
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '0' THEN 'No other data source matches'
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '1' THEN 'One data source matches'
        WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '2' THEN 'Two data sources match'
      END AS addressconfidence,
      CASE
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
        WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
      END AS containment,
      (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
		  ELSE 'Unknown'
	  END AS contributororigin,  
	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '0' THEN 'GURAS != Valnet'
		  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '1' THEN 'GURAS = Valnet'
	  END AS contributoralignment,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate
    FROM custom_addresstrings_query
  )
  INSERT INTO project_addresspoints(addresspointoid,addresssitename,buildingname,locationdescription,address,housenumber,
	roadname,roadtype,roadsuffix,suburbname,state,postcode,council,addresstype,ruraladdress,principaladdresstype,addressstringtype,
	roadside,officialaddressstringoid,deliverypointid,routeoid,gnafprimarysiteid,propid,sppropid,addressconfidence,contributorid, 
	contributororigin,contributoralignment,addresspointtype,containment,gurasid,principaladdresssiteoid,addressstringoid,startdate,
	lastupdate,enddate,geom)
  SELECT rcap.addresspointoid,rcas.addresssitename,rcas.buildingname,rcas.locationdescription,rcap.address,rcap.housenumber,
	rcas.roadname,rcas.roadtype,rcas.roadsuffix,rcas.suburbname,rcas.state,rcas.postcode,rcas.council,rcas.addresstype,rcas.ruraladdress,
	rcas.principaladdresstype,rcas.addressstringtype,rcas.roadside,rcas.officialaddressstringoid,rcas.deliverypointid,rcas.routeoid,
	rcas.gnafprimarysiteid,rcas.propid,rcas.sppropid,rcas.addressconfidence,rcas.contributorid,rcas.contributororigin,
	rcas.contributoralignment,rcap.addresspointtype,rcap.containment,rcap.gurasid,rcap.principaladdresssiteoid,rcap.addressstringoid,rcap.startdate,
	rcap.lastupdate,rcap.enddate,rcap.geom 
	FROM result_custom_addresspoints rcap left join result_custom_addressstrings rcas on rcap.addressstringoid = rcas.addressstringoid;
 PERFORM http_reset_curlopt();
 PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
 with custom_waypoints_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/0/query',
      'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
      '&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS waypoints_json
  ),
  result_custom_waypoints AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS waypointoid,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
      (feature::json -> 'properties' ->> 'roadnameextentoid')::INT AS roadnameextentoid,
      CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
		  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
		  ELSE 'Unknown'
	  END AS contributororigin,
     (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
      CASE
		when (feature::json -> 'properties' ->> 'derivedby')::text = '1' then 'Urban Calculated'
		when (feature::json -> 'properties' ->> 'derivedby')::text = '2' then 'Rural Calculated'
		when (feature::json -> 'properties' ->> 'derivedby')::text = '3' then 'Rural Derived'
      END AS derivedby,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM custom_waypoints_query
  )
  INSERT INTO project_waypoints(waypointoid,address,housenumber,gurasid,principaladdresssiteoid,addressstringoid,addresspointoid,
	roadnameextentoid,principaladdresstype,contributororigin,contributorid,derivedby,startdate,lastupdate,enddate,geom)
  SELECT rcwp.waypointoid,pap.address,pap.housenumber,rcwp.gurasid,rcwp.principaladdresssiteoid,rcwp.addressstringoid,rcwp.addresspointoid,
  	rcwp.roadnameextentoid,rcwp.principaladdresstype,rcwp.contributororigin,rcwp.contributorid,rcwp.derivedby,rcwp.startdate,rcwp.lastupdate,
  	rcwp.enddate,rcwp.geom 
	FROM result_custom_waypoints rcwp left join project_addresspoints pap on rcwp.addresspointoid = pap.addresspointoid;  
  PERFORM http_reset_curlopt();
	PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  with custom_proways_query AS (
    SELECT json_array_elements_text("content"::json -> 'features') AS feature
    FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/2/query',
      'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
      '&outSR=7844&outFields=*&f=geojson',
