      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'waypointoid')::INT AS waypointoid,
      (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
 	  CASE
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
		  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
	  END AS roadside,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
    FROM custom_proways_query
  )
  INSERT INTO project_proways(prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
	lastupdate,enddate,geom)
  SELECT prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
