      'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
      '&outSR=7844&outFields=*&f=geojson',
      'application/x-www-form-urlencoded') AS properties_json
  ),
  result_custom_properties AS (
    SELECT
      (feature::json -> 'properties' ->> 'msoid')::INT AS propertyoid,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '1' THEN 'All property Lots found in VALNET'
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '5' THEN 'One property Lot not found in VALNET'
		  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '6' THEN 'One or more property Lot not found in VALNET'
	  END AS propertytype,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '1' THEN 'CANCELLED'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '2' THEN 'CURRENT'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '3' THEN 'PROFORMA'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '4' THEN 'SKELETON'
	  END AS valnetpropertystatus,
  	  CASE
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '1' THEN 'Rural'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '2' THEN 'Urban'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '3' THEN 'Unknown'
		  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '4' THEN 'Waterway'
	  END AS valnetpropertytype,
	  (feature::json -> 'properties' ->> 'dissolveparcelcount')::INT AS dissolveparcelcount,
	  (feature::json -> 'properties' ->> 'valnetlotcount')::INT AS valnetlotcount,
	  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
	  (feature::json -> 'properties' ->> 'superlot')::text AS superlot,
	  (feature::json -> 'properties' ->> 'housenumber')::text AS housenumber,
	  (feature::json -> 'properties' ->> 'address')::text AS address,
	  CASE
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
		when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
      END AS principaladdresstype,
      (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
      (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
      (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
      TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
      ST_SetSRID(st_force2d(ST_Multi(ST_GeomFromGeoJSON(feature::json -> 'geometry'))), 7844) AS geom
    FROM custom_properties_query
  )
  INSERT INTO project_properties(propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,
	valnetlotcount,propid,superlot,housenumber,address,principaladdresstype,gurasid,principaladdresssiteoid,
	addressstringoid,startdate,lastupdate,enddate,geom)
  SELECT propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,valnetlotcount,propid,superlot,housenumber,
  			address,principaladdresstype,gurasid,principaladdresssiteoid,addressstringoid,startdate,lastupdate,enddate,geom 
  FROM result_custom_properties;
END;
$$;


ALTER FUNCTION "public"."dev_process_downloads"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dev_process_kyng_areas"() RETURNS TABLE("principaladdresssiteoid" integer, "addressstringoid" integer, "gurasid" integer, "addresspointtype" "text", "containment" "text", "urbanity" "text", "lastupdate" "date", "enddate" "date", "address" "text", "housenumber" "text", "geom" "extensions"."geometry")
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  kyng_record RECORD;
  result_record RECORD;
BEGIN
    -- Create a temporary table to store the results
    CREATE TEMP TABLE IF NOT EXISTS temp_results AS SELECT * FROM dev_process_kyng_areas() WITH NO DATA;

  	-- Iterate over each row in kyng_areas table
	FOR kyng_record IN SELECT kyng, kyng_areas.geom FROM kyng_areas LOOP
      -- Use a different name for the variable to avoid ambiguity
      WITH boundary AS (
        SELECT ST_AsGeoJSON(ST_Transform(kyng_record.geom, 4326)) AS result_boundary
      ),
      features_query AS (
        SELECT json_array_elements_text("content"::json -> 'features') AS feature
        FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
          'geometry=' || urlencode('{"rings": ' || (SELECT result_boundary::json -> 'coordinates' FROM boundary) || '}') || 
          '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelContains&outSR=4326&outFields=*&f=geojson',
          'application/x-www-form-urlencoded') AS response_json
      ),
      result_addreasspoints AS (
        SELECT
          (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
          (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
          (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
          CASE
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '1' THEN 'Property'
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '2' THEN 'Unit/Strata'
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '3' THEN 'Building'
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '4' THEN 'Homestead'
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '5' THEN 'Monument'
            WHEN (feature::json -> 'properties' -> 'addresspointtype')::TEXT = '10' THEN 'Other'
          END AS addresspointtype,
          CASE
            WHEN (feature::json -> 'properties' -> 'containment')::TEXT = '1' THEN 'Property'
            WHEN (feature::json -> 'properties' -> 'containment')::TEXT = '2' THEN 'Outside'
            WHEN (feature::json -> 'properties' -> 'containment')::TEXT = '3' THEN 'Unknown'
          END AS containment,
          feature::json -> 'properties' -> 'urbanity' AS urbanity,
          TO_TIMESTAMP(NULLIF((feature::json -> 'properties' -> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
          TO_TIMESTAMP(NULLIF((feature::json -> 'properties' -> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
          feature::json -> 'properties' -> 'address'::TEXT AS address,
          feature::json -> 'properties' -> 'housenumber'::TEXT AS housenumber,
          ST_SetSRID(ST_GeomFromGeoJSON(feature::json -> 'geometry'), 4326) AS geom
        FROM features_query
      )
      INSERT INTO temp_results
      SELECT * FROM result_addreasspoints;
    END LOOP;

    -- Return all results from the temporary table
    FOR result_record IN (SELECT * FROM temp_results) LOOP
    	principaladdresssiteoid := result_record.principaladdresssiteoid;
  		addressstringoid := result_record.addressstringoid;
  		gurasid := result_record.gurasid;
  		addresspointtype := result_record.addresspointtype;
  		containment := result_record.containment;
  		urbanity := result_record.urbanity;
  		lastupdate := result_record.lastupdate;
  		enddate := result_record.enddate;
  		address := result_record.address;
  		housenumber := result_record.housenumber;
  		geom := result_record.geom;
  		RETURN NEXT;
    END LOOP;

    -- Drop the temporary table

   return;
END;
$$;


ALTER FUNCTION "public"."dev_process_kyng_areas"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."end_kyng_area_user"("p_user_id" "uuid", "p_kyng_area_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_updated_id uuid;
BEGIN
    UPDATE public.kyng_area_users_join
    SET end_date = NOW()
    WHERE user_id = p_user_id 
    AND kyng_area_id = p_kyng_area_id
    AND end_date IS NULL
    RETURNING id INTO v_updated_id;
    
    RETURN v_updated_id;
END;
$$;


ALTER FUNCTION "public"."end_kyng_area_user"("p_user_id" "uuid", "p_kyng_area_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."extract_addresspoints"("rings_geometry" "text", "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_total_count int := 0;
  v_batch_count int := 0;
  v_offset int := 0;
  v_batch_size int := 1000;
  v_retry_count int;
  v_backoff_seconds int;
  v_string_count int := 0;
  v_string_batch_count int := 0;
  v_oid_list text;
  v_oid_batch text[];
  v_oid_cursor CURSOR FOR SELECT DISTINCT addressstringoid FROM tmp_addresspoints WHERE addressstringoid IS NOT NULL;
  v_oid_val int;
  v_oid_array int[];
  v_batch_start int;
  v_batch_end int;
  v_total_oids int;
BEGIN
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  -- Clean staging tables
  DROP TABLE IF EXISTS tmp_addresspoints;
  DROP TABLE IF EXISTS tmp_addressstrings;

  CREATE TEMP TABLE tmp_addresspoints (
    addresspointoid int,
    address text,
    housenumber text,
    addressstringoid int,
    gurasid int,
    principaladdresssiteoid int,
    containment text,
    addresspointtype text,
    startdate date,
    lastupdate date,
    enddate date,
    geom geometry(Point, 7844)
  );

  CREATE TEMP TABLE tmp_addressstrings (
    addressstringoid int,
    addresssitename text,
    buildingname text,
    locationdescription text,
    roadname text,
    roadtype text,
    roadsuffix text,
    suburbname text,
    state text,
    postcode text,
    council text,
    addresstype text,
    ruraladdress text,
    principaladdresstype text,
    addressstringtype text,
    roadside text,
    officialaddressstringoid int,
    deliverypointid int,
    routeoid int,
    gnafprimarysiteid int,
    propid int,
    sppropid int,
    addressconfidence text,
    contributorid text,
    contributororigin text,
    contributoralignment text
  );

  ---------------------------------------------------------------------------
  -- PHASE 1: Spatial query on FeatureServer/1 (AddressPoint) for geometry
  ---------------------------------------------------------------------------
  LOOP
    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    LOOP
      BEGIN
        WITH addresspoints_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
            'geometry=' || urlencode('{"rings": ' || rings_geometry || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson' ||
            '&resultOffset=' || v_offset ||
            '&resultRecordCount=' || v_batch_size,
            'application/x-www-form-urlencoded'
          )
          WHERE content IS NOT NULL
        ),
        result_addresspoints AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS addresspointoid,
            feature::json -> 'properties' ->> 'address' AS address,
            feature::json -> 'properties' ->> 'housenumber' AS housenumber,
            NULLIF(feature::json -> 'properties' ->> 'addressstringoid', '')::INT AS addressstringoid,
            NULLIF(feature::json -> 'properties' ->> 'gurasid', '')::INT AS gurasid,
            NULLIF(feature::json -> 'properties' ->> 'principaladdresssiteoid', '')::INT AS principaladdresssiteoid,
            CASE
              WHEN feature::json -> 'properties' ->> 'containment' = '1' THEN 'Yes'
              WHEN feature::json -> 'properties' ->> 'containment' = '2' THEN 'No'
              WHEN feature::json -> 'properties' ->> 'containment' = '3' THEN 'Unknown'
              ELSE NULL
            END AS containment,
            feature::json -> 'properties' ->> 'addresspointtype' AS addresspointtype,
            (TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'startdate', '')::NUMERIC / 1000.0))::date AS startdate,
            (TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'lastupdate', '')::NUMERIC / 1000.0))::date AS lastupdate,
            (TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'enddate', '')::NUMERIC / 1000.0))::date AS enddate,
            ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
          FROM addresspoints_query
        )
        INSERT INTO tmp_addresspoints(
          addresspointoid, address, housenumber, addressstringoid, gurasid,
          principaladdresssiteoid, containment, addresspointtype, startdate,
          lastupdate, enddate, geom
        )
        SELECT
          addresspointoid, address, housenumber, addressstringoid, gurasid,
          principaladdresssiteoid, containment, addresspointtype, startdate,
          lastupdate, enddate, geom
        FROM result_addresspoints
        WHERE addresspointoid IS NOT NULL;

        GET DIAGNOSTICS v_batch_count = ROW_COUNT;
        v_total_count := v_total_count + v_batch_count;

        RAISE NOTICE 'AddressPoints Phase 1 batch at offset %: % records', v_offset, v_batch_count;
        EXIT;

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'AddressPoints Phase 1 retry % of % for offset % due to error: %, waiting % seconds',
            v_retry_count, max_retries, v_offset, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'AddressPoints Phase 1 failed after % retries at offset %: %', max_retries, v_offset, SQLERRM;
        END IF;
      END;
    END LOOP;

    EXIT WHEN v_batch_count = 0;
    v_offset := v_offset + v_batch_count;
  END LOOP;

  RAISE NOTICE 'Phase 1 complete: % addresspoints extracted', v_total_count;

  IF v_total_count = 0 THEN
    PERFORM http_reset_curlopt();
    RAISE WARNING 'Function completed successfully but no records were returned from NSW Spatial Services';
    RETURN 0;
  END IF;

  ---------------------------------------------------------------------------
  -- PHASE 2: Query FeatureServer/3 (AddressString) by msoid batches
  ---------------------------------------------------------------------------
  SELECT array_agg(DISTINCT addressstringoid)
  INTO v_oid_array
  FROM tmp_addresspoints
  WHERE addressstringoid IS NOT NULL;

  v_total_oids := coalesce(array_length(v_oid_array, 1), 0);
  RAISE NOTICE 'Phase 2: enriching % unique addressstringoids from AddressString layer', v_total_oids;

  v_batch_start := 1;
  WHILE v_batch_start <= v_total_oids LOOP
    v_batch_end := LEAST(v_batch_start + 99, v_total_oids);  -- batches of 100

    -- Build comma-separated OID list for this batch
    SELECT string_agg(v_oid_array[i]::text, ',')
    INTO v_oid_list
    FROM generate_series(v_batch_start, v_batch_end) AS i;

    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    LOOP
      BEGIN
        WITH strings_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_get(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/3/query?where=' ||
            urlencode('msoid IN (' || v_oid_list || ')') ||
            '&outFields=*&f=geojson&resultRecordCount=1000'
          )
          WHERE content IS NOT NULL
        ),
        result_strings AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS addressstringoid,
            feature::json -> 'properties' ->> 'addresssitename' AS addresssitename,
            feature::json -> 'properties' ->> 'buildingname' AS buildingname,
            feature::json -> 'properties' ->> 'locationdescription' AS locationdescription,
            feature::json -> 'properties' ->> 'roadname' AS roadname,
            feature::json -> 'properties' ->> 'roadtype' AS roadtype,
            feature::json -> 'properties' ->> 'roadsuffix' AS roadsuffix,
            feature::json -> 'properties' ->> 'suburbname' AS suburbname,
            CASE
              WHEN feature::json -> 'properties' ->> 'state' = '1' THEN 'ACT'
              WHEN feature::json -> 'properties' ->> 'state' = '2' THEN 'NSW'
              WHEN feature::json -> 'properties' ->> 'state' = '3' THEN 'VIC'
              WHEN feature::json -> 'properties' ->> 'state' = '4' THEN 'QLD'
              WHEN feature::json -> 'properties' ->> 'state' = '5' THEN 'SA'
              WHEN feature::json -> 'properties' ->> 'state' = '6' THEN 'TAS'
              WHEN feature::json -> 'properties' ->> 'state' = '7' THEN 'WA'
              WHEN feature::json -> 'properties' ->> 'state' = '8' THEN 'NT'
              WHEN feature::json -> 'properties' ->> 'state' = '9' THEN 'OT'
              ELSE feature::json -> 'properties' ->> 'state'
            END AS state,
            feature::json -> 'properties' ->> 'postcode' AS postcode,
            feature::json -> 'properties' ->> 'council' AS council,
            CASE
              WHEN feature::json -> 'properties' ->> 'addresstype' = '1' THEN 'Urban'
              WHEN feature::json -> 'properties' ->> 'addresstype' = '2' THEN 'Rural'
              ELSE feature::json -> 'properties' ->> 'addresstype'
            END AS addresstype,
            CASE
              WHEN feature::json -> 'properties' ->> 'ruraladdress' = '1' THEN 'Yes'
              WHEN feature::json -> 'properties' ->> 'ruraladdress' = '2' THEN 'No'
              ELSE feature::json -> 'properties' ->> 'ruraladdress'
            END AS ruraladdress,
            CASE
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '1' THEN 'Primary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '2' THEN 'Secondary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '3' THEN 'Alternate'
              ELSE feature::json -> 'properties' ->> 'principaladdresstype'
            END AS principaladdresstype,
            CASE
              WHEN feature::json -> 'properties' ->> 'addressstringtype' = '1' THEN 'Unofficial'
              WHEN feature::json -> 'properties' ->> 'addressstringtype' = '2' THEN 'Alternative'
              WHEN feature::json -> 'properties' ->> 'addressstringtype' = '3' THEN 'Official'
              ELSE feature::json -> 'properties' ->> 'addressstringtype'
            END AS addressstringtype,
            CASE
              WHEN feature::json -> 'properties' ->> 'roadside' = '1' THEN 'Left'
              WHEN feature::json -> 'properties' ->> 'roadside' = '2' THEN 'Right'
              WHEN feature::json -> 'properties' ->> 'roadside' = '3' THEN 'Unknown'
              ELSE feature::json -> 'properties' ->> 'roadside'
            END AS roadside,
            NULLIF(feature::json -> 'properties' ->> 'officialaddressstringoid', '')::INT AS officialaddressstringoid,
            NULLIF(feature::json -> 'properties' ->> 'deliverypointid', '')::INT AS deliverypointid,
            NULLIF(feature::json -> 'properties' ->> 'routeoid', '')::INT AS routeoid,
            NULLIF(feature::json -> 'properties' ->> 'gnafprimarysiteid', '')::INT AS gnafprimarysiteid,
            NULLIF(feature::json -> 'properties' ->> 'propid', '')::INT AS propid,
            NULLIF(feature::json -> 'properties' ->> 'sppropid', '')::INT AS sppropid,
            feature::json -> 'properties' ->> 'addressconfidence' AS addressconfidence,
            feature::json -> 'properties' ->> 'contributorid' AS contributorid,
            CASE
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '1' THEN 'Council'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '2' THEN 'VALNET'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '4' THEN 'GNAF'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '6' THEN 'GURAS'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '8' THEN 'Land and Housing Corporation'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '9' THEN 'RAAP'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '10' THEN 'Australia Post'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '11' THEN 'GURAS App'
              ELSE feature::json -> 'properties' ->> 'contributororigin'
            END AS contributororigin,
            CASE
              WHEN feature::json -> 'properties' ->> 'contributoralignment' = '1' THEN 'Manual'
              WHEN feature::json -> 'properties' ->> 'contributoralignment' = '2' THEN 'Auto'
              ELSE feature::json -> 'properties' ->> 'contributoralignment'
            END AS contributoralignment
          FROM strings_query
        )
        INSERT INTO tmp_addressstrings
        SELECT * FROM result_strings
        WHERE addressstringoid IS NOT NULL;

        GET DIAGNOSTICS v_string_batch_count = ROW_COUNT;
        v_string_count := v_string_count + v_string_batch_count;

        RAISE NOTICE 'AddressStrings batch %-%: % records', v_batch_start, v_batch_end, v_string_batch_count;
        EXIT;

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'AddressStrings retry % of % for batch %-%: %, waiting % seconds',
            v_retry_count, max_retries, v_batch_start, v_batch_end, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'AddressStrings query failed after % retries for batch %-%: %', max_retries, v_batch_start, v_batch_end, SQLERRM;
        END IF;
      END;
    END LOOP;

    v_batch_start := v_batch_end + 1;
  END LOOP;

  RAISE NOTICE 'Phase 2 complete: % addressstrings enriched', v_string_count;

  ---------------------------------------------------------------------------
  -- PHASE 3: Join and insert into project_addresspoints
  ---------------------------------------------------------------------------
  PERFORM http_reset_curlopt();

  TRUNCATE TABLE project_addresspoints;

  INSERT INTO project_addresspoints(
    addresspointoid, address, housenumber, addressstringoid, gurasid,
    principaladdresssiteoid, containment, addresspointtype, startdate,
    lastupdate, enddate, geom,
    addresssitename, buildingname, locationdescription, roadname, roadtype,
    roadsuffix, suburbname, state, postcode, council, addresstype,
    ruraladdress, principaladdresstype, addressstringtype, roadside,
    officialaddressstringoid, deliverypointid, routeoid, gnafprimarysiteid,
    propid, sppropid, addressconfidence, contributorid, contributororigin,
    contributoralignment
  )
  SELECT
    ap.addresspointoid, ap.address, ap.housenumber, ap.addressstringoid, ap.gurasid,
    ap.principaladdresssiteoid, ap.containment, ap.addresspointtype, ap.startdate,
    ap.lastupdate, ap.enddate, ap.geom,
    astr.addresssitename, astr.buildingname, astr.locationdescription, astr.roadname,
    astr.roadtype, astr.roadsuffix, astr.suburbname, astr.state, astr.postcode,
    astr.council, astr.addresstype, astr.ruraladdress, astr.principaladdresstype,
    astr.addressstringtype, astr.roadside, astr.officialaddressstringoid,
    astr.deliverypointid, astr.routeoid, astr.gnafprimarysiteid, astr.propid,
    astr.sppropid, astr.addressconfidence, astr.contributorid, astr.contributororigin,
    astr.contributoralignment
  FROM tmp_addresspoints ap
  LEFT JOIN tmp_addressstrings astr ON ap.addressstringoid = astr.addressstringoid;

  RAISE NOTICE 'Phase 3 complete: inserted % records into project_addresspoints', v_total_count;

  RETURN v_total_count;
END;
$$;


ALTER FUNCTION "public"."extract_addresspoints"("rings_geometry" "text", "max_retries" integer, "initial_backoff" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."extract_addresspoints_wgs1984"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare
  count_value integer;
  offset_value integer := 0;
BEGIN
  -- Get the total count
  WITH boundary AS (
    SELECT ST_AsGeoJSON(ST_Transform(ST_Union(communities.geom), 4326)) AS result
    FROM communities
  ),
  count_query AS (
    SELECT (("content"::json -> 'properties' ->> 'count')::text)::int as num_points
    FROM http_post(
        'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
        '&geometry=' || urlencode('{"rings": ' || (SELECT result::json -> 'coordinates' FROM boundary) || '}') ||
        '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelContains&outSR=4326&returnCountOnly=true&f=geojson',
        'application/x-www-form-urlencoded'
    ) AS response_json
  )
  SELECT num_points INTO count_value
  FROM count_query;
  truncate table public.address_point_extract;
  WHILE offset_value < count_value LOOP
    WITH boundary AS (
      SELECT ST_AsGeoJSON(ST_Transform(ST_Union(communities.geom), 4326)) AS result
      FROM communities
    ),
    features_query AS (
      SELECT json_array_elements_text("content"::json -> 'features') AS feature
      FROM http_post(
          'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
          '&geometry=' || urlencode('{"rings": ' || (SELECT result::json -> 'coordinates' FROM boundary) || '}') ||
          '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelContains&outSR=4326&outFields=*&f=geojson',
          'application/x-www-form-urlencoded'
      ) AS response_json
    ),
    results AS (
      SELECT  
        (feature::json -> 'properties' ->> 'principaladdresssiteoid')::int AS principaladdresssiteoid,
        (feature::json -> 'properties' ->> 'addressstringoid')::int AS addressstringoid,
        (feature::json -> 'properties' ->> 'gurasid')::int AS gurasid,
        CASE
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '1' THEN 'Property'
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '2' THEN 'Unit/Strata'
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '3' THEN 'Building'
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '4' THEN 'Homestead'
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '5' THEN 'Monument'
          WHEN (feature::json -> 'properties' -> 'addresspointtype')::text = '10' THEN 'Other'
        END AS addresspointtype,  
        CASE
          WHEN (feature::json -> 'properties' -> 'containment')::text = '1' THEN 'Property'
          WHEN (feature::json -> 'properties' -> 'containment')::text = '2' THEN 'Outside'
          WHEN (feature::json -> 'properties' -> 'containment')::text = '3' THEN 'Unknown'
        END AS containment,  
        feature::json -> 'properties' -> 'urbanity' AS urbanity,
        TO_TIMESTAMP(NULLIF((feature::json -> 'properties' -> 'lastupdate')::text, '')::numeric / 1000.0) AS lastupdate, 
        TO_TIMESTAMP(NULLIF((feature::json -> 'properties' -> 'enddate')::text, '')::numeric / 1000.0) AS enddate,
        feature::json -> 'properties' -> 'address'::text AS address,
        feature::json -> 'properties' -> 'housenumber'::text AS housenumber,
        ST_SetSRID(ST_GeomFromGeoJSON(feature::json -> 'geometry'), 4326) AS geom
      FROM features_query
    )
    INSERT INTO public.address_point_extract (principaladdresssiteoid, addressstringoid, gurasid, addresspointtype, containment, lastupdate, enddate, address, housenumber, geom)
    SELECT r.principaladdresssiteoid, r.addressstringoid, r.gurasid, r.addresspointtype, r.containment, r.lastupdate, r.enddate, r.address, r.housenumber, r.geom
    FROM results r;
    offset_value := offset_value + 2000;
  END LOOP;
END
$$;


ALTER FUNCTION "public"."extract_addresspoints_wgs1984"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."extract_properties"("rings_geometry" "text", "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_total_count int := 0;
  v_batch_count int := 0;
  v_offset int := 0;
  v_batch_size int := 1000;
  v_retry_count int;
  v_backoff_seconds int;
BEGIN
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  DROP TABLE IF EXISTS tmp_properties;
  CREATE TEMP TABLE tmp_properties (LIKE project_properties INCLUDING ALL);

  -- Pagination loop to handle API result limits
  LOOP
    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    -- Retry loop for this batch
    LOOP
      BEGIN
        WITH properties_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme_multiCRS/FeatureServer/12/query',
            'geometry=' || urlencode('{"rings": ' || rings_geometry || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson' ||
            '&resultOffset=' || v_offset ||
            '&resultRecordCount=' || v_batch_size,
            'application/x-www-form-urlencoded'
          )
          WHERE content IS NOT NULL
        ),
        result_properties AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS propertyoid,
            CASE
              WHEN feature::json -> 'properties' ->> 'propertytype' = '1' THEN 'All property Lots found in VALNET'
              WHEN feature::json -> 'properties' ->> 'propertytype' = '5' THEN 'One property Lot not found in VALNET'
              WHEN feature::json -> 'properties' ->> 'propertytype' = '6' THEN 'One or more property Lot not found in VALNET'
              ELSE NULL
            END AS propertytype,
            CASE
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '1' THEN 'CANCELLED'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '2' THEN 'CURRENT'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '3' THEN 'PROFORMA'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '4' THEN 'SKELETON'
              ELSE NULL
            END AS valnetpropertystatus,
            CASE
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '1' THEN 'Rural'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '2' THEN 'Urban'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '3' THEN 'Unknown'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '4' THEN 'Waterway'
              ELSE NULL
            END AS valnetpropertytype,
            NULLIF(feature::json -> 'properties' ->> 'dissolveparcelcount', '')::INT AS dissolveparcelcount,
            NULLIF(feature::json -> 'properties' ->> 'valnetlotcount', '')::INT AS valnetlotcount,
            NULLIF(feature::json -> 'properties' ->> 'propid', '')::INT AS propid,
            feature::json -> 'properties' ->> 'superlot' AS superlot,
            feature::json -> 'properties' ->> 'housenumber' AS housenumber,
            feature::json -> 'properties' ->> 'address' AS address,
            CASE
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '1' THEN 'Primary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '2' THEN 'Secondary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '3' THEN 'Alternate'
              ELSE NULL
            END AS principaladdresstype,
            NULLIF(feature::json -> 'properties' ->> 'gurasid', '')::INT AS gurasid,
            NULLIF(feature::json -> 'properties' ->> 'principaladdresssiteoid', '')::INT AS principaladdresssiteoid,
            NULLIF(feature::json -> 'properties' ->> 'addressstringoid', '')::INT AS addressstringoid,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'startdate', '')::NUMERIC / 1000.0) AS startdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'lastupdate', '')::NUMERIC / 1000.0) AS lastupdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'enddate', '')::NUMERIC / 1000.0) AS enddate,
            ST_SetSRID(st_force2d(ST_Multi(ST_GeomFromGeoJSON(feature::json -> 'geometry'))), 7844) AS geom
          FROM properties_query
        )
        INSERT INTO tmp_properties(
          propertyoid, propertytype, valnetpropertystatus, valnetpropertytype, dissolveparcelcount,
          valnetlotcount, propid, superlot, housenumber, address, principaladdresstype, gurasid,
          principaladdresssiteoid, addressstringoid, startdate, lastupdate, enddate, geom
        )
        SELECT
          propertyoid, propertytype, valnetpropertystatus, valnetpropertytype, dissolveparcelcount,
          valnetlotcount, propid, superlot, housenumber, address, principaladdresstype, gurasid,
          principaladdresssiteoid, addressstringoid, startdate, lastupdate, enddate, geom
        FROM result_properties
        WHERE propertyoid IS NOT NULL;

        GET DIAGNOSTICS v_batch_count = ROW_COUNT;
        v_total_count := v_total_count + v_batch_count;

        RAISE NOTICE 'Properties batch at offset %: % records', v_offset, v_batch_count;
        EXIT; -- success for this batch

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'Properties retry % of % for offset % due to error: %, waiting % seconds',
            v_retry_count, max_retries, v_offset, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'Properties query failed after % retries at offset %: %', max_retries, v_offset, SQLERRM;
        END IF;
      END;
    END LOOP;

    -- Exit pagination loop only when no records returned
    EXIT WHEN v_batch_count = 0;

    v_offset := v_offset + v_batch_count;  -- Use actual records returned, not batch_size
  END LOOP;

  PERFORM http_reset_curlopt();

  IF v_total_count > 0 THEN
    TRUNCATE TABLE project_properties;
    INSERT INTO project_properties SELECT * FROM tmp_properties;
    RAISE NOTICE 'Inserted % records into project_properties', v_total_count;
  ELSE
    RAISE WARNING 'Function completed successfully but no records were returned from NSW Spatial Services';
  END IF;

  RETURN v_total_count;
END;
$$;


ALTER FUNCTION "public"."extract_properties"("rings_geometry" "text", "max_retries" integer, "initial_backoff" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."extract_properties_singlepart"("rings_geometry" "text", "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_total_count int := 0;
  v_batch_count int := 0;
  v_offset int := 0;
  v_batch_size int := 1000;
  v_retry_count int;
  v_backoff_seconds int;
BEGIN
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  DROP TABLE IF EXISTS tmp_properties_singlepart;
  CREATE TEMP TABLE tmp_properties_singlepart (LIKE project_properties_singlepart INCLUDING ALL);

  -- Pagination loop to handle API result limits
  LOOP
    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    -- Retry loop for this batch
    LOOP
      BEGIN
        WITH properties_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme_multiCRS/FeatureServer/12/query',
            'geometry=' || urlencode('{"rings": ' || rings_geometry || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson' ||
            '&resultOffset=' || v_offset ||
            '&resultRecordCount=' || v_batch_size,
            'application/x-www-form-urlencoded'
          )
          WHERE content IS NOT NULL
        ),
        result_properties AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS propertyoid,
            CASE
              WHEN feature::json -> 'properties' ->> 'propertytype' = '1' THEN 'All property Lots found in VALNET'
              WHEN feature::json -> 'properties' ->> 'propertytype' = '5' THEN 'One property Lot not found in VALNET'
              WHEN feature::json -> 'properties' ->> 'propertytype' = '6' THEN 'One or more property Lot not found in VALNET'
              ELSE NULL
            END AS propertytype,
            CASE
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '1' THEN 'CANCELLED'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '2' THEN 'CURRENT'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '3' THEN 'PROFORMA'
              WHEN feature::json -> 'properties' ->> 'valnetpropertystatus' = '4' THEN 'SKELETON'
              ELSE NULL
            END AS valnetpropertystatus,
            CASE
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '1' THEN 'Rural'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '2' THEN 'Urban'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '3' THEN 'Unknown'
              WHEN feature::json -> 'properties' ->> 'valnetpropertytype' = '4' THEN 'Waterway'
              ELSE NULL
            END AS valnetpropertytype,
            NULLIF(feature::json -> 'properties' ->> 'dissolveparcelcount', '')::INT AS dissolveparcelcount,
            NULLIF(feature::json -> 'properties' ->> 'valnetlotcount', '')::INT AS valnetlotcount,
            NULLIF(feature::json -> 'properties' ->> 'propid', '')::INT AS propid,
            feature::json -> 'properties' ->> 'superlot' AS superlot,
            feature::json -> 'properties' ->> 'housenumber' AS housenumber,
            feature::json -> 'properties' ->> 'address' AS address,
            CASE
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '1' THEN 'Primary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '2' THEN 'Secondary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '3' THEN 'Alternate'
              ELSE NULL
            END AS principaladdresstype,
            NULLIF(feature::json -> 'properties' ->> 'gurasid', '')::INT AS gurasid,
            NULLIF(feature::json -> 'properties' ->> 'principaladdresssiteoid', '')::INT AS principaladdresssiteoid,
            NULLIF(feature::json -> 'properties' ->> 'addressstringoid', '')::INT AS addressstringoid,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'startdate', '')::NUMERIC / 1000.0) AS startdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'lastupdate', '')::NUMERIC / 1000.0) AS lastupdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'enddate', '')::NUMERIC / 1000.0) AS enddate,
            ST_SetSRID(st_force2d((ST_Dump(ST_GeomFromGeoJSON(feature::json -> 'geometry'))).geom), 7844) AS geom
          FROM properties_query
        )
        INSERT INTO tmp_properties_singlepart(
          propertyoid, propertytype, valnetpropertystatus, valnetpropertytype, dissolveparcelcount,
          valnetlotcount, propid, superlot, housenumber, address, principaladdresstype, gurasid,
          principaladdresssiteoid, addressstringoid, startdate, lastupdate, enddate, geom
        )
        SELECT
          propertyoid, propertytype, valnetpropertystatus, valnetpropertytype, dissolveparcelcount,
          valnetlotcount, propid, superlot, housenumber, address, principaladdresstype, gurasid,
          principaladdresssiteoid, addressstringoid, startdate, lastupdate, enddate, geom
        FROM result_properties
        WHERE propertyoid IS NOT NULL;

        GET DIAGNOSTICS v_batch_count = ROW_COUNT;
        v_total_count := v_total_count + v_batch_count;

        RAISE NOTICE 'Properties (singlepart) batch at offset %: % records', v_offset, v_batch_count;
        EXIT; -- success for this batch

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'Properties (singlepart) retry % of % for offset % due to error: %, waiting % seconds',
            v_retry_count, max_retries, v_offset, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'Properties (singlepart) query failed after % retries at offset %: %', max_retries, v_offset, SQLERRM;
        END IF;
      END;
    END LOOP;

    -- Exit pagination loop only when no records returned
    EXIT WHEN v_batch_count = 0;

    v_offset := v_offset + v_batch_count;  -- Use actual records returned, not batch_size
  END LOOP;

  PERFORM http_reset_curlopt();

  IF v_total_count > 0 THEN
    TRUNCATE TABLE project_properties_singlepart;
    INSERT INTO project_properties_singlepart SELECT * FROM tmp_properties_singlepart;
    RAISE NOTICE 'Inserted % records into project_properties_singlepart', v_total_count;
  ELSE
    RAISE WARNING 'Function completed successfully but no records were returned from NSW Spatial Services';
  END IF;

  RETURN v_total_count;
END;
$$;


