CREATE OR REPLACE FUNCTION "public"."extract_proways"("rings_geometry" "text", "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_total_count int := 0;
  v_batch_count int := 0;
  v_offset int := 0;
  v_batch_size int := 1000;
  v_retry_count int;
  v_backoff_seconds int;
BEGIN
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  DROP TABLE IF EXISTS tmp_proways;
  CREATE TEMP TABLE tmp_proways (LIKE project_proways INCLUDING ALL);

  -- Pagination loop to handle API result limits
  LOOP
    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    -- Retry loop for this batch
    LOOP
      BEGIN
        WITH proways_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/2/query',
            'geometry=' || urlencode('{"rings": ' || rings_geometry || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson' ||
            '&resultOffset=' || v_offset ||
            '&resultRecordCount=' || v_batch_size,
            'application/x-www-form-urlencoded'
          )
          WHERE content IS NOT NULL
        ),
        result_proways AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS prowayoid,
            NULLIF(feature::json -> 'properties' ->> 'gurasid', '')::INT AS gurasid,
            NULLIF(feature::json -> 'properties' ->> 'principaladdresssiteoid', '')::INT AS principaladdresssiteoid,
            NULLIF(feature::json -> 'properties' ->> 'waypointoid', '')::INT AS waypointoid,
            NULLIF(feature::json -> 'properties' ->> 'addresspointoid', '')::INT AS addresspointoid,
            CASE
              WHEN feature::json -> 'properties' ->> 'roadside' = '1' THEN 'Left'
              WHEN feature::json -> 'properties' ->> 'roadside' = '2' THEN 'Right'
              WHEN feature::json -> 'properties' ->> 'roadside' = '3' THEN 'Unknown'
              ELSE NULL
            END AS roadside,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'startdate', '')::NUMERIC / 1000.0) AS startdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'lastupdate', '')::NUMERIC / 1000.0) AS lastupdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'enddate', '')::NUMERIC / 1000.0) AS enddate,
            ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
          FROM proways_query
        )
        INSERT INTO tmp_proways(
          prowayoid, gurasid, principaladdresssiteoid, waypointoid, addresspointoid,
          roadside, startdate, lastupdate, enddate, geom
        )
        SELECT
          prowayoid, gurasid, principaladdresssiteoid, waypointoid, addresspointoid,
          roadside, startdate, lastupdate, enddate, geom
        FROM result_proways
        WHERE prowayoid IS NOT NULL;

        GET DIAGNOSTICS v_batch_count = ROW_COUNT;
        v_total_count := v_total_count + v_batch_count;

        RAISE NOTICE 'Proways batch at offset %: % records', v_offset, v_batch_count;
        EXIT; -- success for this batch

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'Proways retry % of % for offset % due to error: %, waiting % seconds',
            v_retry_count, max_retries, v_offset, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'Proways query failed after % retries at offset %: %', max_retries, v_offset, SQLERRM;
        END IF;
      END;
    END LOOP;

    -- Exit pagination loop only when no records returned
    EXIT WHEN v_batch_count = 0;

    v_offset := v_offset + v_batch_count;  -- Use actual records returned, not batch_size
  END LOOP;

  PERFORM http_reset_curlopt();

  IF v_total_count > 0 THEN
    TRUNCATE TABLE project_proways;
    INSERT INTO project_proways SELECT * FROM tmp_proways;
    RAISE NOTICE 'Inserted % records into project_proways', v_total_count;
  ELSE
    RAISE WARNING 'Function completed successfully but no records were returned from NSW Spatial Services';
  END IF;

  RETURN v_total_count;
END;
$$;


