CREATE OR REPLACE FUNCTION "public"."extract_waypoints"("rings_geometry" "text", "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_total_count int := 0;
  v_batch_count int := 0;
  v_offset int := 0;
  v_batch_size int := 1000;
  v_retry_count int;
  v_backoff_seconds int;
BEGIN
  PERFORM http_reset_curlopt();
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  DROP TABLE IF EXISTS tmp_waypoints;
  CREATE TEMP TABLE tmp_waypoints (LIKE project_waypoints INCLUDING ALL);

  -- Pagination loop to handle API result limits
  LOOP
    v_retry_count := 0;
    v_backoff_seconds := initial_backoff;

    -- Retry loop for this batch
    LOOP
      BEGIN
        WITH waypoints_query AS (
          SELECT json_array_elements_text(content::json -> 'features') AS feature
          FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/0/query',
            'geometry=' || urlencode('{"rings": ' || rings_geometry || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson' ||
            '&resultOffset=' || v_offset ||
            '&resultRecordCount=' || v_batch_size,
            'application/x-www-form-urlencoded'
          )
          WHERE content IS NOT NULL
        ),
        result_waypoints AS (
          SELECT
            NULLIF(feature::json -> 'properties' ->> 'msoid', '')::INT AS waypointoid,
            NULLIF(feature::json -> 'properties' ->> 'gurasid', '')::INT AS gurasid,
            NULLIF(feature::json -> 'properties' ->> 'principaladdresssiteoid', '')::INT AS principaladdresssiteoid,
            NULLIF(feature::json -> 'properties' ->> 'addressstringoid', '')::INT AS addressstringoid,
            NULLIF(feature::json -> 'properties' ->> 'addresspointoid', '')::INT AS addresspointoid,
            NULLIF(feature::json -> 'properties' ->> 'roadnameextentoid', '')::INT AS roadnameextentoid,
            CASE
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '1' THEN 'Primary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '2' THEN 'Secondary'
              WHEN feature::json -> 'properties' ->> 'principaladdresstype' = '3' THEN 'Alternate'
              ELSE NULL
            END AS principaladdresstype,
            CASE
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '1' THEN 'Council'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '2' THEN 'VALNET'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '4' THEN 'GNAF'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '6' THEN 'GURAS'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '8' THEN 'Land and Housing Corporation'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '9' THEN 'RAAP'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '10' THEN 'Australia Post'
              WHEN feature::json -> 'properties' ->> 'contributororigin' = '11' THEN 'GURAS App'
              ELSE 'Unknown'
            END AS contributororigin,
            (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
            CASE
              WHEN feature::json -> 'properties' ->> 'derivedby' = '1' THEN 'Urban Calculated'
              WHEN feature::json -> 'properties' ->> 'derivedby' = '2' THEN 'Rural Calculated'
              WHEN feature::json -> 'properties' ->> 'derivedby' = '3' THEN 'Rural Derived'
              ELSE NULL
            END AS derivedby,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'startdate', '')::NUMERIC / 1000.0) AS startdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'lastupdate', '')::NUMERIC / 1000.0) AS lastupdate,
            TO_TIMESTAMP(NULLIF(feature::json -> 'properties' ->> 'enddate', '')::NUMERIC / 1000.0) AS enddate,
            ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
          FROM waypoints_query
        )
        INSERT INTO tmp_waypoints(
          waypointoid, gurasid, principaladdresssiteoid, addressstringoid,
          addresspointoid, roadnameextentoid, principaladdresstype, contributororigin,
          contributorid, derivedby, startdate, lastupdate, enddate, geom
        )
        SELECT
          rwp.waypointoid, rwp.gurasid, rwp.principaladdresssiteoid, rwp.addressstringoid,
          rwp.addresspointoid, rwp.roadnameextentoid, rwp.principaladdresstype,
          rwp.contributororigin, rwp.contributorid, rwp.derivedby, rwp.startdate,
          rwp.lastupdate, rwp.enddate, rwp.geom
        FROM result_waypoints rwp;

        GET DIAGNOSTICS v_batch_count = ROW_COUNT;
        v_total_count := v_total_count + v_batch_count;

        RAISE NOTICE 'Waypoints batch at offset %: % records', v_offset, v_batch_count;
        EXIT; -- success for this batch

      EXCEPTION WHEN OTHERS THEN
        v_retry_count := v_retry_count + 1;
        IF v_retry_count <= max_retries THEN
          RAISE NOTICE 'Waypoints retry % of % for offset % due to error: %, waiting % seconds',
            v_retry_count, max_retries, v_offset, SQLERRM, v_backoff_seconds;
          PERFORM http_reset_curlopt();
          PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
          PERFORM pg_sleep(v_backoff_seconds);
          v_backoff_seconds := v_backoff_seconds * 2;
        ELSE
          PERFORM http_reset_curlopt();
          RAISE EXCEPTION 'Waypoints query failed after % retries at offset %: %', max_retries, v_offset, SQLERRM;
        END IF;
      END;
    END LOOP;

    -- Exit pagination loop only when no records returned
    EXIT WHEN v_batch_count = 0;

    v_offset := v_offset + v_batch_count;
  END LOOP;

  PERFORM http_reset_curlopt();

  IF v_total_count > 0 THEN
    TRUNCATE TABLE project_waypoints;
    INSERT INTO project_waypoints SELECT * FROM tmp_waypoints;
    RAISE NOTICE 'Inserted % records into project_waypoints', v_total_count;
  ELSE
    RAISE WARNING 'Function completed successfully but no records were returned from NSW Spatial Services';
  END IF;

  RETURN v_total_count;
END;
$$;


ALTER FUNCTION "public"."extract_waypoints"("rings_geometry" "text", "max_retries" integer, "initial_backoff" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_functions_with_string"("search_string" "text") RETURNS SETOF "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    function_name text;
BEGIN
    FOR function_name IN
        SELECT routine_name
        FROM information_schema.routines
        WHERE routine_definition ILIKE '%' || search_string || '%'
        AND routine_schema = 'public'
    LOOP
        RETURN NEXT function_name;
    END LOOP;
    
    RETURN;
END;
$$;


ALTER FUNCTION "public"."find_functions_with_string"("search_string" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_orphaned_attributes"() RETURNS TABLE("attribute_id" "uuid", "feature_id" "uuid", "field_id" "uuid")
    LANGUAGE "sql" SECURITY DEFINER
    AS $$
    SELECT 
        fa.id as attribute_id,
        fa.feature_id,
        fa.field_id
    FROM feature_attributes fa
    LEFT JOIN spatial_features sf ON fa.feature_id = sf.id
    WHERE sf.id IS NULL;
$$;


ALTER FUNCTION "public"."find_orphaned_attributes"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."find_orphaned_spatial_features"() RETURNS TABLE("feature_id" "uuid", "template_id" "uuid", "property_id" "uuid", "user_id" "uuid")
    LANGUAGE "sql" SECURITY DEFINER
    AS $$
    SELECT 
        sf.id as feature_id,
        sf.template_id,
        sf.property_id,
        sf.user_id
    FROM spatial_features sf
    LEFT JOIN feature_templates ft ON sf.template_id = ft.id
    LEFT JOIN property_profile pp ON sf.property_id = pp.id
    LEFT JOIN user_profile up ON sf.user_id = up.id
    WHERE ft.id IS NULL 
    OR pp.id IS NULL 
    OR up.id IS NULL;
$$;


ALTER FUNCTION "public"."find_orphaned_spatial_features"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."first_function"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  extent_rings_geometry TEXT;
  kyng_rings_geometry TEXT;
BEGIN
	-- Get the extent rings text
	SELECT '' || '{"rings": ' ||  ((ST_AsGeoJSON(ST_Extent(geom)))::json -> 'coordinates')  || '}' || ''
	INTO extent_rings_geometry FROM kyng_areas;
	
	RAISE NOTICE 'extent rings text: %', extent_rings_geometry;



    -- Call the addresspoint extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_addresspoints(extent_rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_addresspoints() completed successfully.';

    -- Call the waypoint extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_waypoints(extent_rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_waypoints() completed successfully.';

    -- Call the proway extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_proways(extent_rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_proways() completed successfully.';

    -- Call the property extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_properties(extent_rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_proways() completed successfully.';
END;
$$;


ALTER FUNCTION "public"."first_function"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_custom_geojson_features"("input_id" "uuid", "addresspointfeaturestyle" "text", "waypointfeaturestyle" "text", "propertyfeaturestyle" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    geojson_features jsonb[];
BEGIN
    SELECT ARRAY[
        jsonb_build_object(
            'leafletGeoJSONFeature',
            jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'id', pg.id,
                    'principaladdresssiteoid', pg.principaladdresssiteoid,
                    'created_at', pg.created_at,
                    'last_updated', pg.last_updated,
                    'featureType', 'AddressPoint'
                ),
                'geometry', ST_AsGeoJSON(ST_Force2D(pg.address_point))::jsonb
            ),
            'featureStyle', addresspointFeatureStyle
        ),
        jsonb_build_object(
            'leafletGeoJSONFeature',
            jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'id', pg.id,
                    'principaladdresssiteoid', pg.principaladdresssiteoid,
                    'created_at', pg.created_at,
                    'last_updated', pg.last_updated,
                    'featureType', 'WayPoint'
                ),
                'geometry', ST_AsGeoJSON(ST_Force2D(pg.way_point))::jsonb
            ),
            'featureStyle', waypointFeatureStyle
        ),
        jsonb_build_object(
            'leafletGeoJSONFeature',
            jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'id', pg.id,
                    'principaladdresssiteoid', pg.principaladdresssiteoid,
                    'created_at', pg.created_at,
                    'last_updated', pg.last_updated,
                    'featureType', 'Property'
                ),
                'geometry', ST_AsGeoJSON(ST_Force2D(pg.property))::jsonb
            ),
            'featureStyle', propertyFeatureStyle
        )
    ]
    INTO geojson_features
    FROM public.property_geometry pg
    WHERE pg.id = input_id;

    RETURN jsonb_agg(geojson_features);
END;
$$;


