CREATE OR REPLACE FUNCTION "public"."get_address_status"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text", OUT "status_message" "text", OUT "cadastral_id" "text", OUT "geom_coordinates" "extensions"."geometry", OUT "principaladdresssiteoid" integer, OUT "valid_address" "text") RETURNS "record"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    var_search_address text;
    var_where_clause text;
    address_exists boolean;
    api_response json;
    mapserver_response json;
    mapserver_url text;
BEGIN
    -- Store the search address
    SELECT upper(address_text) || ' ' || upper(given_suburb) INTO var_search_address;
    
    -- Get where clause
    SELECT public.get_query_address(upper(address_text), upper(given_suburb)) INTO var_where_clause;
    
    -- Check custom_address table
    PERFORM 1 FROM public.custom_address ca 
    WHERE ca.address IN (SELECT regexp_split_to_table(var_where_clause, ','));
    
    IF FOUND THEN
        status_message := 'Not a custom address';
        RETURN;
    END IF;
    
    -- Check project_addresspoints
    PERFORM 1 FROM public.project_addresspoints pa
    WHERE pa.address IN (SELECT regexp_split_to_table(var_where_clause, ','));
    
    IF FOUND THEN
        status_message := 'Not a custom address';
        RETURN;
    END IF;
    
    -- Query PSMA geocoder
    SELECT content::json INTO api_response
    FROM http((
        'GET',
        'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(var_search_address),
        ARRAY[http_header('Authorization', api_key)],
        NULL,
        NULL
    )::http_request);
    
    -- Extract cadastral identifier and geometry
    cadastral_id := api_response->'features'->0->'properties'->>'cadastralIdentifier';
    geom_coordinates := ST_SetSRID(
        ST_MakePoint(
            (api_response->'features'->0->'geometry'->'coordinates'->0->0)::float,
            (api_response->'features'->0->'geometry'->'coordinates'->0->1)::float
        ),
        4326
    );
    
    -- Check address validity
    IF (api_response->'features'->0->'matchCode'->>'streetName' = 'exact' AND
        api_response->'features'->0->'matchCode'->>'localityName' = 'exact' AND
        api_response->'features'->0->'matchCode'->>'streetNumber1' = 'exact' AND
        api_response->'features'->0->'matchCode'->>'streetType' = 'exact') THEN
        
        -- Construct mapserver URL with the geometry point
        mapserver_url := 'https://maps.six.nsw.gov.au/arcgis/rest/services/sixmaps/PropertyAddress/MapServer/3/query'
            || '?where=&text=&objectIds=&time='
            || '&geometry=' || ST_X(geom_coordinates) || '%2C' || ST_Y(geom_coordinates) || '%2C0'
            || '&geometryType=esriGeometryPoint&inSR=4326'
            || '&spatialRel=esriSpatialRelIntersects&relationParam='
            || '&outFields=principaladdresssiteoid%2C+address'
            || '&returnGeometry=true&returnTrueCurves=false&maxAllowableOffset='
            || '&geometryPrecision=&outSR=4326&returnIdsOnly=false&returnCountOnly=false'
            || '&orderByFields=&groupByFieldsForStatistics=&outStatistics='
            || '&returnZ=false&returnM=false&gdbVersion=&returnDistinctValues=false'
            || '&resultOffset=&resultRecordCount=&queryByDistance='
            || '&returnExtentsOnly=false&datumTransformation=&parameterValues='
            || '&rangeValues=&f=geojson';
            
        -- Query mapserver
        SELECT content::json INTO mapserver_response
        FROM http((
            'GET',
            mapserver_url,
            ARRAY[]::http_header[],
            NULL,
            NULL
        )::http_request);
        
        -- Extract principaladdresssiteoid and address if features exist
        IF jsonb_array_length(mapserver_response->'features') > 0 THEN
            principaladdresssiteoid := (mapserver_response->'features'->0->'properties'->>'principaladdresssiteoid')::integer;
            valid_address := mapserver_response->'features'->0->'properties'->>'address';
        END IF;
        
        status_message := 'Custom address';
    ELSE
        status_message := 'Not a valid address';
    END IF;
END;
$$;


ALTER FUNCTION "public"."get_address_status"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text", OUT "status_message" "text", OUT "cadastral_id" "text", OUT "geom_coordinates" "extensions"."geometry", OUT "principaladdresssiteoid" integer, OUT "valid_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_addresspoint_from_address"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text") RETURNS TABLE("status" integer, "searchaddressstreet" "text", "searchaddresssuburb" "text", "validaddressstreet" "text", "validaddresssuburb" "text", "validaddresspostcode" "text", "principaladdresssiteoid" integer, "community" "text", "kyng" "text")
    LANGUAGE "plpgsql"
    AS $$

declare
	var_search_address text;
	var_where_clause text;
	address_exists boolean;
	
begin
	select upper(address_text) || ' ' ||  upper(given_suburb) into var_search_address;

	select public.get_query_address(upper(address_text), upper(given_suburb)) into var_where_clause;

	return query 
	select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
		trim(both trim(trailing ca.suburb from ca.address)) as validaddressstreet, ca.suburb as validaddresssuburb, 
		ca.postcode as validaddresspostcode, ca.principaladdresssiteoid::int4 as principaladdresssiteoid, 
		ca.community as community, ca.kyng as kyng 
	from public.custom_address ca
	where ca.address in (select regexp_split_to_table(var_where_clause, ','));

	if not found then
		return query
		select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
			trim(both trim(trailing pa.suburbname from pa.address)) as validaddressstreet, pa.suburbname as validaddresssuburb, 
			pa.postcode as validaddresspostcode, pa.principaladdresssiteoid as principaladdresssiteoid, cas.community as community, ka.kyng as kyng 
		from public.project_addresspoints pa
		inner join community_areas cas 
		on ST_Intersects(pa.geom, cas.geom) 
		inner join kyng_areas ka 
		on ST_Intersects(pa.geom, ka.geom) 
		where pa.address in (select regexp_split_to_table(var_where_clause, ','));
	end if;

	-- if there is no match, query the psma geocoder 
	if not found then
		-- check if the address is a valid address
		SELECT
			content::json->'features'->0->'matchCode'->>'streetName' = 'exact' AND
			content::json->'features'->0->'matchCode'->>'localityName' = 'exact' AND
			content::json->'features'->0->'matchCode'->>'streetNumber1' = 'exact' AND
			content::json->'features'->0->'matchCode'->>'streetType' = 'exact'
		INTO address_exists
		FROM http((
				'GET',
				'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(var_search_address),
				ARRAY[http_header('Authorization', api_key)],
				NULL,
				NULL
			)::http_request);
		if address_exists then
			return query
			select 404 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
			'' as validaddressstreet, '' as validaddresssuburb, '' as validaddresspostcode, -1 as principaladdresssiteoid, 
			'' as community, '' as kyng; 
		else
			return query
			select 403 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
				'' as validaddressstreet, '' as validaddresssuburb, '' as validaddresspostcode, -1 as principaladdresssiteoid, 
				'' as community, '' as kyng;
		end if;
	end if;
end
$$;


ALTER FUNCTION "public"."get_addresspoint_from_address"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_addresspoint_from_principaladdresssiteoid"("principal_address_site_oid" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    address_response jsonb;
    result jsonb;
    max_retries constant integer := 3;
    current_retry integer := 0;
    success boolean := false;
    address_geom geometry;
BEGIN
    SET LOCAL statement_timeout = '30000';
    -- HTTP request with retries
    WHILE current_retry < max_retries AND NOT success LOOP
        BEGIN
            SELECT content::jsonb INTO address_response
            FROM http_get('https://maps.six.nsw.gov.au/arcgis/rest/services/sixmaps/PropertyAddress/MapServer/2/query?where=' || 
                         urlencode('AddressPoint.principaladdresssiteoid=' || principal_address_site_oid) || 
                         '&outFields=' || urlencode('AddressPoint.principaladdresssiteoid,addressstring.address,addressstring.suburbname,addressstring.postcode') || 
                         '&outSR=7844&f=geojson');
            success := true;
        EXCEPTION
            WHEN OTHERS THEN
                current_retry := current_retry + 1;
                IF current_retry = max_retries THEN
                    RAISE;
                END IF;
                PERFORM pg_sleep(1);
        END;
    END LOOP;

    -- Convert GeoJSON geometry to PostGIS geometry and force 2D
    address_geom := ST_Force2D(ST_SetSRID(
        ST_GeomFromGeoJSON(address_response->'features'->0->'geometry'::text),
        7844
    ));

    -- Build result JSON with spatial joins
    WITH spatial_data AS (
        SELECT 
            ca.community,
            ka.kyng
        FROM (SELECT address_geom::geometry(Point, 7844) as geom) pa
        LEFT JOIN community_areas ca ON ST_Intersects(pa.geom, ca.geom)
        LEFT JOIN kyng_areas ka ON ST_Intersects(pa.geom, ka.geom)
    )
    SELECT jsonb_build_object(
        'validaddressstreet', TRIM(BOTH FROM TRIM(TRAILING address_response->'features'->0->'properties'->>'addressstring.suburbname' 
                                FROM address_response->'features'->0->'properties'->>'addressstring.address')),
        'validaddresssuburb', address_response->'features'->0->'properties'->>'addressstring.suburbname',
        'validaddresspostcode', address_response->'features'->0->'properties'->>'addressstring.postcode',
        'principaladdresssiteoid', principal_address_site_oid,
        'community', sd.community,
        'kyng', sd.kyng,
        'geom', ST_AsGeoJSON(ST_Transform(address_geom, 4326))::jsonb
    )
    INTO result
    FROM spatial_data sd;

    RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_addresspoint_from_principaladdresssiteoid"("principal_address_site_oid" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_addresspoints_by_area"("kyng_area_id" "text") RETURNS json
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  result json;
BEGIN
  SELECT json_agg(row_to_json(t))
  INTO result
  FROM (
    SELECT
      row_number() OVER ()::integer AS rowid,
      addresssitename,
      address,
      housenumber,
      principaladdresstype,
      addresspointtype,
      addresstype,
      addressstringtype,
      roadside,
      deliverypointid,
      contributororigin,
      contributoralignment,
      gnafprimarysiteid,
      addresspointoid,
      principaladdresssiteoid,
      ST_AsGeoJSON(geom)::json AS geom
    FROM project_addresspoints
    WHERE ST_Within(geom, (
      SELECT ST_Union(geom)
      FROM kyng_areas
      WHERE id = kyng_area_id::uuid
    ))
  ) t;

  RETURN result;
END;
$$;


