CREATE OR REPLACE FUNCTION "public"."get_addresspoints_geojson"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
DECLARE
    result json;
    bounds json;
    centre json;
BEGIN
    -- Calculate bounds and center for all addresspoints
    WITH extent AS (
        SELECT ST_Extent(geom) AS bbox
        FROM project_addresspoints
        WHERE enddate = '3000-01-01'
    )
    SELECT 
        json_build_array(
            json_build_array(ST_YMin(bbox), ST_XMin(bbox)),
            json_build_array(ST_YMax(bbox), ST_XMax(bbox))
        ),
        json_build_array(
            ST_Y(ST_Centroid(bbox)),
            ST_X(ST_Centroid(bbox))
        )
    INTO bounds, centre
    FROM extent;

    WITH all_addresspoints AS (
        SELECT
            json_build_object(
                'type', 'FeatureCollection',
                'features', json_agg(
                    json_build_object(
                        'type', 'Feature',
                        'geometry', ST_AsGeoJSON(geom)::json,
                        'properties', json_build_object(
                            'id', id,
                            'addresspointoid', addresspointoid,
                            'enddate', enddate
                        )
                    )
                )
            ) AS all_addresspoints
        FROM project_addresspoints
        WHERE enddate = '3000-01-01'
    ),
    registered_addresspoints AS (
        SELECT
            json_build_object(
                'type', 'FeatureCollection',
                'features', json_agg(
                    json_build_object(
                        'type', 'Feature',
                        'geometry', ST_AsGeoJSON(a.geom)::json,
                        'properties', json_build_object(
                            'addresspointtype', a.addresspointtype::text
                        )
                    )
                )
            ) AS registered_addresspoints
        FROM project_addresspoints a
        JOIN community_areas c ON ST_Contains(c.geom, a.geom)
        WHERE a.principaladdresssiteoid IN (
            SELECT (raw_app_meta_data -> 'principaladdresssiteoid')::integer
            FROM auth.users
        )
        AND c.community = 'BCYCA'
    )
    SELECT json_build_object(
        'allAddresspoints', (SELECT all_addresspoints FROM all_addresspoints),
        'registeredAddresspoints', (SELECT registered_addresspoints FROM registered_addresspoints),
        'initialExtent', bounds,
        'centre', centre
    ) INTO result;
    
    RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_addresspoints_geojson"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_admin_messages_for_user"("id_input" "uuid") RETURNS TABLE("id" bigint, "message" "text", "created_at" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public'
    AS $$

begin
	return query
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and 
		(app_message.context = 'admins' or app_message.context = 'both') and 
		app_message.scope = 'all'
    UNION
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and 
		(app_message.context = 'admins' or app_message.context = 'both') and 
		app_message.scope like '%' || id_input::text || '%';
end;
$$;


ALTER FUNCTION "public"."get_admin_messages_for_user"("id_input" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_app_messages"() RETURNS TABLE("id" integer, "context" "text", "scope" "jsonb", "message" "text", "created_at" "text", "revoked" "text")
    LANGUAGE "sql" SECURITY DEFINER
    AS $$
    SELECT 
        am.id, 
        am.context,
        CASE 
            WHEN am.scope = 'all' THEN NULL
            ELSE (
                SELECT jsonb_object_agg(u.id::text, u.email)
                FROM auth.users u
                JOIN (
                    SELECT TRIM('"' FROM UNNEST(string_to_array(am.scope, ','))) AS user_id
                ) ids ON u.id::text = ids.user_id
            )
        END as scope,
        am.message,
        TO_CHAR(am.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at,
        TO_CHAR(am.revoked AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS revoked
    FROM public.app_message am;
$$;


ALTER FUNCTION "public"."get_app_messages"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_community_data"("community_name" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    result jsonb;
BEGIN
    WITH community_geom AS (
        SELECT 
            ST_Transform(geom, 4326) as geom
        FROM community_areas 
        WHERE community = community_name
    ),
    address_points AS (
        SELECT 
            json_build_object(
                'type', 'FeatureCollection',
                'features', json_agg(
                    json_build_object(
                        'type', 'Feature',
                        'geometry', ST_AsGeoJSON(ST_Transform(pa.geom, 4326))::json,
                        'properties', json_build_object(
                            'id', pa.id,
                            'address', pa.address,
                            'suburbname', pa.suburbname
                        )
                    )
                )
            ) as address_points_geojson
        FROM project_addresspoints pa
        JOIN community_geom cg ON ST_Contains(cg.geom, ST_Transform(pa.geom, 4326))
    ),
    registered_addresspoints AS (
        SELECT
            json_build_object(
                'type', 'FeatureCollection',
                'features', json_agg(
                    json_build_object(
                        'type', 'Feature',
                        'geometry', ST_AsGeoJSON(ST_Transform(a.geom, 4326))::json,
                        'properties', json_build_object(
                            'addresspointtype', a.addresspointtype::text
                        )
                    )
                )
            ) AS registered_points_geojson
        FROM project_addresspoints a
        JOIN community_geom cg ON ST_Contains(cg.geom, ST_Transform(a.geom, 4326))
        WHERE a.principaladdresssiteoid IN (
            SELECT (raw_app_meta_data -> 'principaladdresssiteoid')::integer
            FROM auth.users
        )
    ),
    community_bounds AS (
        SELECT 
            json_build_array(
                json_build_array(
                    ST_YMin(geom),
                    ST_XMin(geom)
                ),
                json_build_array(
                    ST_YMax(geom),
                    ST_XMax(geom)
                )
            ) as extent_bounds
        FROM community_geom
    )
    SELECT 
        jsonb_build_object(
            'community', json_build_object(
                'type', 'FeatureCollection',
                'features', json_agg(
                    json_build_object(
                        'type', 'Feature',
                        'geometry', ST_AsGeoJSON(ST_Transform(ca.geom, 4326))::json,
                        'properties', json_build_object(
                            'community', ca.community,
                            'coordinator', ca.coordinator
                        )
                    )
                )
            ),
            'addressPoints', (SELECT address_points_geojson FROM address_points),
            'registeredPoints', (SELECT registered_points_geojson FROM registered_addresspoints),
            'mapExtent', (SELECT extent_bounds FROM community_bounds)
        )
    INTO result
    FROM community_areas ca
    WHERE ca.community = community_name
    GROUP BY ca.community;

    RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_community_data"("community_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_enum_values"("enum_names" "text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    result jsonb = '{}'::jsonb;
    enum_name text;
BEGIN
    FOREACH enum_name IN ARRAY enum_names
    LOOP
        result = result || jsonb_build_object(
            enum_name,
            (
                SELECT jsonb_agg(enumlabel ORDER BY enumsortorder)
                FROM pg_enum
                WHERE enumtypid = (
                    SELECT oid 
                    FROM pg_type 
                    WHERE typname = enum_name
                )
            )
        );
    END LOOP;
    
    RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_enum_values"("enum_names" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_geojson"("uuid" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  kyng_geometry geometry;
  geojson json;
  addressspoint_result jsonb;
  waypoint_result jsonb;
  proway_result jsonb;
  property_result jsonb;


BEGIN
  SELECT INTO kyng_geometry geom
  FROM kyng_areas
  WHERE id = get_geojson.uuid;
  
  IF FOUND THEN
	-- Address points within the kyng area with rowid
	SELECT jsonb_agg(feature) INTO geojson
	FROM (
    	SELECT jsonb_build_object(
	      'type', 'Feature',
	      'properties', jsonb_build_object(
	        'rowid', rownum,
	        'Address Site Name', addresssitename,
	        'Address', address,
	        'House Number', housenumber,
	        'Principal Address Type', principaladdresstype,
	        'Address Point Type', addresspointtype,
	        'Address Type', addresstype,
	        'Address String Type', addressstringtype,
	        'Roadside', roadside,
	        'Delivery Point ID', deliverypointid,
	        'Contributor Origin', contributororigin,
	        'Contributor Alignment', contributoralignment,
	        'GNAF Primary Site ID', gnafprimarysiteid,
	        'Address Point OID', addresspointoid,
	        'Principal Address Site OID', principaladdresssiteoid
	      ),
	      'geometry', ST_AsGeoJSON(geom)::jsonb
	    ) AS feature
	    FROM (
	      SELECT *, ROW_NUMBER() OVER () AS rownum
	      FROM project_addresspoints
	      WHERE ST_Within(geom, kyng_geometry)
	    ) AS sub
	  ) AS features;

	  -- Wrap the features array in a FeatureCollection object
	  addressspoint_result := jsonb_build_object(
	    'type', 'FeatureCollection',
	    'features', geojson
	  );

    -- Waypoints related to address points with rowid and all properties
	SELECT jsonb_agg(feature) INTO geojson
	FROM (
    	SELECT jsonb_build_object(
	      'type', 'Feature',
	      'properties', jsonb_build_object(
			'rowid', rownum, 
			'Way Point OID', waypointoid,
			'Address', address,
			'Housenumber', housenumber,
			'gurasid', gurasid,
			'Principal Address Site OID', principaladdresssiteoid,
			'Address String OID', addressstringoid,
			'Address Point OID', addresspointoid,
			'Road Name Extent OID', roadnameextentoid,
			'Principal Address Type', principaladdresstype
		  ),
	      'geometry', ST_AsGeoJSON(geom)::jsonb
	    ) AS feature
	    FROM (
		  SELECT wp.*, ROW_NUMBER() OVER () AS rownum 
		  FROM project_waypoints wp INNER JOIN project_addresspoints addr 
		  ON wp.addresspointoid = addr.addresspointoid
	    ) AS sub
	  ) AS features;

	  -- Wrap the features array in a FeatureCollection object
	  waypoint_result := jsonb_build_object(
	    'type', 'FeatureCollection',
	    'features', geojson
	  );

    -- Proways related to waypoints with rowid and all properties
	SELECT jsonb_agg(feature) INTO geojson
	FROM (
    	SELECT jsonb_build_object(
	      'type', 'Feature',
	      'properties', jsonb_build_object(
			'rowid', rownum, 
			'prowayoid', prowayoid, 
			'gurasid', gurasid, 
			'Principal Address Site OID', principaladdresssiteoid, 
			'Way Point OID', waypointoid, 
			'Address Point OID', addresspointoid, 
			'Road Side', roadside
		  ),
	      'geometry', ST_AsGeoJSON(geom)::jsonb
	    ) AS feature
	    FROM (
		  SELECT prow.*, ROW_NUMBER() OVER () AS rownum 
		  FROM project_proways prow INNER JOIN project_waypoints wp 
		  ON prow.waypointoid = wp.waypointoid
	    ) AS sub
	  ) AS features;

	  -- Wrap the features array in a FeatureCollection object
	  proway_result := jsonb_build_object(
	    'type', 'FeatureCollection',
	    'features', geojson
	  );

	-- Properties related to the kyng area with rowid
	SELECT jsonb_agg(feature) INTO geojson
	FROM (
    	SELECT jsonb_build_object(
	      'type', 'Feature',
	      'properties', jsonb_build_object(
			'rowid', rownum, 
			'gurasid', gurasid, 
			'Address', address, 
			'VALNET Property Status', valnetpropertystatus, 
			'VALNET PropertyType', valnetpropertytype, 
			'Dissolve Parcel Count', dissolveparcelcount, 
			'VALNET Lot Count', valnetlotcount, 
			'Principal Address Site OID', principaladdresssiteoid
		  ),
	      'geometry', ST_AsGeoJSON(geom)::jsonb
	    ) AS feature
	    FROM (
		  SELECT *, ROW_NUMBER() OVER () AS rownum 
		  FROM public.project_properties p 
		  WHERE ST_Within(p.geom,(SELECT geom FROM kyng_areas WHERE id = get_geojson.uuid))
	    ) AS sub
	  ) AS features;

	  -- Wrap the features array in a FeatureCollection object
	  property_result := jsonb_build_object(
	    'type', 'FeatureCollection',
	    'features', geojson
	  );
  ELSE
  	RAISE EXCEPTION 'No matching kyng area found for UUID: %', get_geojson.uuid;
  END IF;

  RETURN jsonb_build_object(	
	'kyngArea', kyng_geometry,
    'addressPoints', addressspoint_result,
	'wayPoints', waypoint_result,
    'prowayLines', proway_result,
    'propertyAreas', property_result
  );
END;
$$;


ALTER FUNCTION "public"."get_geojson"("uuid" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_geometry_info_html"() RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    result_html text;
BEGIN
    SELECT INTO result_html
    '<style>
      .table-container {
        width: 100%;
        border-collapse: collapse;
      }
      .table-container th,
      .table-container td {
        padding: 8px;
        border: 1px solid #ddd;
      }
      .table-container th {
        text-align: center;
        background-color: #f2f2f2;
        font-weight: bold;
      }
      .table-container tr:nth-child(even) {
        background-color: #f2f2f2;
      }
    </style>
    <div class="table-container">
      <table>
        <tr>
          <th>Table</th>
          <th>Geometry Field & Type</th>
        </tr>' || STRING_AGG(
            '<tr>
              <td>' || table_schema || '.' || table_name || '</td>
              <td>' || array_to_string(geometry_fields, ', ') || '</td>
            </tr>'
            , '') || '</table>
    </div>'
    FROM (
        SELECT c.table_schema, c.table_name,
        ARRAY_AGG(c.column_name || ' (' || gc.type || ', SRID=' || gc.srid || ')') AS geometry_fields
        FROM information_schema.columns c
        JOIN information_schema.tables t ON
            c.table_schema = t.table_schema AND c.table_name = t.table_name
        JOIN extensions.geometry_columns gc ON
            c.column_name = gc.f_geometry_column AND c.table_name = gc.f_table_name
        WHERE c.data_type = 'USER-DEFINED' AND c.udt_name = 'geometry' AND t.table_type = 'BASE TABLE'
        GROUP BY c.table_schema, c.table_name, gc.type, gc.srid
    ) AS query_result;

    RETURN result_html;
END;
$$;


ALTER FUNCTION "public"."get_geometry_info_html"() OWNER TO "postgres";


