CREATE OR REPLACE FUNCTION "public"."get_kyngs_geojson"("uuid" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    kyng_geometry geometry;
    geojson json;
    addressspoint_result jsonb;
    waypoint_result jsonb;
    proway_result jsonb;
    property_result jsonb;
    address_point_ids int[]; 
    bounds_array numeric[];

BEGIN
    SELECT INTO kyng_geometry geom
    FROM kyng_areas
    WHERE id = get_kyngs_geojson.uuid;

    IF FOUND THEN
        -- Get the bounds as [minLat, minLng, maxLat, maxLng]
        SELECT ARRAY[
            ST_YMin(ST_Envelope(kyng_geometry)),
            ST_XMin(ST_Envelope(kyng_geometry)),
            ST_YMax(ST_Envelope(kyng_geometry)),
            ST_XMax(ST_Envelope(kyng_geometry))
        ] INTO bounds_array;
        -- Select features from project_properties where centroid is within the kyng area
        SELECT jsonb_agg(feature) INTO geojson
        FROM (
            SELECT jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'rowid', rownum, 
                    'gurasid', ug.gurasid,
                    'Address', ug.address,
                    'VALNET Property Status', ug.valnetpropertystatus,
                    'VALNET PropertyType', ug.valnetpropertytype,
                    'Dissolve Parcel Count', dissolveparcelcount, 
                    'VALNET Lot Count', valnetlotcount, 
                    'Principal Address Site OID', principaladdresssiteoid,
                    'Alternate Addresses', aa.alternate_addresses,
                    'Secondary Addresses', sa.secondary_addresses
                ),
                'geometry', ST_AsGeoJSON(sub.geom)::jsonb
            ) AS feature
            FROM (
                SELECT *, ROW_NUMBER() OVER () AS rownum 
                FROM public.project_properties p 
                WHERE ST_Within(ST_PointOnSurface(p.geom),(SELECT geom FROM kyng_areas WHERE id = get_kyngs_geojson.uuid))
            ) AS sub
            LEFT JOIN (
                SELECT DISTINCT ON (project_properties.gurasid) project_properties.gurasid,
                project_properties.address,
                project_properties.valnetpropertystatus,
                project_properties.valnetpropertytype,
                project_properties.geom
                FROM project_properties
                WHERE project_properties.principaladdresstype = 'Primary'
            ) AS ug ON sub.gurasid = ug.gurasid
            LEFT JOIN (
                SELECT project_properties.gurasid,
                string_agg(project_properties.address, ', ') AS alternate_addresses
                FROM project_properties
                WHERE project_properties.principaladdresstype = 'Alternate'
                GROUP BY project_properties.gurasid
            ) AS aa ON sub.gurasid = aa.gurasid
            LEFT JOIN (
                SELECT project_properties.gurasid,
                string_agg(project_properties.address, ', ') AS secondary_addresses
                FROM project_properties
                WHERE project_properties.principaladdresstype = 'Secondary'
                GROUP BY project_properties.gurasid
            ) AS sa ON sub.gurasid = sa.gurasid
        ) AS features;

        -- Wrap the features array in a FeatureCollection object
        property_result := jsonb_build_object(
            'type', 'FeatureCollection',
            'features', geojson
        );

        -- Select features from project_addresspoints where addresspointoid is in the address_point_ids array
        SELECT ARRAY_AGG(addr.addresspointoid) INTO address_point_ids
        FROM project_addresspoints addr
        WHERE ST_Within(addr.geom, kyng_geometry);

        SELECT jsonb_agg(feature) INTO geojson
        FROM (
            SELECT jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'rowid', rownum,
                    'Address Site Name', addresssitename,
                    'Address', address,
                    'House Number', housenumber,
                    'Principal Address Type', principaladdresstype,
                    'Address Point Type', addresspointtype,
                    'Address Type', addresstype,
                    'Address String Type', addressstringtype,
                    'Roadside', roadside,
                    'Delivery Point ID', deliverypointid,
                    'Contributor Origin', contributororigin,
                    'Contributor Alignment', contributoralignment,
                    'GNAF Primary Site ID', gnafprimarysiteid,
                    'Address Point OID', addresspointoid,
                    'Principal Address Site OID', principaladdresssiteoid
                ),
                'geometry', ST_AsGeoJSON(geom)::jsonb
            ) AS feature
            FROM (
                SELECT *, ROW_NUMBER() OVER () AS rownum
                FROM project_addresspoints
                WHERE ST_Within(geom, kyng_geometry)
            ) AS sub
        ) AS features;

        -- Wrap the features array in a FeatureCollection object
        addressspoint_result := jsonb_build_object(
            'type', 'FeatureCollection',
            'features', geojson
        );

        -- Select features from project_waypoints where addresspointoid is in the address_point_ids array
        SELECT jsonb_agg(feature) INTO geojson
        FROM (
            SELECT jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'rowid', rownum, 
                    'Way Point OID', waypointoid,
                    'Address', address,
                    'House Number', housenumber,
                    'gurasid', gurasid,
                    'Principal Address Site OID', principaladdresssiteoid,
                    'Address String OID', addressstringoid,
                    'Address Point OID', addresspointoid,
                    'Road Name Extent OID', roadnameextentoid,
                    'Principal Address Type', principaladdresstype
                ),
                'geometry', ST_AsGeoJSON(geom)::jsonb
            ) AS feature
            FROM (
                SELECT wp.*, ROW_NUMBER() OVER () AS rownum 
                FROM project_waypoints wp 
                WHERE wp.addresspointoid = ANY(address_point_ids)
            ) AS sub
        ) AS features;

        -- Wrap the features array in a FeatureCollection object
        waypoint_result := jsonb_build_object(
            'type', 'FeatureCollection',
            'features', geojson
        );

        -- Select features from project_proways where addresspointoid is in the address_point_ids array
        SELECT jsonb_agg(feature) INTO geojson
        FROM (
            SELECT jsonb_build_object(
                'type', 'Feature',
                'properties', jsonb_build_object(
                    'rowid', rownum, 
                    'prowayoid', prowayoid, 
                    'gurasid', gurasid, 
                    'Principal Address Site OID', principaladdresssiteoid, 
                    'Way Point OID', waypointoid, 
                    'Address Point OID', addresspointoid, 
                    'Road Side', roadside
                ),
                'geometry', ST_AsGeoJSON(geom)::jsonb
            ) AS feature
            FROM (
                SELECT prow.*, ROW_NUMBER() OVER () AS rownum 
                FROM project_proways prow 
                WHERE prow.addresspointoid = ANY(address_point_ids)
            ) AS sub
        ) AS features;

        -- Wrap the features array in a FeatureCollection object
        proway_result := jsonb_build_object(
            'type', 'FeatureCollection',
            'features', geojson
        );

        RETURN jsonb_build_object(
            'kyngArea', kyng_geometry,
            'addressPoints', addressspoint_result,
            'wayPoints', waypoint_result,
            'prowayLines', proway_result,
            'propertyAreas', property_result,
            'bounds', array[
                array[bounds_array[1], bounds_array[2]],
                array[bounds_array[3], bounds_array[4]]
            ]
        );
    ELSE
        RAISE EXCEPTION 'No matching kyng area found for UUID: %', get_kyngs_geojson.uuid;
    END IF;
END;
$$;


ALTER FUNCTION "public"."get_kyngs_geojson"("uuid" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_lists"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
	DECLARE
	  email_list json;
	  address_list json;
	  street_list json;
	  community_list json;
	  suburb_list json;
	  result json;
    begin
		SELECT json_agg(json_build_object('lut_text', email, 'user_id', id )) INTO email_list
		FROM (
		  SELECT id, lower(email) AS email
		  FROM auth.users
		  WHERE email_confirmed_at IS NOT NULL
		) AS subquery1;	
		SELECT json_agg(json_build_object('lut_text', address, 'user_id', user_ids)) INTO address_list
		FROM (
			SELECT CONCAT(pp.property_address_street, ', ', pp.property_address_suburb) AS address, json_agg(u.id) AS user_ids
			FROM auth.users u 
			JOIN user_property_profile_join upj ON u.id = upj.user_id
			JOIN property_profile pp ON upj.property_id = pp.id
			GROUP BY address
		) AS subquery2;
		SELECT json_agg(json_build_object('lut_text', street, 'user_id', user_ids)) INTO street_list
		FROM (
			SELECT UPPER(rtrim(ltrim(regexp_replace(property_address_street, '^\d+ ', '')))) as street, json_agg(u.id) AS user_ids
			FROM auth.users u 
			JOIN user_property_profile_join upj ON u.id = upj.user_id
			JOIN property_profile pp ON upj.property_id = pp.id
			GROUP BY street
		) AS subquery3;
		SELECT json_agg(json_build_object('lut_text', community, 'user_id', user_ids)) INTO community_list
		FROM (
			SELECT c.community AS community, json_agg(u.id) AS user_ids
			FROM community_areas c
			JOIN property_geometry pg ON ST_Within(pg.address_point, c.geom)
			JOIN property_profile pp ON pg.id = pp.id
			JOIN user_property_profile_join upj ON pp.id = upj.property_id
			JOIN auth.users u ON upj.user_id = u.id
			GROUP BY c.community
		) AS subquery4;
		
		SELECT json_agg(json_build_object('lut_text', suburb, 'user_id', user_ids)) INTO suburb_list
		FROM (
			SELECT upper(rtrim(ltrim(property_address_suburb))) as suburb, json_agg(u.id) AS user_ids
			FROM auth.users u 
			JOIN user_property_profile_join upj ON u.id = upj.user_id
			JOIN property_profile pp ON upj.property_id = pp.id
			GROUP BY suburb
		) AS subquery5;
			
		SELECT json_build_object('emailList', email_list, 'addressList', address_list, 'streetList', street_list, 'communityList', community_list, 'suburbList', suburb_list) INTO result;
		RETURN result;
    end;
$$;


ALTER FUNCTION "public"."get_lists"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_members"("api_key" "text", "list_id" "text") RETURNS SETOF json
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  url text := format('https://%s.api.mailchimp.com/3.0/lists/%s/members', substring(api_key from 33), list_id);
  headers text[] := array['Authorization', format('apikey %s', api_key)];
  response text;
  json_objs json;
BEGIN
  response := pgnet.get(url, headers);
  json_objs := (SELECT json_agg(elem) FROM json_array_elements(response::json->'members') AS elem);
  RETURN QUERY SELECT json_objs;
END;
$$;


ALTER FUNCTION "public"."get_members"("api_key" "text", "list_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_new_users_confirmed_without_address"() RETURNS TABLE("id" "uuid", "email" "text", "email_confirmed_at" timestamp without time zone, "last_sign_in_at" timestamp without time zone, "principaladdresssiteoid" integer, "address" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
    begin
	return query 
		WITH paoid_query AS (
		    SELECT string_agg(raw_user_meta_data->>'principaladdresssiteoid', ',') AS var_site_ids
		    FROM auth.users u
		    JOIN public.profile p ON p.id = u.id
		    WHERE u.email_confirmed_at IS NOT NULL 
		        AND (raw_app_meta_data->>'tester') IS NULL
		        AND property_address_street IS NULL
		),
		addressquery AS (
		    SELECT json_array_elements_text("content"::json -> 'features') AS feature
		    FROM http_post(
		        'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
		        'where=' || urlencode('principaladdresssiteoid IN (' || (SELECT var_site_ids FROM paoid_query) || ')') || 
		        '&outFields=principaladdresssiteoid,address&returnGeometry=false&f=geojson',
		        'application/x-www-form-urlencoded'
		    ) AS addresspoints_json
		),
		unaddressed_query AS (
		    SELECT u.id, u.email::text, u.email_confirmed_at AT TIME ZONE 'Australia/Sydney' AS email_confirmed_at, 
		        u.last_sign_in_at AT TIME ZONE 'Australia/Sydney' AS last_sign_in_at, 
		        (u.raw_user_meta_data->>'principaladdresssiteoid')::INT AS principaladdresssiteoid
		    FROM auth.users u
		    JOIN public.profile p ON p.id = u.id
		    WHERE u.email_confirmed_at IS NOT NULL 
		        AND (raw_app_meta_data->>'tester') IS NULL
		        AND property_address_street IS NULL
		)
		SELECT ua.id, ua.email::TEXT, 
		    ua.email_confirmed_at  AS email_confirmed_at, 
		    ua.last_sign_in_at AS last_sign_in_at, 
		    ua.principaladdresssiteoid AS principaladdresssiteoid,
		    a.feature::json -> 'properties' ->> 'address' AS address
		FROM unaddressed_query AS ua 
		JOIN addressquery AS a ON ua.principaladdresssiteoid = (a.feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT;
    END;
$$;


ALTER FUNCTION "public"."get_new_users_confirmed_without_address"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_new_users_confirmed_without_kits"() RETURNS TABLE("email" "text", "first_name" "text", "family_name" "text", "property_address_street" "text", "property_address_suburb" "text", "email_confirmed_at" "text", "landline" "text", "mobile" "text", "unanswered" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    BEGIN
	return query 
		with unkitted_properties as
		(
			SELECT users.email, users.id, users.email_confirmed_at
			FROM auth.users
			WHERE users.email_confirmed_at IS NOT NULL 
				AND (raw_app_meta_data->>'kit_date') IS NULL
				AND (raw_app_meta_data->>'tester') IS NULL
		)
		select ukp.email::text, p.first_name, p.family_name, p.property_address_street, p.property_address_suburb, ukp.email_confirmed_at::text, 
				case 
					when p.phone is null or  btrim(p.phone) = '' then 'Not Provided' 
					else p.phone
				end as landline,
				case 
					when p.mobile is null or  btrim(p.mobile) = '' then 'Not Provided' 
					else p.mobile
				end as mobile,
				rtrim((
				case when p.rfs_survival_plan is null then 'RFS Survival Plan, ' else '' end ||
				case when p.mobile_reception is null then 'Mobile Reception, ' else '' end ||
				case when p.fire_fighting_experience is null then 'Fire Fighting Experience, ' else '' end ||
				case when p.fire_trauma is null then 'Fire Trauma, ' else '' end ||
				case when p.plan_to_leave_before_fire is null then 'Plan to Leave Before Fire, ' else '' end ||
				case when p.plan_to_leave_before_flood is null then 'Plan to Leave Before Flood, ' else '' end ||
				case when p.residency_profile is null then 'Residency Profile, ' else '' end ||
				case 
					when p.property_rented = true and p.agent_name is null then 'Agent Name, ' 
					when p.property_rented = true and (p.agent_phone is null and p.agent_mobile is null) then 'Agent Phone/Mobile, ' 
					else '' 
				end ||
				case when p.sign_posted is null then 'Sign Posted, ' else '' end ||
				case when p.truck_access is null then 'Truck Access, ' else '' end ||
				case when p.truck_access = 4 and p.truck_access_other_information is null then 'Truck Access Other Information, ' else '' end ||
				case when p.residents0_18 = 0 and  p.residents19_50 = 0 and  p.residents51_70 = 0 and  p.residents71_ = 0 then 'Resident Census, ' else '' end ||
				case when p.vulnerable_residents is null then 'Vulnerable Residents, ' else '' end ||
				case when p.number_dogs = 0 and  p.number_cats = 0 and  p.number_birds = 0 and  p.number_other_pets = 0 then 'Pet Census, ' else '' end ||
				case when p.live_stock_present is null then 'Live Stock Present, ' else '' end ||
				case when p.live_stock_safe_area is null then 'Live Stock Safe Area, ' else '' end ||
				case when p.static_water_available  is null then 'Static Water, ' else '' end ||
				case when p.have_stortz  is null then 'Have Stortz, ' else '' end ||
				case when p.have_stortz = 'Y' and (stortz_size is null or stortz_size = 0) then 'Stortz Size, ' else '' end ||
				case when p.fire_hazard_reduction is null then 'Fire Hazard Reduction, ' else '' end ||
				case when p.fire_fighting_resources is null then 'Fire Fighting Resources, ' else '' end ||
				case when p.site_hazards  is null then 'Site Hazards, ' else '' end
			), ', ') as unanswered
		from public.profile p join unkitted_properties ukp on ukp.id = p.id;
    END;
$$;


ALTER FUNCTION "public"."get_new_users_confirmed_without_kits"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_new_users_unconfirmed"() RETURNS TABLE("email" "text", "applied_at" timestamp without time zone, "address" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$

BEGIN
    RETURN QUERY
    	WITH paoid_query AS (
    		SELECT string_agg(raw_user_meta_data->>'principaladdresssiteoid', ',') as var_site_ids
		    FROM auth.users
		    WHERE email_confirmed_at IS NULL
		),
    	authquery AS (
			SELECT users.email, 
				users.confirmation_sent_at  AT TIME ZONE 'Australia/Sydney' AS applied_at, 
				(raw_user_meta_data->>'principaladdresssiteoid')::INT AS principaladdresssiteoid
			FROM auth.users
			WHERE email_confirmed_at IS NULL 
				AND (raw_app_meta_data->>'tester') IS NULL
	    ),
	    addressquery AS (
		    SELECT json_array_elements_text("content"::json -> 'features') AS feature
		    FROM http_post(
		        'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query',
		        'where=' || urlencode('principaladdresssiteoid IN (' || (SELECT var_site_ids FROM paoid_query) || ')') || 
		        '&outFields=principaladdresssiteoid,address&returnGeometry=false&f=geojson',
		        'application/x-www-form-urlencoded'
		    ) AS addresspoints_json
	    )
    SELECT au.email::TEXT, au.applied_at, 
           a.feature::json -> 'properties' ->> 'address' AS address
    FROM authquery AS au 
    JOIN addressquery AS a ON au.principaladdresssiteoid = (a.feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT;
END;
$$;


ALTER FUNCTION "public"."get_new_users_unconfirmed"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_points_geometry"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'extensions'
    AS $$
DECLARE
  query_url TEXT := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query';
  body TEXT = '{
    "outFields" : "*",
    "returnGeometry" : "true",
    "outSR" : 4326,
    "f" : "geojson"
  }';
  response text;
BEGIN
  select
  	"content"::text
	from
	  http_post(query_url, body, 'application/json') into response;
  RETURN response;
END;
$$;


