CREATE OR REPLACE FUNCTION "public"."get_principaladdresssiteoid_from_cadastralidentifier"("cadastral_identifier" "text") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    guras_response jsonb;
    propid integer;
    address_response jsonb;
    principal_address_site_oid integer;
    max_retries constant integer := 2; 
    current_retry integer := 0;
    success boolean := false;
BEGIN
    PERFORM http_set_curlopt('CURLOPT_TIMEOUT', '180');
    PERFORM http_set_curlopt('CURLOPT_CONNECTTIMEOUT', '60');
   -- First HTTP request with retries 
    WHILE current_retry < max_retries AND NOT success LOOP
         BEGIN
			RAISE LOG '++++ Will select using % == retry %', cadastral_identifier, current_retry;
            SELECT content::jsonb INTO guras_response
            FROM http_get('https://maps.six.nsw.gov.au/arcgis/rest/services/sixmaps/Guras/MapServer/10/query' || 
                '?where=' || urlencode('ptlotsecpn=''' || cadastral_identifier || '''') ||
                '&outFields=propid&returnGeometry=false&f=pjson');
            success := true;
			RAISE LOG '++++ Done select retry %', current_retry;
        EXCEPTION
            WHEN OTHERS THEN
                current_retry := current_retry + 1;
                IF current_retry = max_retries THEN
                    RAISE;
                END IF;
                PERFORM pg_sleep(2); 
        END;
    END LOOP;

    -- Extract propid
    propid := (guras_response->'features'->0->'attributes'->>'propid')::integer;

    -- Reset retry counter and success flag
    current_retry := 0;
    success := false;

    -- Second HTTP request with retries
    WHILE current_retry < max_retries AND NOT success LOOP
        BEGIN
            SELECT content::jsonb INTO address_response
            FROM http_get('https://maps.six.nsw.gov.au/arcgis/rest/services/sixmaps/Guras/MapServer/9/query' ||
                '?where=' || urlencode('propid=' || propid::text) ||
                '&outFields=principaladdresssiteoid&returnGeometry=false&f=pjson');
            success := true;
        EXCEPTION
            WHEN OTHERS THEN
                 current_retry := current_retry + 1;
                IF current_retry = max_retries THEN
                    RAISE;
                END IF;
                PERFORM pg_sleep(2); 
        END;
    END LOOP;

    -- Extract and return principaladdresssiteoid
    RETURN (address_response->'features'->0->'attributes'->>'principaladdresssiteoid')::integer;
END;
$$;


ALTER FUNCTION "public"."get_principaladdresssiteoid_from_cadastralidentifier"("cadastral_identifier" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_profile_for_user"("id_input" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
result JSONB;
BEGIN
SELECT jsonb_build_object(
'family_name', up.family_name,
'fire_fighting_experience', up.fire_fighting_experience,
'fire_trauma', up.fire_trauma,
'first_name', up.first_name,
'mobile', up.mobile,
'other_comments', up.other_comments,
'plan_to_leave_before_fire', up.plan_to_leave_before_fire,
'plan_to_leave_before_flood', up.plan_to_leave_before_flood,
'residency_profile', up.residency_profile,
'rfs_survival_plan', up.rfs_survival_plan,
'stay_in_touch_choices', up.stay_in_touch_choices,
'community_bcyca_profile', (
    SELECT jsonb_build_object(
        'other_comments', cbp.other_comments,
        'bcyca_profile_id', cbp.bcyca_profile_id,
        'stay_in_touch_choices', cbp.stay_in_touch_choices,
        'other_community_meeting', cbp.other_community_meeting,
        'other_information_sheet', cbp.other_information_sheet,
        'other_community_workshop', cbp.other_community_workshop,
        'community_meeting_choices', cbp.community_meeting_choices,
        'information_sheet_choices', cbp.information_sheet_choices,
        'community_workshop_choices', cbp.community_workshop_choices,
        'will_run_community_workshops', cbp.will_run_community_workshops
    )
    FROM community_bcyca_profile cbp
    WHERE cbp.bcyca_profile_id::UUID = up.bcyca_profile_id::UUID
),
'community_tinonee_profile', (
    SELECT jsonb_build_object(
        'other_comments', ctp.other_comments,
        'tinonee_profile_id', ctp.tinonee_profile_id,
        'stay_in_touch_choices', ctp.stay_in_touch_choices,
        'other_community_meeting', ctp.other_community_meeting,
        'other_information_sheet', ctp.other_information_sheet,
        'other_community_workshop', ctp.other_community_workshop,
        'community_meeting_choices', ctp.community_meeting_choices,
        'information_sheet_choices', ctp.information_sheet_choices,
        'community_workshop_choices', ctp.community_workshop_choices,
        'will_run_community_workshops', ctp.will_run_community_workshops
    )
    FROM community_tinonee_profile ctp
    WHERE ctp.tinonee_profile_id::UUID = up.tinonee_profile_id::UUID
),
'community_mondrook_profile', (
    SELECT jsonb_build_object(
        'other_comments', cmp.other_comments,
        'mondrook_profile_id', cmp.mondrook_profile_id,
        'stay_in_touch_choices', cmp.stay_in_touch_choices,
        'other_community_meeting', cmp.other_community_meeting,
        'other_information_sheet', cmp.other_information_sheet,
        'other_community_workshop', cmp.other_community_workshop,
        'community_meeting_choices', cmp.community_meeting_choices,
        'information_sheet_choices', cmp.information_sheet_choices,
        'community_workshop_choices', cmp.community_workshop_choices,
        'will_run_community_workshops', cmp.will_run_community_workshops
    )
    FROM community_mondrook_profile cmp
    WHERE cmp.mondrook_profile_id::UUID = up.mondrook_profile_id::UUID
),
'community_external_profile', (
    SELECT jsonb_build_object(
        'other_comments', cep.other_comments,
        'external_profile_id', cep.external_profile_id,
        'stay_in_touch_choices', cep.stay_in_touch_choices,
        'other_community_meeting', cep.other_community_meeting,
        'other_information_sheet', cep.other_information_sheet,
        'other_community_workshop', cep.other_community_workshop,
        'community_meeting_choices', cep.community_meeting_choices,
        'information_sheet_choices', cep.information_sheet_choices,
        'community_workshop_choices', cep.community_workshop_choices,
        'will_run_community_workshops', cep.will_run_community_workshops
    )
    FROM community_external_profile cep
    WHERE cep.external_profile_id::UUID = up.external_profile_id::UUID
),
'user_postal_address', (
    SELECT jsonb_build_object(
        'postal_address_postcode', upa.postal_address_postcode,
        'postal_address_street', upa.postal_address_street,
        'postal_address_suburb', upa.postal_address_suburb
    )
    FROM user_postal_address upa
    WHERE upa.user_id::UUID = id_input::UUID
),
'property_profile', (
    SELECT jsonb_agg(jsonb_build_object(
        'id', pp.id,
        'phone', pp.phone,
        'kyng_areas', (
            SELECT jsonb_agg(jsonb_build_object('kyng', ka.kyng))
            FROM kyng_areas ka
            WHERE ka.id::UUID = pp.kyng::UUID
        ),
        'have_stortz', pp.have_stortz,
        'number_cats', pp.number_cats,
        'number_dogs', pp.number_dogs,
        'sign_posted', pp.sign_posted,
        'stortz_size', pp.stortz_size,
        'number_birds', pp.number_birds,
        'residents71_', pp.residents71_,
        'site_hazards', pp.site_hazards,
        'truck_access', pp.truck_access,
        'other_hazards', pp.other_hazards,
        'residents0_18', pp.residents0_18,
        'property_agent', (
            SELECT jsonb_build_object(
                'agent_mobile', pa.agent_mobile,
                'agent_name', pa.agent_name,
                'agent_phone', pa.agent_phone
            )
            FROM property_agent pa
            WHERE pa.property_id::UUID = pp.id::UUID
        ),
        'residents19_50', pp.residents19_50,
        'residents51_70', pp.residents51_70,
        'community_areas', (
            SELECT jsonb_agg(jsonb_build_object('community', ca.community))
            FROM community_areas ca
            WHERE ca.id::UUID = pp.community::UUID
        ),
        'property_rented', pp.property_rented,
        'mobile_reception', pp.mobile_reception,
        'number_other_pets', pp.number_other_pets,
        'live_stock_present', pp.live_stock_present,
        'other_site_hazards', pp.other_site_hazards,
        'land_adjacent_hazard', pp.land_adjacent_hazard,
        'live_stock_safe_area', pp.live_stock_safe_area,
        'vulnerable_residents', pp.vulnerable_residents,
        'fire_hazard_reduction', pp.fire_hazard_reduction,
        'other_essential_assets', pp.other_essential_assets,
        'static_water_available', pp.static_water_available,
        'fire_fighting_resources', pp.fire_fighting_resources,
        'property_address_street', pp.property_address_street,
        'property_address_suburb', pp.property_address_suburb,
        'property_address_postcode', pp.property_address_postcode,
        'share_livestock_safe_area', pp.share_livestock_safe_area,
        'truck_access_other_information', pp.truck_access_other_information,
        'linked_users', (
            SELECT jsonb_agg(au.email)
            FROM user_property_profile_join upj2
            JOIN auth.users au ON au.id::UUID = upj2.user_id::UUID
            WHERE upj2.property_id::UUID = pp.id::UUID
            AND upj2.user_id::UUID != id_input::UUID
        )
    ))
    FROM property_profile pp
    JOIN user_property_profile_join upj ON pp.id::UUID = upj.property_id::UUID
    WHERE upj.user_id::UUID = id_input::UUID
)
) INTO result
FROM user_profile up
WHERE up.id::UUID = id_input::UUID;

RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_profile_for_user"("id_input" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_profile_messages_for_user"("id_input" "uuid") RETURNS TABLE("id" bigint, "message" "text", "created_at" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public'
    AS $$

begin
	return query
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and 
		(app_message.context = 'users' or app_message.context = 'both') and 
		app_message.scope = 'all'
    UNION
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and 
		(app_message.context = 'users' or app_message.context = 'both') and 
		app_message.scope like '%' || id_input::text || '%';
end;
$$;


