CREATE OR REPLACE FUNCTION "public"."get_property_address_list"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
DECLARE
    property_address_list json;
    result json;
BEGIN
    SELECT json_agg(json_build_object(
        'lut_text', address, 
        'property_id', property_ids
    )) INTO property_address_list
    FROM (
        SELECT 
            CONCAT(pp.property_address_street, ', ', pp.property_address_suburb) AS address,
            json_agg(pp.id) AS property_ids
        FROM property_profile pp
        GROUP BY address
    ) AS subquery;

    SELECT json_build_object(
        'property_address_list', property_address_list
    ) INTO result;
    
    RETURN result;
END;
$$;


