CREATE OR REPLACE FUNCTION "public"."get_property_data"("principaladdresssiteoid" integer, "out_srid_value" integer) RETURNS TABLE("gurasid" integer, "waypoint" "extensions"."geometry", "property" "extensions"."geometry")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$

declare
    var_wstatus integer;
	var_werror json;
	var_wfeatures json;
	var_wfeature json;
    var_pstatus integer;
	var_perror json;
	var_pfeatures json;
	var_pfeature json;
	var_waypoint geometry;
	var_property geometry;
	var_gurasid int;
begin
	with w as
	(
		select
			status,
			"content"::json -> 'features' as features,
			"content"::json -> 'error' as errors
		from http_get(
					'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/0/query?where=principaladdresssiteoid='
		  			|| principaladdresssiteoid::text || '&returnZ=true&featureEncoding=esriDefault&outSR=' || out_srid_value::text || '&f=geojson')
	)
    select status, features, errors into var_wstatus, var_wfeatures, var_werror from w;
	with p as
	(
		select
			status,
			"content"::json -> 'features' as features,
			"content"::json -> 'error' as errors
		from http_get(
					'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme/FeatureServer/12/query?where=principaladdresssiteoid='
		  			|| principaladdresssiteoid::text || '&outFields=gurasid&returnZ=true&featureEncoding=esriDefault&outSR=' || out_srid_value::text || '&f=geojson')
	)
    select status, features, errors into var_pstatus, var_pfeatures, var_perror from p;
	if var_wstatus = 200 then
		if var_werror is null then
			if var_wfeatures::text = '[]' then
				select ST_GeomFromText('POINT EMPTY') into var_waypoint;
            else
            	select json_array_elements_text(var_wfeatures) into var_wfeature;
                select  ST_Transform(ST_SetSRID(ST_GeomFromGeoJSON(var_wfeature::json -> 'geometry'), out_srid_value), 7844) into var_waypoint;
            end if;
        end if;
    else
        select ST_SetSRID(ST_GeomFromText('POINT EMPTY'), 7844) into var_waypoint;
    end if;
    if var_pstatus = 200 then
		if var_perror is null then
			if var_pfeatures::text = '[]' then
                select NULL into var_gurasid;
				select ST_GeomFromText('POLYGON EMPTY') into var_property;
            else
            	select json_array_elements_text(var_pfeatures) into var_pfeature;
                select (var_pfeature::json -> 'properties' ->> 'gurasid')::int into var_gurasid;
                select ST_Transform(ST_SetSRID(ST_GeomFromGeoJSON(var_pfeature::json -> 'geometry'), out_srid_value), 7844) into var_property;
            end if;
        end if;
    else
        select ST_SetSRID(ST_GeomFromText('POLYGON EMPTY'), 7844) into var_property;
    end if;
    begin
        return query select var_gurasid as gurasid, var_waypoint as waypoint, var_property as property;
    end;
end;
$$;


ALTER FUNCTION "public"."get_property_data"("principaladdresssiteoid" integer, "out_srid_value" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_property_features_by_category"("property_id_param" "uuid", "category_param" "public"."feature_category") RETURNS TABLE("feature_id" "uuid", "feature_type" "text", "geometry" "extensions"."geometry", "attributes" "jsonb")
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        sf.id,
        ft.name,
        sf.geom,
        jsonb_object_agg(tf.field_name, fa.value)
    FROM spatial_features sf
    JOIN feature_templates ft ON sf.template_id = ft.id
    LEFT JOIN feature_attributes fa ON sf.id = fa.feature_id
    LEFT JOIN template_fields tf ON fa.field_id = tf.id
    WHERE sf.property_id = property_id_param
    AND ft.category = category_param
    GROUP BY sf.id, ft.name, sf.geom;
END;
$$;


