CREATE OR REPLACE FUNCTION "public"."get_property_for_user"("id_input" "uuid") RETURNS TABLE("id" "uuid", "property_address_street" "text", "property_address_suburb" "text", "property_address_postcode" "text", "property_rented" boolean, "phone" "text", "mobile_reception" smallint, "sign_posted" boolean, "other_essential_assets" "text", "residents0_18" smallint, "residents19_50" smallint, "residents51_70" smallint, "residents71_" smallint, "vulnerable_residents" boolean, "number_birds" smallint, "number_cats" smallint, "number_dogs" smallint, "number_other_pets" smallint, "live_stock_present" boolean, "live_stock_safe_area" "text", "share_livestock_safe_area" "text", "static_water_available" smallint[], "have_stortz" "text", "stortz_size" smallint, "truck_access" smallint, "truck_access_other_information" "text", "fire_fighting_resources" smallint[], "fire_hazard_reduction" smallint[], "site_hazards" smallint[], "other_hazards" "text", "other_site_hazards" "text", "land_adjacent_hazard" "text", "created_at" timestamp with time zone, "last_updated" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

begin

	return query select p.id,
	p.property_address_street,
    p.property_address_suburb,
    p.property_address_postcode,
    p.property_rented,
    p.phone,
    p.mobile_reception,
    p.sign_posted,
    p.other_essential_assets,
    p.residents0_18,
    p.residents19_50,
    p.residents51_70,
    p.residents71_,
    p.vulnerable_residents,
    p.number_birds,
    p.number_cats,
    p.number_dogs,
    p.number_other_pets,
    p.live_stock_present,
    p.live_stock_safe_area,
    p.share_livestock_safe_area,
    p.static_water_available,
    p.have_stortz,
    p.stortz_size,
    p.truck_access,
    p.truck_access_other_information,
    p.fire_fighting_resources,
    p.fire_hazard_reduction,
    p.site_hazards,
    p.other_hazards,
    p.other_site_hazards,
    p.land_adjacent_hazard,
    p.last_updated,
    p.created_at from public.property_profile p inner join public.user_property_profile_join up
