CREATE OR REPLACE FUNCTION "public"."get_property_geometries"() RETURNS SETOF "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO '$user', 'public', 'extensions'
    AS $$
DECLARE
    v_row record;
    combined_geom geometry;
BEGIN
    FOR v_row IN SELECT * FROM public.property_geometry LOOP
        -- Combine all geometries for this row
        combined_geom := ST_Union(v_row.address_point, ST_Union(v_row.way_point, v_row.property));

        RETURN NEXT json_build_object(
            'id', v_row.id,
            'principalAddressSiteOid', v_row.principaladdresssiteoid,
            'addressPoint', json_build_object(
                'type', 'Feature',
                'geometry', ST_AsGeoJSON(v_row.address_point)::jsonb,
                'properties', json_build_object(
                    'id', v_row.id,
                    'principalAddressSiteOid', v_row.principaladdresssiteoid,
                    'created_at', v_row.created_at,
                    'last_updated', v_row.last_updated
                )
            ),
            'wayPoint', json_build_object(
                'type', 'Feature',
                'geometry', ST_AsGeoJSON(v_row.way_point)::jsonb,
                'properties', json_build_object(
                    'id', v_row.id,
                    'principalAddressSiteOid', v_row.principaladdresssiteoid,
                    'created_at', v_row.created_at,
                    'last_updated', v_row.last_updated
                )
            ),
            'property', json_build_object(
                'type', 'Feature',
                'geometry', ST_AsGeoJSON(v_row.property)::jsonb,
                'properties', json_build_object(
                    'id', v_row.id,
                    'principalAddressSiteOid', v_row.principaladdresssiteoid,
                    'created_at', v_row.created_at,
                    'last_updated', v_row.last_updated
                )
            ),
            'bounds', json_build_object(
                '_southWest', json_build_array(ST_YMin(combined_geom), ST_XMin(combined_geom)),
                '_northEast', json_build_array(ST_YMax(combined_geom), ST_XMax(combined_geom))
            ),
            'center', json_build_object(
                'lat', ST_Y(ST_Centroid(combined_geom)),
                'lng', ST_X(ST_Centroid(combined_geom))
            )
        );
    END LOOP;
END;
$$;


ALTER FUNCTION "public"."get_property_geometries"() OWNER TO "postgres";


