ALTER FUNCTION "public"."get_property_geometries"("p_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_property_geometry"("id_input" "uuid") RETURNS SETOF "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO '$user', 'public', 'extensions'
    AS $$
DECLARE
    combined_geom geometry;
BEGIN
    SELECT ST_Union(pg.address_point, ST_Union(pg.way_point, pg.property)) 
    FROM public.property_geometry pg 
    WHERE pg.id = id_input
    INTO combined_geom;

    RETURN QUERY 
    SELECT jsonb_build_object(
        'address_point', jsonb_build_object(
            'type', 'Feature',
            'geometry', ST_AsGeoJSON(pg.address_point)::jsonb,
            'properties', jsonb_build_object(
                'feature_type', 'address_point',
                'id', pg.id,
                'principaladdresssiteoid', pg.principaladdresssiteoid,
                'created_at', pg.created_at,
                'last_updated', pg.last_updated
            )
        ),
        'way_point', jsonb_build_object(
            'type', 'Feature',
            'geometry', ST_AsGeoJSON(pg.way_point)::jsonb,
            'properties', jsonb_build_object(
                'feature_type', 'way_point',
                'id', pg.id,
                'principaladdresssiteoid', pg.principaladdresssiteoid,
                'created_at', pg.created_at,
                'last_updated', pg.last_updated
            )
        ),
        'property', jsonb_build_object(
            'type', 'Feature',
            'geometry', ST_AsGeoJSON(pg.property)::jsonb,
            'properties', jsonb_build_object(
                'feature_type', 'property',
                'id', pg.id,
                'principaladdresssiteoid', pg.principaladdresssiteoid,
                'created_at', pg.created_at,
                'last_updated', pg.last_updated
            )
        ),
        'bounds', json_build_array(
            json_build_array(ST_YMin(combined_geom), ST_XMin(combined_geom)),
            json_build_array(ST_YMax(combined_geom), ST_XMax(combined_geom))
        ),
        'centre', json_build_array(
            ST_Y(ST_Centroid(combined_geom)),
            ST_X(ST_Centroid(combined_geom))
        )
    ) FROM public.property_geometry pg 
    WHERE pg.id = id_input;
END;
$$;


