CREATE OR REPLACE FUNCTION "public"."get_query_address"("address_text" "text", "given_suburb" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    var_alias text;
    var_search_address text;
    var_suburb_aliases text[];
BEGIN
    IF given_suburb <> '' THEN
        var_search_address := upper(replace(btrim(address_text || ' ' || given_suburb), '  ', ''));
        SELECT aliases FROM public.suburb_aliases WHERE suburb_name = given_suburb INTO var_suburb_aliases;
        IF array_length(var_suburb_aliases, 1) > 0 THEN
            FOREACH var_alias IN ARRAY var_suburb_aliases
            LOOP
                var_search_address := var_search_address || 
                                     ',' || upper(replace(btrim(address_text || ' ' || var_alias), '  ', ' '));
            END LOOP;
        END IF;
        var_search_address := rtrim(var_search_address, ',');
    END IF;
    RETURN var_search_address;
END;
$$;


