CREATE OR REPLACE FUNCTION "public"."get_registered_properties_by_kyng_area"("kyngarea_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
    RETURN (
        SELECT jsonb_build_object(
            'type', 'FeatureCollection',
            'features', jsonb_agg(features.feature ORDER BY 
                features.roadname, 
                features.roadtype, 
                features.suburbname, 
                features.housenumber::integer
            )
        )
        FROM (
            SELECT 
                jsonb_build_object(
                    'type', 'Feature',
                    'geometry', ST_AsGeoJSON(pa.geom)::jsonb,
                    'properties', jsonb_build_object(
                        'address', pa.address,
                        'principaladdresssiteoid', pa.principaladdresssiteoid
                    )
                ) AS feature,
                pa.roadname,
                pa.roadtype,
                pa.suburbname,
                pa.housenumber
            FROM project_addresspoints pa
            JOIN kyng_areas ka ON ST_Intersects(ka.geom, pa.geom)
            WHERE ka.id = kyngarea_id
            AND pa.principaladdresssiteoid IN (
                SELECT principaladdresssiteoid 
                FROM property_geometry
            )
        ) features
    );
END;
$$;


ALTER FUNCTION "public"."get_registered_properties_by_kyng_area"("kyngarea_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_rfs_property_data_for_street"("street_input" "text") RETURNS TABLE("property_id" "uuid", "phone" "text", "address" "text", "agentinformation" json, "property" json, "onsite_hazards" json, "other_local_hazards" json, "fire_fighting_assets" json, "site_animals" json, "residents" json[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$

begin
	return query select
	pp.id as property_id, pp.phone as phone,
	rtrim(ltrim(pp.property_address_street)) || ', ' || rtrim(ltrim(pp.property_address_suburb)) as address,
	case when pp.property_rented = true then
		json_build_object(
			'agentname',
				coalesce(trim(a.agent_name), 'Not Supplied'),
			'agentmobile',
				coalesce(trim(a.agent_mobile), 'Not Supplied'),
			'agentphone',
				coalesce(trim(a.agent_phone), 'Not Supplied')
		)
	end as agentinformation,
	json_build_object(
			'identification',
				case when sign_posted = true then 'Property is well sign-posted and numbered clearly from the road.'
					 else 'Property may be difficult to identify from the road.'
				end,
			'truck_access',
				case when truck_access = 1 then 'All gates are more than 2.5 metres wide.'
					 when truck_access = 2 then 'Most gates are more than 2.5 metres wide.'
					 when truck_access = 3 then 'Restricted by gate width.'
					 when truck_access = 4 then truck_access_other_information
					 else 'Access could be difficult - no information.'
				end,
			'critical_assets',
				case
					when other_essential_assets is null or trim(other_essential_assets) = '' then 'No additional critical assets noted.'
				else
					other_essential_assets
				end,
			'vulnerable',
				case
					when vulnerable_residents = true then 'Vulnerable resident(s) may be present.'
					when vulnerable_residents = false then 'No vulnerable residents flagged.'
					else  'No Information provided'
				end,
			'age_profile', json_build_object(
					'age0_18', residents0_18::text,
					'age19_50', residents19_50::text ,
					'age51_70', residents51_70::text,
					'age71_', residents71_::text
					)
	) as property,
	json_build_object(
			'on_site_hazards',
			json_build_object(
				'Solar_batteries',
				case when site_hazards @> ARRAY[1::smallint] then
						'Present'
					else
						'Not Reported'
					end,
				'Fuel_stores',
				case when site_hazards @> ARRAY[2::smallint] then
						'Present'
					else
						'Not Reported'
					end,
				'Chemical_stores',
				case when site_hazards @> ARRAY[3::smallint] then
						'Present'
					else
						'Not Reported'
					end,
				'Bottled_gas',
				case when site_hazards @> ARRAY[4::smallint] then
						'Present'
					else
						'Not Reported'
					end
			),
			'other_site_hazards',
				case
					when other_site_hazards = '' or other_site_hazards is null then 'None reported'
				else
					other_site_hazards
				end
	) as onsite_hazards,
	json_build_object(
			'land_adjacent_hazard',
				case
					when land_adjacent_hazard = 'Y' then 'Reported Yes'
					when land_adjacent_hazard = 'M' then 'Reported Maybe'
				else
					'Not Reported'
				end,
			'other_local_hazards',
				case
					when other_hazards = '' or other_hazards is null then 'None Reported'
				else
					other_hazards
				end
		) as other_local_hazards,
		json_build_object(
			'static_water',
				case
					when static_water_available  @> ARRAY[5::smallint] then 'None'
				else
					replace(replace(replace(replace(replace(replace(static_water_available::text,'{',''),'}',''),'1','Tank(s)'),'2','Swimming Pool(s)'),'3','Dam(s)'),'4','Creek(s)')
				end,
				'stortz_fitting',
				case
					when have_stortz = 'N' or have_stortz is null then 'None'
					when have_stortz = 'M' then 'Not sure if present on tank(s)'
					when have_stortz = 'Y' then 'Tank has ' || stortz_size::text || ' mm Stortz fitting attached.'
				end,
			'equipment',
				replace(replace(replace(replace(replace(replace(replace(static_water_available::text,'{',''),'}',''),'1','Fire trailer(s)'),'2','Fire fighting pump(s)'),'3','Fire hose(s)'),'4','Trailer(s) with spray equipment'),'5','Generator'),
			'firebreaks',
				case when fire_hazard_reduction  @> ARRAY[1::smallint] then
						'Present'
					else
						'Not Present'
					end,
			'slashed_apz_s',
				case when fire_hazard_reduction  @> ARRAY[2::smallint] then
						'Present'
					else
						'Not Present'
					end,
			'backup_pump',
				case when fire_hazard_reduction  @> ARRAY[3::smallint] then
						'Present'
					else
						'Not Present'
					end,
			'driveway_overhead_clearance',
				case when fire_hazard_reduction  @> ARRAY[4::smallint] then
						'Present'
					else
						'Not Present'
					end,
			'truck_access_around_property',
				case when fire_hazard_reduction  @> ARRAY[5::smallint] then
						'Available'
					else
						'Not Available'
					end
		) as fire_fighting_assets,
	json_build_object(
			'pets',json_build_object(
				'dogs',
					case when number_dogs > 5 then 'More than 5'
						 else number_dogs::text
					end,
				'cats',
					case when number_cats > 5 then 'More than 5'
						 else number_cats::text
					end,
				'birds',
					case when number_birds > 5 then 'More than 5'
						 else number_birds::text
					end,
				'other_pets',
					case when number_other_pets > 5 then 'More than 5'
						 else number_other_pets::text
					end
			),
			'livestock',
				case
					when live_stock_present = true then
						'Livestock present on property.'
					else 'No livestock reported.'
				end,
			'safe_area',
				case
					when live_stock_safe_area  = 'Y' and share_livestock_safe_area = 'Y' then
					json_build_object(
					 	'status', 'Livestock safe area reported on property.',
					 	'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
					)
					when live_stock_safe_area  = 'Y' and share_livestock_safe_area = 'M' then
					json_build_object(
					 	'status', 'Livestock safe area reported on property.',
					 	'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
					)
					when live_stock_safe_area  = 'Y' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
					json_build_object(
					 	'status', 'Livestock safe area reported on property.'
					)
					when live_stock_safe_area  = 'M' and share_livestock_safe_area = 'Y' then
					json_build_object(
					 	'status', 'Livestock safe area may exist on property.',
					 	'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
					)
					when live_stock_safe_area  = 'M' and share_livestock_safe_area = 'M' then
					json_build_object(
					 	'status', 'Livestock safe area may exist on property.',
					 	'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
					)
					when live_stock_safe_area  = 'M' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
					json_build_object(
					 	'status', 'Livestock safe area may exist on property.'
					)
					when (live_stock_safe_area  = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'Y' then
					json_build_object(
					 	'status', 'No livestock safe area identified on property.',
					 	'availability', 'If safe area identified, would allow other people to leave their stock in safe area, for a short period in /nan emergency.'
					)
					when (live_stock_safe_area  = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'M' then
					json_build_object(
					 	'status', 'No livestock safe area identified on property.',
					 	'availability', 'If safe area identified, may allow other people to leave their stock in safe area, for a short period in /nan emergency.'
					)
					when (live_stock_safe_area  = 'N or live_stock_safe_area is null') and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
					json_build_object(
					 	'status', 'No livestock safe area identified on property.'
					)
				end
		) as site_animals, r.residents
from public.property_profile pp
left join property_agent a on pp.id = a.property_id
left join
	(
		SELECT uppj.property_id AS id,
		array_agg(
			json_build_object(
				'name',
				case
					when nullif(trim(first_name),'') is null and nullif(trim(family_name),'') is null
						then 'Not Supplied'
					when nullif(trim(first_name),'') is not null and nullif(trim(family_name),'') is not null
						then trim(first_name) || ' ' || trim(family_name)
					else trim(coalesce(trim(first_name),'') || ' ' || coalesce(trim(family_name), ''))
				end,
				'mobile',coalesce(trim(mobile),'Not Supplied'),
				'resident',
				case
					when residency_profile = 1 then 'Resident at the property fulltime'
					when residency_profile = 2 then 'Present large proportion of time'
					when residency_profile = 3 then 'Occasional short periods away'
					when residency_profile = 4 then 'At the property at least every month'
					when residency_profile = 5 then 'At the property occasionally'
					when residency_profile = 6 then 'Resident fulltime with long absences'
					when residency_profile = 7 then 'Not very often at the property'
					else 'No Information Supplied'
				end,
				'survival_plan',
				case
					when rfs_survival_plan  = 'Y' then 'RFS Survival Plan in place'
					when rfs_survival_plan  = 'N' then 'No RFS Survival Plan'
					else 'No Information Supplied'
				end,
				'plan_to_leave',
				case
					when plan_to_leave_before_fire  = 1 then 'Planning on staying'
					when plan_to_leave_before_fire  = 2 then 'Leaving as early as possible'
					when plan_to_leave_before_fire  = 3 then 'Will stay or leave depending on severity'
					else  'No Information Supplied'
				end
			)
		) AS residents
		FROM   user_property_profile_join uppj
		JOIN   user_profile up ON up.id = uppj.user_id
		GROUP  BY uppj.property_id
	) r USING (id)
where upper(property_address_street) like  '%' || street_input;
end;
$$;


ALTER FUNCTION "public"."get_rfs_property_data_for_street"("street_input" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_rfs_user_data_for_porperties"("property_ids" "uuid"[]) RETURNS TABLE("property_id" "uuid", "phone" "text", "address" "text", "agentinformation" json, "property" json, "onsite_hazards" json, "other_local_hazards" json, "fire_fighting_assets" json, "site_animals" json, "residents" json[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
begin
    return query 
    select
        pp.id as property_id,
        pp.phone as phone,
        rtrim(ltrim(pp.property_address_street)) || ', ' || rtrim(ltrim(pp.property_address_suburb)) as address,
        case when pp.property_rented = true then
            json_build_object(
                'agentname', coalesce(trim(a.agent_name), 'Not Supplied'),
                'agentmobile', coalesce(trim(a.agent_mobile), 'Not Supplied'),
                'agentphone', coalesce(trim(a.agent_phone), 'Not Supplied')
            )
        end as agentinformation,
        json_build_object(
            'identification',
                case when sign_posted = true then 'Property is well sign-posted and numbered clearly from the road.'
                     else 'Property may be difficult to identify from the road.'
                end,
            'truck_access',
                case when truck_access = 1 then 'All gates are more than 2.5 metres wide.'
                     when truck_access = 2 then 'Most gates are more than 2.5 metres wide.'
                     when truck_access = 3 then 'Restricted by gate width.'
                     when truck_access = 4 then truck_access_other_information
                     else 'Access could be difficult - no information.'
                end,
            'critical_assets',
                case when other_essential_assets is null or trim(other_essential_assets) = '' 
                     then 'No additional critical assets noted.'
                     else other_essential_assets
                end,
            'vulnerable',
                case when vulnerable_residents = true then 'Vulnerable resident(s) may be present.'
                     when vulnerable_residents = false then 'No vulnerable residents flagged.'
                     else 'No Information provided'
                end,
            'age_profile', json_build_object(
                'age0_18', residents0_18::text,
                'age19_50', residents19_50::text,
                'age51_70', residents51_70::text,
                'age71_', residents71_::text
            )
        ) as property,
        json_build_object(
            'on_site_hazards',
            json_build_object(
                'Solar_batteries',
                    case when site_hazards @> ARRAY[1::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Fuel_stores',
                    case when site_hazards @> ARRAY[2::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Chemical_stores',
                    case when site_hazards @> ARRAY[3::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Bottled_gas',
                    case when site_hazards @> ARRAY[4::smallint] then 'Present'
                         else 'Not Reported'
                    end
            ),
            'other_site_hazards',
                case when other_site_hazards = '' or other_site_hazards is null 
                     then 'None reported'
                     else other_site_hazards
                end
        ) as onsite_hazards,
        json_build_object(
            'land_adjacent_hazard',
                case when land_adjacent_hazard = 'Y' then 'Reported Yes'
                     when land_adjacent_hazard = 'M' then 'Reported Maybe'
                     else 'Not Reported'
                end,
            'other_local_hazards',
                case when other_hazards = '' or other_hazards is null 
                     then 'None Reported'
                     else other_hazards
                end
        ) as other_local_hazards,
        json_build_object(
            'static_water',
                case when static_water_available @> ARRAY[5::smallint] then 'None'
                     else replace(replace(replace(replace(replace(replace(
                          static_water_available::text,
                          '{',''),'}',''),
                          '1','Tank(s)'),
                          '2','Swimming Pool(s)'),
                          '3','Dam(s)'),
                          '4','Creek(s)')
                end,
            'stortz_fitting',
                case when have_stortz = 'N' or have_stortz is null then 'None'
                     when have_stortz = 'M' then 'Not sure if present on tank(s)'
                     when have_stortz = 'Y' then 'Tank has ' || stortz_size::text || ' mm Stortz fitting attached.'
                end,
            'equipment',
                replace(replace(replace(replace(replace(replace(replace(
                    static_water_available::text,
                    '{',''),'}',''),
                    '1','Fire trailer(s)'),
                    '2','Fire fighting pump(s)'),
                    '3','Fire hose(s)'),
                    '4','Trailer(s) with spray equipment'),
                    '5','Generator'),
            'firebreaks',
                case when fire_hazard_reduction @> ARRAY[1::smallint] then 'Present'
                     else 'Not Present'
                end,
            'slashed_apz_s',
                case when fire_hazard_reduction @> ARRAY[2::smallint] then 'Present'
                     else 'Not Present'
                end,
            'backup_pump',
                case when fire_hazard_reduction @> ARRAY[3::smallint] then 'Present'
                     else 'Not Present'
                end,
            'driveway_overhead_clearance',
                case when fire_hazard_reduction @> ARRAY[4::smallint] then 'Present'
                     else 'Not Present'
                end,
            'truck_access_around_property',
                case when fire_hazard_reduction @> ARRAY[5::smallint] then 'Available'
                     else 'Not Available'
                end
        ) as fire_fighting_assets,
        json_build_object(
            'pets', json_build_object(
                'dogs',
                    case when number_dogs > 5 then 'More than 5'
                         else number_dogs::text
                    end,
                'cats',
                    case when number_cats > 5 then 'More than 5'
                         else number_cats::text
                    end,
                'birds',
                    case when number_birds > 5 then 'More than 5'
                         else number_birds::text
                    end,
                'other_pets',
                    case when number_other_pets > 5 then 'More than 5'
                         else number_other_pets::text
                    end
            ),
            'livestock',
                case when live_stock_present = true then 'Livestock present on property.'
                     else 'No livestock reported.'
                end,
            'safe_area',
                case when live_stock_safe_area = 'Y' and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.',
                        'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'Y' and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.',
                        'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'Y' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.'
                    )
                    when live_stock_safe_area = 'M' and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.',
                        'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'M' and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.',
                        'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'M' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.',
                        'availability', 'If safe area identified, would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.',
                        'availability', 'If safe area identified, may allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.'
                    )
                end
        ) as site_animals,
        r.residents
    from unnest(property_ids) pid
    join public.property_profile pp on pp.id = pid
    left join property_agent a on pp.id = a.property_id
    left join (
        SELECT uppj.property_id AS id,
        array_agg(
            json_build_object(
                'name',
                case when nullif(trim(first_name),'') is null and nullif(trim(family_name),'') is null
                     then 'Not Supplied'
                     when nullif(trim(first_name),'') is not null and nullif(trim(family_name),'') is not null
                     then trim(first_name) || ' ' || trim(family_name)
                     else trim(coalesce(trim(first_name),'') || ' ' || coalesce(trim(family_name), ''))
                end,
                'mobile', coalesce(trim(mobile),'Not Supplied'),
                'resident',
                case when residency_profile = 1 then 'Resident at the property fulltime'
                     when residency_profile = 2 then 'Present large proportion of time'
                     when residency_profile = 3 then 'Occasional short periods away'
                     when residency_profile = 4 then 'At the property at least every month'
                     when residency_profile = 5 then 'At the property occasionally'
                     when residency_profile = 6 then 'Resident fulltime with long absences'
                     when residency_profile = 7 then 'Not very often at the property'
                     else 'No Information Supplied'
                end,
                'survival_plan',
                case when rfs_survival_plan = 'Y' then 'RFS Survival Plan in place'
                     when rfs_survival_plan = 'N' then 'No RFS Survival Plan'
                     else 'No Information Supplied'
                end,
                'plan_to_leave',
                case when plan_to_leave_before_fire = 1 then 'Planning on staying'
                     when plan_to_leave_before_fire = 2 then 'Leaving as early as possible'
                     when plan_to_leave_before_fire = 3 then 'Will stay or leave depending on severity'
                     else 'No Information Supplied'
                end
            )
        ) AS residents
        FROM user_property_profile_join uppj
        JOIN user_profile up ON up.id = uppj.user_id
        GROUP BY uppj.property_id
    ) r ON r.id = pp.id;
end;
$$;


ALTER FUNCTION "public"."get_rfs_user_data_for_porperties"("property_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_rfs_user_map_data_for_porperties"("property_ids" "uuid"[]) RETURNS TABLE("property_id" "uuid", "phone" "text", "address" "text", "agentinformation" json, "property" json, "onsite_hazards" json, "other_local_hazards" json, "fire_fighting_assets" json, "site_animals" json, "residents" json[], "property_geojson" json, "feature_layers" json)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public', 'auth', 'extensions'
    AS $$
begin
    return query 
    with feature_data as (
        select 
            sf.property_id,
            ft.category,
            ft.geometry_type,
            jsonb_agg(
                jsonb_build_object(
                    'type', 'Feature',
                    'geometry', ST_AsGeoJSON(sf.geom)::jsonb,
                    'properties', jsonb_build_object(
                        'id', sf.id,
                        'name', ft.name,
                        'attributes', (
                            select jsonb_object_agg(tf.field_name, fa.value)
                            from feature_attributes fa
                            join template_fields tf on tf.id = fa.field_id
                            where fa.feature_id = sf.id
                        )
                    )
                )
            ) as features
        from spatial_features sf
        join feature_templates ft on ft.id = sf.template_id
        where sf.property_id = ANY(property_ids)
        group by sf.property_id, ft.category, ft.geometry_type
    )
    select
        pp.id as property_id,
        pp.phone as phone,
        rtrim(ltrim(pp.property_address_street)) || ', ' || rtrim(ltrim(pp.property_address_suburb)) as address,
        case when pp.property_rented = true then
            json_build_object(
                'agentname', coalesce(trim(a.agent_name), 'Not Supplied'),
                'agentmobile', coalesce(trim(a.agent_mobile), 'Not Supplied'),
                'agentphone', coalesce(trim(a.agent_phone), 'Not Supplied')
            )
        end as agentinformation,
        json_build_object(
            'identification',
                case when sign_posted = true then 'Property is well sign-posted and numbered clearly from the road.'
                     else 'Property may be difficult to identify from the road.'
                end,
            'truck_access',
                case when truck_access = 1 then 'All gates are more than 2.5 metres wide.'
                     when truck_access = 2 then 'Most gates are more than 2.5 metres wide.'
                     when truck_access = 3 then 'Restricted by gate width.'
                     when truck_access = 4 then truck_access_other_information
                     else 'Access could be difficult - no information.'
                end,
            'critical_assets',
                case when other_essential_assets is null or trim(other_essential_assets) = '' 
                     then 'No additional critical assets noted.'
                     else other_essential_assets
                end,
            'vulnerable',
                case when vulnerable_residents = true then 'Vulnerable resident(s) may be present.'
                     when vulnerable_residents = false then 'No vulnerable residents flagged.'
                     else 'No Information provided'
                end,
            'age_profile', json_build_object(
                'age0_18', residents0_18::text,
                'age19_50', residents19_50::text,
                'age51_70', residents51_70::text,
                'age71_', residents71_::text
            )
        ) as property,
        json_build_object(
            'on_site_hazards',
            json_build_object(
                'Solar_batteries',
                    case when site_hazards @> ARRAY[1::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Fuel_stores',
                    case when site_hazards @> ARRAY[2::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Chemical_stores',
                    case when site_hazards @> ARRAY[3::smallint] then 'Present'
                         else 'Not Reported'
                    end,
                'Bottled_gas',
                    case when site_hazards @> ARRAY[4::smallint] then 'Present'
                         else 'Not Reported'
                    end
            ),
            'other_site_hazards',
                case when other_site_hazards = '' or other_site_hazards is null 
                     then 'None reported'
                     else other_site_hazards
                end
        ) as onsite_hazards,
        json_build_object(
            'land_adjacent_hazard',
                case when land_adjacent_hazard = 'Y' then 'Reported Yes'
                     when land_adjacent_hazard = 'M' then 'Reported Maybe'
                     else 'Not Reported'
                end,
            'other_local_hazards',
                case when other_hazards = '' or other_hazards is null 
                     then 'None Reported'
                     else other_hazards
                end
        ) as other_local_hazards,
        json_build_object(
            'static_water',
                case when static_water_available @> ARRAY[5::smallint] then 'None'
                     else replace(replace(replace(replace(replace(replace(
                          static_water_available::text,
                          '{',''),'}',''),
                          '1','Tank(s)'),
                          '2','Swimming Pool(s)'),
                          '3','Dam(s)'),
                          '4','Creek(s)')
                end,
            'stortz_fitting',
                case when have_stortz = 'N' or have_stortz is null then 'None'
                     when have_stortz = 'M' then 'Not sure if present on tank(s)'
                     when have_stortz = 'Y' then 'Tank has ' || stortz_size::text || ' mm Stortz fitting attached.'
                end,
            'equipment',
                replace(replace(replace(replace(replace(replace(replace(
                    static_water_available::text,
                    '{',''),'}',''),
                    '1','Fire trailer(s)'),
                    '2','Fire fighting pump(s)'),
                    '3','Fire hose(s)'),
                    '4','Trailer(s) with spray equipment'),
                    '5','Generator'),
            'firebreaks',
                case when fire_hazard_reduction @> ARRAY[1::smallint] then 'Present'
                     else 'Not Present'
                end,
            'slashed_apz_s',
                case when fire_hazard_reduction @> ARRAY[2::smallint] then 'Present'
                     else 'Not Present'
                end,
            'backup_pump',
                case when fire_hazard_reduction @> ARRAY[3::smallint] then 'Present'
                     else 'Not Present'
                end,
            'driveway_overhead_clearance',
                case when fire_hazard_reduction @> ARRAY[4::smallint] then 'Present'
                     else 'Not Present'
                end,
            'truck_access_around_property',
                case when fire_hazard_reduction @> ARRAY[5::smallint] then 'Available'
                     else 'Not Available'
                end
        ) as fire_fighting_assets,
        json_build_object(
            'pets', json_build_object(
                'dogs',
                    case when number_dogs > 5 then 'More than 5'
                         else number_dogs::text
                    end,
                'cats',
                    case when number_cats > 5 then 'More than 5'
                         else number_cats::text
                    end,
                'birds',
                    case when number_birds > 5 then 'More than 5'
                         else number_birds::text
                    end,
                'other_pets',
                    case when number_other_pets > 5 then 'More than 5'
                         else number_other_pets::text
                    end
            ),
            'livestock',
                case when live_stock_present = true then 'Livestock present on property.'
                     else 'No livestock reported.'
                end,
            'safe_area',
                case when live_stock_safe_area = 'Y' and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.',
                        'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'Y' and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.',
                        'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'Y' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'Livestock safe area reported on property.'
                    )
                    when live_stock_safe_area = 'M' and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.',
                        'availability', 'Would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'M' and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.',
                        'availability', 'May allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when live_stock_safe_area = 'M' and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'Livestock safe area may exist on property.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'Y' then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.',
                        'availability', 'If safe area identified, would allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and share_livestock_safe_area = 'M' then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.',
                        'availability', 'If safe area identified, may allow other people to leave their stock in safe area, for a short period in an emergency.'
                    )
                    when (live_stock_safe_area = 'N' or live_stock_safe_area is null) and (share_livestock_safe_area = 'N' or share_livestock_safe_area is null) then
                    json_build_object(
                        'status', 'No livestock safe area identified on property.'
                    )
                end
        ) as site_animals,
        r.residents,
        json_build_object(
            'type', 'Feature',
            'geometry', ST_AsGeoJSON(pg.property)::json,
            'properties', json_build_object(
                'address_point', ST_AsGeoJSON(pg.address_point)::json,
                'way_point', ST_AsGeoJSON(pg.way_point)::json
            )
        ) as property_geojson,
        (
            select json_object_agg(
                category || '_' || geometry_type,
                json_build_object(
                    'type', 'FeatureCollection',
                    'features', features
                )
            )
            from feature_data fd
            where fd.property_id = pp.id
        ) as feature_layers
    from unnest(property_ids) pid
    join public.property_profile pp on pp.id = pid
    left join property_geometry pg on pg.id = pp.id
    left join property_agent a on pp.id = a.property_id
    left join (
        SELECT uppj.property_id AS id,
        array_agg(
            json_build_object(
                'name',
                case when nullif(trim(first_name),'') is null and nullif(trim(family_name),'') is null
                     then 'Not Supplied'
                     when nullif(trim(first_name),'') is not null and nullif(trim(family_name),'') is not null
                     then trim(first_name) || ' ' || trim(family_name)
                     else trim(coalesce(trim(first_name),'') || ' ' || coalesce(trim(family_name), ''))
                end,
                'mobile', coalesce(trim(mobile),'Not Supplied'),
                'resident',
                case when residency_profile = 1 then 'Resident at the property fulltime'
                     when residency_profile = 2 then 'Present large proportion of time'
                     when residency_profile = 3 then 'Occasional short periods away'
                     when residency_profile = 4 then 'At the property at least every month'
                     when residency_profile = 5 then 'At the property occasionally'
                     when residency_profile = 6 then 'Resident fulltime with long absences'
                     when residency_profile = 7 then 'Not very often at the property'
                     else 'No Information Supplied'
                end,
                'survival_plan',
                case when rfs_survival_plan = 'Y' then 'RFS Survival Plan in place'
                     when rfs_survival_plan = 'N' then 'No RFS Survival Plan'
                     else 'No Information Supplied'
                end,
                'plan_to_leave',
                case when plan_to_leave_before_fire = 1 then 'Planning on staying'
                     when plan_to_leave_before_fire = 2 then 'Leaving as early as possible'
                     when plan_to_leave_before_fire = 3 then 'Will stay or leave depending on severity'
                     else 'No Information Supplied'
                end
            )
        ) AS residents
        FROM user_property_profile_join uppj
        JOIN user_profile up ON up.id = uppj.user_id
        GROUP BY uppj.property_id
    ) r ON r.id = pp.id;
end;
$$;


ALTER FUNCTION "public"."get_rfs_user_map_data_for_porperties"("property_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_site_boundary"() RETURNS TABLE("project_geom" "extensions"."geometry", "project_boundary" json)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_temp'
    AS $$
	BEGIN
		RETURN QUERY
		    SELECT
		        ST_Transform(ST_Union(wkb_geometry), 4326) AS project_geom,
		        ST_AsGeoJSON(ST_Transform(ST_Union(wkb_geometry), 4326))::json AS project_boundary
		    FROM project_area;
	END
$$;


ALTER FUNCTION "public"."get_site_boundary"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_site_roads"() RETURNS TABLE("roadname" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    WITH boundary AS (
        SELECT ST_Transform(ST_Union(project_area.wkb_geometry), 4326) AS project_geom,
               ST_AsGeoJSON(ST_Transform(ST_Union(project_area.wkb_geometry), 4326)) AS project_boundary
        FROM project_area
    ),
    suburbs_response AS (
        SELECT content::json -> 'features' AS features
        FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer/2/query',
            'geometry=' || urlencode('{"rings": ' || (SELECT project_boundary::json -> 'coordinates' FROM boundary) || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=4326&outFields=*&f=geojson',
            'application/x-www-form-urlencoded'
        )
    ),
    suburbs AS (
        SELECT DISTINCT feature -> 'properties' ->> 'suburbname' AS suburbname,
               ST_Transform(ST_GeomFromGeoJSON(feature ->> 'geometry'), 4326) AS suburb_geom
        FROM suburbs_response, json_array_elements(features) AS feature
    ),
    roads_response AS (
        SELECT content::json -> 'features' AS features
        FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Transport_Theme/FeatureServer/6/query',
            'geometry=' || urlencode('{"rings": ' || (SELECT project_boundary::json -> 'coordinates' FROM boundary) || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=4326&outFields=*&f=geojson',
            'application/x-www-form-urlencoded'
        )
    ),
    roads AS (
        SELECT DISTINCT feature -> 'properties' ->> 'roadnamestring' AS roadname,
               ST_Transform(ST_GeomFromGeoJSON(feature ->> 'geometry'), 4326) AS road_geom
        FROM roads_response, json_array_elements(features) AS feature
    )
    SELECT DISTINCT r.roadname
    FROM roads r;
END;
$$;


ALTER FUNCTION "public"."get_site_roads"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_site_roads_in_suburb"("suburb" "text") RETURNS TABLE("roadname" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    WITH boundary AS (
        SELECT ST_Transform(ST_Union(project_area.wkb_geometry), 4326) AS project_geom,
               ST_AsGeoJSON(ST_Transform(ST_Union(project_area.wkb_geometry), 4326)) AS project_boundary
        FROM project_area
    ),
    suburbs_response AS (
        SELECT content::json -> 'features' AS features
        FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer/2/query',
            'geometry=' || urlencode('{"rings": ' || (SELECT project_boundary::json -> 'coordinates' FROM boundary) || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=4326&outFields=*&f=geojson',
            'application/x-www-form-urlencoded'
        )
    ),
    suburbs AS (
        SELECT DISTINCT feature -> 'properties' ->> 'suburbname' AS suburbname,
               ST_Transform(ST_GeomFromGeoJSON(feature ->> 'geometry'), 4326) AS suburb_geom
        FROM suburbs_response, json_array_elements(features) AS feature
    ),
    roads_response AS (
        SELECT content::json -> 'features' AS features
        FROM http_post(
            'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Transport_Theme/FeatureServer/6/query',
            'geometry=' || urlencode('{"rings": ' || (SELECT project_boundary::json -> 'coordinates' FROM boundary) || '}') ||
            '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=4326&outFields=*&f=geojson',
            'application/x-www-form-urlencoded'
        )
    ),
    roads AS (
        SELECT DISTINCT feature -> 'properties' ->> 'roadnamestring' AS roadname,
               ST_Transform(ST_GeomFromGeoJSON(feature ->> 'geometry'), 4326) AS road_geom
        FROM roads_response, json_array_elements(features) AS feature
    )
    SELECT DISTINCT r.roadname
    FROM roads r
    JOIN suburbs s ON ST_Intersects(r.road_geom, s.suburb_geom)
    WHERE LOWER(s.suburbname) = LOWER(suburb);
END;
$$;


ALTER FUNCTION "public"."get_site_roads_in_suburb"("suburb" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_site_suburbs"() RETURNS TABLE("suburbname" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
	RETURN QUERY
	WITH boundary AS (
	    SELECT ST_Transform(ST_Union(project_area.wkb_geometry), 4326) AS project_geom,
	           ST_AsGeoJSON(ST_Transform(ST_Union(project_area.wkb_geometry), 4326)) AS project_boundary
	    FROM project_area
	),
	suburbs_response AS (
	    SELECT content::json -> 'features' AS features
	    FROM http_post(
	        'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer/2/query',
	        'geometry=' || urlencode('{"rings": ' || (SELECT project_boundary::json -> 'coordinates' FROM boundary) || '}') ||
	        '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=4326&outFields=*&f=geojson',  -- Changed outSR to 4326 for consistency
	        'application/x-www-form-urlencoded'
	    )
	),
	suburbs AS (
	    SELECT DISTINCT feature -> 'properties' ->> 'suburbname' AS suburbname,
	           ST_Transform(ST_GeomFromGeoJSON(feature ->> 'geometry'), 4326) AS suburb_geom  -- Parse geometry for later use
	    FROM suburbs_response, json_array_elements(features) AS feature
