CREATE OR REPLACE FUNCTION "public"."get_spatial_feature_attributes"("p_property_id" "uuid") RETURNS json
    LANGUAGE "plpgsql"
    AS $$
BEGIN
    RETURN (
        SELECT json_object_agg(fa.id, attribute_data)
        FROM (
            SELECT 
                fa.id,
                json_build_object(
                    'id', fa.id,
                    'feature_id', fa.feature_id,
                    'field_id', fa.field_id,
                    'value', fa.value,
                    'last_edited', fa.last_edited
                ) AS attribute_data
            FROM feature_attributes fa
            JOIN spatial_features sf ON fa.feature_id = sf.id
            WHERE sf.property_id = p_property_id
        ) fa
    );
END;
$$;


