CREATE OR REPLACE FUNCTION "public"."get_suburb_polygon"() RETURNS "extensions"."geometry"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    geojson text;
BEGIN
    -- retrieve the geojson data from the URL using the http extension
    SELECT http_get('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer/2/query?where=suburbname+in+%28%27BELBORA%27%2C%27BOOTAWA%27%2C%27BURRELL+CREEK%27%2C%27HILLVILLE%27%2C%27KIMBRIKI%27%2C%27KUNDIBAKH%27%2C%27MONDROOK%27%2C%27TINONEE%27%29&f=geojson')
    INTO geojson;
    
    -- convert the geojson text to a geometry collection
    RETURN ST_CollectionExtract(ST_GeomFromGeoJSON(geojson), 3);

END;
$$;


ALTER FUNCTION "public"."get_suburb_polygon"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_suburbs_geometry"() RETURNS "extensions"."geometry"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  suburb_names TEXT[] := ARRAY['BELBORA', 'BOOTAWA', 'BURRELL CREEK', 'HILLVILLE', 'KIMBRIKI', 'KUNDIBAKH', 'MONDROOK', 'TINONEE'];
  query_url TEXT := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Administrative_Boundaries_Theme/FeatureServer/2/query?where=suburbname+in+%28%27' || array_to_string(suburb_names, '%27%2C%27') || '%27%29&f=geojson';
  geojson_result TEXT;
  suburb_geometry Geometry;
BEGIN
  SELECT http_get(query_url) INTO geojson_result;
  SELECT ST_Transform(ST_SetSRID(ST_Union(ST_GeomFromGeoJSON(feat->>'geometry')), 4283), 3857)
          FROM ( SELECT json_array_elements(geojson_result::json->'features')as feat) as f into suburb_geometry;
  RETURN suburb_geometry;
END;
$$;


