CREATE OR REPLACE FUNCTION "public"."get_tester_messages_for_user"("id_input" "uuid") RETURNS TABLE("id" bigint, "message" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO '$user', 'public'
    AS $$

begin
	return query
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and app_message.context = 'tester' and app_message.scope = 'all'
    UNION
    SELECT app_message.id, app_message.message, TO_CHAR(app_message.created_at AT TIME ZONE 'UTC', 'DD/MM/YYYY HH24:MI') AS created_at FROM public.app_message
    WHERE app_message.revoked is null and app_message.context = 'tester' and  app_message.scope like '%' || id_input::text || '%';
end;
$$;


