CREATE OR REPLACE FUNCTION "public"."get_unregistered_properties_by_kyng_area"("kyngarea_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
    RETURN (
        SELECT jsonb_build_object(
            'type', 'FeatureCollection',
            'features', jsonb_agg(features.feature ORDER BY 
                features.roadname, 
                features.roadtype, 
                features.suburbname, 
                features.housenumber::integer
            )
        )
        FROM (
            SELECT 
                jsonb_build_object(
                    'type', 'Feature',
                    'geometry', ST_AsGeoJSON(pa.geom)::jsonb,
                    'properties', jsonb_build_object(
                        'address', pa.address,
                        'principaladdresssiteoid', pa.principaladdresssiteoid
                    )
                ) AS feature,
                pa.roadname,
                pa.roadtype,
                pa.suburbname,
                pa.housenumber
            FROM project_addresspoints pa
            JOIN kyng_areas ka ON ST_Intersects(ka.geom, pa.geom)
            WHERE ka.id = kyngarea_id
            AND pa.principaladdresssiteoid NOT IN (
                SELECT principaladdresssiteoid 
                FROM property_geometry
            )
        ) features
    );
END;
$$;


ALTER FUNCTION "public"."get_unregistered_properties_by_kyng_area"("kyngarea_id" "uuid") OWNER TO "postgres";


