CREATE OR REPLACE FUNCTION "public"."get_user_vetting_data"() RETURNS TABLE("email" "text", "name" "text", "property_address" "text", "landline" "text", "mobile" "text", "unanswered" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

begin
	return query select u.email::text, up.first_name || ' ' || up.family_name as name, pp.property_address_street || ', ' || pp.property_address_suburb || ' ' || pp.property_address_postcode as property_address,
	case
		when pp.phone is null or  btrim(pp.phone) = '' then 'Not Provided'
		else pp.phone
	end as landline,
	case
		when up.mobile is null or  btrim(up.mobile) = '' then 'Not Provided'
		else up.mobile
	end as mobile,
	rtrim((
	case when up.rfs_survival_plan is null then 'RFS Survival Plan, ' else '' end ||
	case when pp.mobile_reception is null then 'Mobile Reception, ' else '' end ||
	case when up.fire_fighting_experience is null then 'Fire Fighting Experience, ' else '' end ||
	case when up.fire_trauma is null then 'Fire Trauma, ' else '' end ||
	case when up.plan_to_leave_before_fire is null then 'Plan to Leave Before Fire, ' else '' end ||
	case when up.plan_to_leave_before_flood is null then 'Plan to Leave Before Flood, ' else '' end ||
	case when up.residency_profile is null then 'Residency Profile, ' else '' end ||
	case
		when pp.property_rented is not null and a.agent_name is null then 'Agent Name, '
		when pp.property_rented is not null and (a.agent_phone is null and a.agent_mobile is null) then 'Agent Phone/Mobile, '
		else ''
	end ||
	case when pp.sign_posted is null then 'Sign Posted, ' else '' end ||
	case when pp.truck_access is null then 'Truck Access, ' else '' end ||
	case when pp.truck_access = 4 and pp.truck_access_other_information is null then 'Truck Access Other Information, ' else '' end ||
	case when pp.residents0_18 = 0 and  pp.residents19_50 = 0 and  pp.residents51_70 = 0 and  pp.residents71_ = 0 then 'Resident Census, ' else '' end ||
	case when pp.vulnerable_residents is null then 'Vulnerable Residents, ' else '' end ||
	case when pp.number_dogs = 0 and  pp.number_cats = 0 and  pp.number_birds = 0 and  pp.number_other_pets = 0 then 'Pet Census, ' else '' end ||
	case when pp.live_stock_present is null then 'Live Stock Present, ' else '' end ||
	case when pp.live_stock_safe_area is null then 'Live Stock Safe Area, ' else '' end ||
	case when pp.static_water_available  is null then 'Static Water, ' else '' end ||
	case when pp.have_stortz  is null then 'Have Stortz, ' else '' end ||
	case when pp.have_stortz = 'Y' and (stortz_size is null or stortz_size = 0) then 'Stortz Size, ' else '' end ||
	case when pp.fire_hazard_reduction is null then 'Fire Hazard Reduction, ' else '' end ||
	case when pp.fire_fighting_resources is null then 'Fire Fighting Resources, ' else '' end ||
	case when pp.site_hazards  is null then 'Site Hazards, ' else '' end
	), ', ') as unanswered
	from public.user_profile up left join
		auth.users u on up.id = u.id left join
		public.user_property_profile_join uppj on up.id = uppj.user_id join
		public.property_profile pp on pp.id = uppj.property_id left join
		public.property_agent a on a.property_id =  pp.id;
end;
$$;


ALTER FUNCTION "public"."get_user_vetting_data"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_users_with_kyng_status"() RETURNS TABLE("user_id" "uuid", "email" "text", "kyng_area_id" "uuid", "kyng" "text", "user_name" "text", "phone_number" "text", "start_date" "text", "end_date" "text", "updated_at" "text", "admin_user_id" "uuid", "admin_email" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        au.id as user_id,
        au.email::text,
        kaj.kyng_area_id,
        ka.kyng,
        kaj.user_name,
        kaj.phone_number,
        to_char(kaj.start_date AT TIME ZONE 'UTC' AT TIME ZONE current_setting('TIMEZONE'), 'YYYY-MM-DD HH24:MI:SS') as start_date,
        to_char(kaj.end_date AT TIME ZONE 'UTC' AT TIME ZONE current_setting('TIMEZONE'), 'YYYY-MM-DD HH24:MI:SS') as end_date,
        to_char(kaj.updated_at AT TIME ZONE 'UTC' AT TIME ZONE current_setting('TIMEZONE'), 'YYYY-MM-DD HH24:MI:SS') as updated_at,
        kaj.admin_user_id,
        admin_user.email::text as admin_email
    FROM auth.users au
    LEFT JOIN public.kyng_area_users_join kaj 
        ON au.id = kaj.user_id
    LEFT JOIN public.kyng_areas ka
        ON kaj.kyng_area_id = ka.id
    LEFT JOIN auth.users admin_user
        ON kaj.admin_user_id = admin_user.id;
END;
$$;


ALTER FUNCTION "public"."get_users_with_kyng_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_validated_addresspoint_from_address"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text") RETURNS TABLE("status" integer, "searchaddressstreet" "text", "searchaddresssuburb" "text", "validaddressstreet" "text", "validaddresssuburb" "text", "validaddresspostcode" "text", "principaladdresssiteoid" integer, "community" "text", "kyng" "text", "geojson" "jsonb", "matchcodes" "jsonb", "geocoder_result" "jsonb", "found_in_custom" boolean, "found_in_project" boolean)
    LANGUAGE "plpgsql"
    AS $$
declare
    var_search_address text;
    var_where_clause text;
    address_exists boolean;
    geocoder_result jsonb;
    site_oid_value integer;
    address_point_details jsonb;
    found_in_custom boolean;
    found_in_project boolean;
begin
    SET LOCAL statement_timeout = '60000';
    found_in_custom := false;
    found_in_project := false;

    select upper(address_text) || ' ' ||  upper(given_suburb) into var_search_address;
    select public.get_query_address(upper(address_text), upper(given_suburb)) into var_where_clause;

    RAISE LOG '+++++ WHERE CUSTOM ADDRESS IN %',var_where_clause;

    SELECT EXISTS (
        SELECT 1 
        FROM public.custom_address ca 
        WHERE ca.address IN (SELECT regexp_split_to_table(var_where_clause, ','))
    ) INTO found_in_custom;

    RAISE LOG 'found_in_custom value: %', found_in_custom;

    IF NOT found_in_custom THEN
        SELECT EXISTS (
            SELECT 1 
            FROM public.project_addresspoints pa
            WHERE pa.address IN (SELECT regexp_split_to_table(var_where_clause, ','))
        ) INTO found_in_project;
    END IF;

    IF NOT found_in_custom AND NOT found_in_project THEN
        SELECT process_geoscape_geocoder_response(var_search_address || ' NSW', api_key) INTO geocoder_result; 
		RAISE LOG 'process_geoscape_geocoder_response(%): == %', var_search_address, (geocoder_result);
        IF geocoder_result->>'matchType' != 'noMatch' THEN
            SELECT get_principaladdresssiteoid_from_cadastralidentifier(
                geocoder_result->>'cadastralIdentifier'
            ) INTO site_oid_value;
            IF site_oid_value IS NOT NULL THEN
                SELECT get_addresspoint_from_principaladdresssiteoid(site_oid_value) INTO address_point_details;
            END IF;
        END IF;
    END IF;

    RETURN QUERY
    WITH custom_address_results AS (
        select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
            trim(both trim(trailing ca.suburb from ca.address)) as validaddressstreet, ca.suburb as validaddresssuburb, 
            ca.postcode as validaddresspostcode, ca.principaladdresssiteoid::int4 as principaladdresssiteoid, 
            ca.community as community, ca.kyng as kyng,
            ST_AsGeoJSON(ST_Transform(ST_SetSRID(ST_Point(0, 0), 7844), 4326))::jsonb as geojson,
            null::jsonb as matchcodes,
            null::jsonb as geocoder_result,
            true as found_in_custom,
            false as found_in_project
        from public.custom_address ca
        where ca.address in (select regexp_split_to_table(var_where_clause, ','))
    ),
    project_address_results AS (
        select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
            trim(both trim(trailing pa.suburbname from pa.address)) as validaddressstreet, pa.suburbname as validaddresssuburb, 
            pa.postcode as validaddresspostcode, pa.principaladdresssiteoid as principaladdresssiteoid, 
            cas.community as community, ka.kyng as kyng,
            ST_AsGeoJSON(ST_Transform(pa.geom, 4326))::jsonb as geojson,
            null::jsonb as matchcodes,
            null::jsonb as geocoder_result,
            false as found_in_custom,
            true as found_in_project
        from public.project_addresspoints pa
        inner join community_areas cas on ST_Intersects(pa.geom, cas.geom) 
        inner join kyng_areas ka on ST_Intersects(pa.geom, ka.geom) 
        where pa.address in (select regexp_split_to_table(var_where_clause, ','))
        AND NOT EXISTS (SELECT 1 FROM custom_address_results)
    ),
    geocoder_results AS (
        SELECT 
            CASE 
                WHEN address_point_details IS NOT NULL 
                     AND (address_point_details->>'validaddressstreet' IS NOT NULL AND address_point_details->>'validaddressstreet' != '')
                     AND (address_point_details->>'validaddresssuburb' IS NOT NULL AND address_point_details->>'validaddresssuburb' != '')
                     AND (address_point_details->>'validaddresspostcode' IS NOT NULL AND address_point_details->>'validaddresspostcode' != '')
                     AND (address_point_details->>'principaladdresssiteoid' IS NOT NULL)
                     AND (address_point_details->>'community' IS NOT NULL AND address_point_details->>'community' != '')
                     AND (address_point_details->>'kyng' IS NOT NULL AND address_point_details->>'kyng' != '')
                THEN 200
                WHEN address_point_details IS NOT NULL 
                     AND (address_point_details->>'validaddressstreet' IS NOT NULL AND address_point_details->>'validaddressstreet' != '')
                     AND (address_point_details->>'validaddresssuburb' IS NOT NULL AND address_point_details->>'validaddresssuburb' != '')
                     AND (address_point_details->>'validaddresspostcode' IS NOT NULL AND address_point_details->>'validaddresspostcode' != '')
                     AND (address_point_details->>'principaladdresssiteoid' IS NOT NULL)
                THEN 404
                ELSE 403
            END AS status,
            address_text AS searchaddressstreet,
            given_suburb AS searchaddresssuburb,
            COALESCE((address_point_details->>'validaddressstreet')::text, '') AS validaddressstreet,
            COALESCE((address_point_details->>'validaddresssuburb')::text, '') AS validaddresssuburb,
            COALESCE((address_point_details->>'validaddresspostcode')::text, '') AS validaddresspostcode,
            COALESCE((address_point_details->>'principaladdresssiteoid')::integer, -1) AS principaladdresssiteoid,
            COALESCE((address_point_details->>'community')::text, '') AS community,
            COALESCE((address_point_details->>'kyng')::text, '') AS kyng,
            COALESCE(
                (address_point_details->>'geom')::jsonb,
                ST_AsGeoJSON(ST_Transform(ST_SetSRID(ST_Point(0, 0), 7844), 4326))::jsonb
            ) as geojson,
            (geocoder_result->>'matchCodes')::jsonb as matchcodes,
            (geocoder_result)::jsonb as geocoder_result,
            false as found_in_custom,
            false as found_in_project
        WHERE NOT EXISTS (SELECT 1 FROM custom_address_results)
        AND NOT EXISTS (SELECT 1 FROM project_address_results)
    )
    SELECT * FROM (
        SELECT * FROM custom_address_results
        UNION ALL
        SELECT * FROM project_address_results
        UNION ALL
        SELECT * FROM geocoder_results
    ) results
    LIMIT 1;
end
$$;


ALTER FUNCTION "public"."get_validated_addresspoint_from_address"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."has_all_permissions"("permissions" "text"[]) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT NOT EXISTS (
    SELECT 1
    FROM unnest(permissions) AS required_perm
    WHERE NOT has_permission(required_perm)
  );
$$;


ALTER FUNCTION "public"."has_all_permissions"("permissions" "text"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."has_all_permissions"("permissions" "text"[]) IS 'Check if user has ALL of the provided permissions. Returns true only if all match.';



CREATE OR REPLACE FUNCTION "public"."has_any_permission"("permissions" "text"[]) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM unnest(permissions) AS required_perm
    WHERE has_permission(required_perm)
  );
$$;


ALTER FUNCTION "public"."has_any_permission"("permissions" "text"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."has_any_permission"("permissions" "text"[]) IS 'Check if user has ANY of the provided permissions. Returns true if at least one matches.';



CREATE OR REPLACE FUNCTION "public"."has_permission"("required_permission" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM jsonb_array_elements_text(
      COALESCE((auth.jwt() -> 'permissions')::jsonb, '[]'::jsonb)
    ) AS perm
    WHERE perm = required_permission
      OR required_permission LIKE perm || '.%'
  );
$$;


ALTER FUNCTION "public"."has_permission"("required_permission" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."has_permission"("required_permission" "text") IS 'Check if user has a specific permission with hierarchical matching. Returns true if user has exact permission or parent permission.';



CREATE OR REPLACE FUNCTION "public"."health_check"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
    result json;
begin
    -- Update last_check timestamp
    insert into public.health_status (last_check)
    values (now())
    on conflict (id)
    do update set last_check = now()
    returning json_build_object(
        'status', 'healthy',
        'timestamp', last_check
    ) into result;
    
    return result;
end;
$$;


ALTER FUNCTION "public"."health_check"() OWNER TO "postgres";


