CREATE OR REPLACE FUNCTION "public"."log_auth_failure"("p_email" "text", "p_error_type" "text", "p_error_message" "text", "p_ip_address" "text") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_log_id bigint;
    v_user_record auth.users%ROWTYPE;
BEGIN
    -- Get the user record if it exists
    SELECT * INTO v_user_record 
    FROM auth.users 
    WHERE email = p_email;

    -- Insert the log entry with user details
    INSERT INTO public.failed_login_attempts (
        email,
        auth_user_id,
        ip_address,
        auth_user_role,
        error_type,
        error_message
    )
    VALUES (
        p_email,
        v_user_record.id,
        CASE 
            WHEN p_ip_address IS NULL THEN NULL
            ELSE p_ip_address::inet
        END,
        v_user_record.role,
        p_error_type,
        p_error_message
    )
    RETURNING id INTO v_log_id;
    
    RETURN v_log_id;
END;
$$;


ALTER FUNCTION "public"."log_auth_failure"("p_email" "text", "p_error_type" "text", "p_error_message" "text", "p_ip_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_auth_failure"("p_email" "text", "p_error_type" "text", "p_error_message" "text", "p_ip_address" "text", "p_user_agent" "text") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_log_id bigint;
    v_user_record auth.users%ROWTYPE;
BEGIN
    -- Get the user record if it exists
    SELECT * INTO v_user_record 
    FROM auth.users 
    WHERE email = p_email;

    -- Insert the log entry with user details
    INSERT INTO public.failed_login_attempts (
        email,
        auth_user_id,
        ip_address,
        auth_user_role,
        error_type,
        error_message
    )
    VALUES (
        p_email,
        v_user_record.id,
        p_ip_address::inet,
        v_user_record.role,
        p_error_type,
        p_error_message
    )
    RETURNING id INTO v_log_id;
    
    RETURN v_log_id;
END;
$$;


ALTER FUNCTION "public"."log_auth_failure"("p_email" "text", "p_error_type" "text", "p_error_message" "text", "p_ip_address" "text", "p_user_agent" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."make_kyng_address_points"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$


DECLARE
  kyng_record RECORD;
  feature_collections jsonb;
  table_name TEXT;
BEGIN
  CREATE TEMP TABLE IF NOT EXISTS temp_table_kyngs AS
    SELECT DISTINCT kyng
    FROM kyng_areas;

  FOR kyng_record IN SELECT kyng FROM temp_table_kyngs
  LOOP
    EXECUTE format('
      SELECT jsonb_build_object(
        ''type'', ''FeatureCollection'',
        ''features'', jsonb_agg(ap.feature)
      )::jsonb
      FROM (
        SELECT jsonb_build_object(
          ''type'', ''Feature'',
          ''geometry'', ST_AsGeoJSON(ap.geom)::jsonb,
          ''properties'', jsonb_build_object(
            ''principaladdresssiteoid'', ap.principaladdresssiteoid,
            ''addressstringoid'', ap.addressstringoid,
            ''gurasid'', ap.gurasid,
            ''addresspointtype'', ap.addresspointtype,
            ''containment'', ap.containment,
            ''lastupdate'', ap.lastupdate,
            ''enddate'', ap.enddate,
            ''address'', ap.address,
            ''housenumber'', ap.housenumber
          )
        ) AS feature
        FROM address_point_extract ap
        WHERE EXISTS (
          SELECT 1 FROM kyng_areas k WHERE k.kyng = %L AND ST_Intersects(ap.geom, k.geom)
        )
      ) ap', kyng_record.kyng)
    INTO feature_collections;

    -- Generate a unique table name for each feature_collection
    table_name := 'kyng_' || kyng_record.kyng;

    -- Drop the table if it exists
    EXECUTE format('DROP TABLE IF EXISTS %I', table_name);

    -- Create a new table with columns for each property and a geom field
    EXECUTE format('
      CREATE TABLE %I (
        principaladdresssiteoid INTEGER,
        addressstringoid INTEGER,
        gurasid INTEGER,
        addresspointtype TEXT,
        containment TEXT,
        lastupdate DATE,
        enddate DATE,
        address TEXT,
        housenumber TEXT,
        geom GEOMETRY(Point, 7844)
      )', table_name);

    -- Insert the feature_collection into the table
    EXECUTE format('
      INSERT INTO %I (
        principaladdresssiteoid,
        addressstringoid,
        gurasid,
        addresspointtype,
        containment,
        lastupdate,
        enddate,
        address,
        housenumber,
        geom
      ) SELECT
        (feature->''properties''->>''principaladdresssiteoid'')::INTEGER,
        (feature->''properties''->>''addressstringoid'')::INTEGER,
        (feature->''properties''->>''gurasid'')::INTEGER,
        feature->''properties''->>''addresspointtype'',
        feature->''properties''->>''containment'',
        (feature->''properties''->>''lastupdate'')::DATE,
        (feature->''properties''->>''enddate'')::DATE,
        feature->''properties''->>''address'',
        feature->''properties''->>''housenumber'',
        ST_SetSRID(ST_MakePoint(
          (feature->''geometry''->''coordinates''->>0)::DOUBLE PRECISION,
          (feature->''geometry''->''coordinates''->>1)::DOUBLE PRECISION
        ), 7844)
      FROM jsonb_array_elements(%L::jsonb->''features'') AS feature', table_name, feature_collections);

    RAISE NOTICE 'Created table %I for Kyng %', table_name, kyng_record.kyng;
  END LOOP;

  DROP TABLE IF EXISTS temp_table_kyngs;
END;
$$;


ALTER FUNCTION "public"."make_kyng_address_points"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."new_custom_access_token_hook"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    AS $$

  declare
    claims jsonb;
    user_role public.app_role;
    coordinates_kyng jsonb := '[]'::jsonb;  -- Initialize coordinates_kyng as an empty JSON array
  begin
    -- Check if the user is marked as admin in the profiles table
    select role into user_role from public.user_roles where user_id = (event->>'user_id')::uuid;
    -- Check if the user is marked as a kyng coordinator in the profiles table
    select jsonb_agg(kyng_area_id) INTO coordinates_kyng from public.kyng_area_users_join where user_id = (event->>'user_id')::uuid;

    claims := event->'claims';

    if user_role is not null then
      -- Set the claim
      claims := jsonb_set(claims, '{user_role}', to_jsonb(user_role));
    else
      claims := jsonb_set(claims, '{user_role}', 'null');
    end if;

   -- Add the 'coordinates_kyng' property to claims
   if coordinates_kyng is not null then
     claims := jsonb_set(claims, '{coordinates_kyng}', coordinates_kyng);
   end if;

    -- Update the 'claims' object in the original event
    event := jsonb_set(event, '{claims}', claims);

    -- Return the modified or original event
    return event;
  end;
$$;


ALTER FUNCTION "public"."new_custom_access_token_hook"("event" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."pgnet_process_geoscape_geocoder_response"("address_string" "text", "api_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    api_response jsonb;
    match_codes jsonb;
    first_parcel jsonb;
    formatted_plan text;
    request_id bigint;
    http_response net.http_response_result;
BEGIN
    -- Validate API key
    IF api_key IS NULL OR api_key = '' THEN
        RAISE EXCEPTION 'API key cannot be null or empty';
    END IF;

    -- Make HTTP request and get response
    RAISE LOG 'MESSAGE process_geoscape_geocoder_response - calling psma geocoder with: %', address_string;
    
    SELECT net.http_get(
        url := 'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(address_string) || '&additionalProperties=parcelBundle',
        headers := jsonb_build_object(
            'Authorization', api_key,
            'Content-Type', 'application/json'
        ),
        timeout_milliseconds := 60000
    ) INTO request_id;

    -- Wait for and get the response
    SELECT * INTO http_response 
    FROM net.http_get_result(request_id);

    -- Check for successful response
    IF http_response.status <> 200 THEN
        RAISE LOG 'MESSAGE process_geoscape_geocoder_response - API error: %', http_response.response_body;
        RETURN jsonb_build_object(
            'matchType', 'apiError',
            'formattedAddress', null,
            'cadastralIdentifier', null
        );
    END IF;

    -- Parse response body
    api_response := http_response.response_body::jsonb;
    RAISE LOG 'MESSAGE process_geoscape_geocoder_response - raw response is: %', api_response;

    -- Handle case where no features are returned
    IF api_response->'features' IS NULL OR jsonb_array_length(api_response->'features') = 0 THEN
        RETURN jsonb_build_object(
            'matchType', 'noMatch',
            'formattedAddress', null,
            'cadastralIdentifier', null
        );
    END IF;

    -- Extract match codes from the first feature
    match_codes := api_response->'features'->0->'matchCode';
    
    -- Get first parcel from parcelBundle
    first_parcel := api_response->'features'->0->'properties'->'parcelBundle'->0;
    
    -- Only proceed with plan formatting if parcel exists
    IF first_parcel IS NOT NULL THEN
        -- Format the plan string
        formatted_plan := LEFT(first_parcel->>'plan', 2) || '/' || 
                         (first_parcel->>'lot') || '/' ||
                         COALESCE(first_parcel->>'section', '') || '/' ||
                         SUBSTRING(first_parcel->>'plan', 3);
    END IF;

    -- Check if all required match codes are "exact"
    IF match_codes IS NOT NULL AND
       match_codes->>'streetName' = 'exact' AND
       match_codes->>'stateTerritory' = 'exact' AND
       match_codes->>'streetType' = 'exact' AND
       match_codes->>'streetNumber1' = 'exact' THEN
        
        RETURN jsonb_build_object(
            'matchType', match_codes->>'localityName',
            'formattedAddress', api_response->'features'->0->'properties'->>'formattedAddress',
            'cadastralIdentifier', formatted_plan
        );
    ELSE
        RETURN jsonb_build_object(
            'matchType', 'noMatch',
            'formattedAddress', null,
            'cadastralIdentifier', null
        );
    END IF;

EXCEPTION
    WHEN others THEN
        RAISE WARNING 'Error in process_geoscape_geocoder_response: %', SQLERRM;
        RETURN jsonb_build_object(
            'matchType', 'noMatch',
            'formattedAddress', null,
            'cadastralIdentifier', null
        );
END;
$$;


ALTER FUNCTION "public"."pgnet_process_geoscape_geocoder_response"("address_string" "text", "api_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_downloads"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$

DECLARE
  var_boundary_rings text;
  var_addresspoints_uri text;
  var_addressstrings_uri text;
  var_waypoints_uri text;
  var_proways_uri text;
  var_properties_uri text;
  var_spatial_count_filter text;
  var_spatial_filter text;
  var_custom_principaladdresssiteoids text;
  var_custom_principaladdresssiteoids_count_filter text;
  var_custom_principaladdresssiteoids_filter text;
  var_content_type text;
  var_record_count integer;
  var_properties_increment integer := 100;
  var_addresses_increment integer := 2000;
  var_offset_value integer;

begin

  WITH boundary AS (
    SELECT ST_AsGeoJSON(ST_Transform(ST_Union(project_area.wkb_geometry), 4326)) AS project_boundary from project_area
  )
  SELECT project_boundary::json -> 'coordinates' FROM boundary into var_boundary_rings;
 
  var_addresspoints_uri := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query';
  var_addressstrings_uri := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/3/query';
  var_waypoints_uri := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/0/query';
  var_proways_uri := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/2/query';
  var_properties_uri := 'https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Land_Parcel_Property_Theme_multiCRS/FeatureServer/12/query';
  var_content_type := 'application/x-www-form-urlencoded';
 
  var_spatial_count_filter := 'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || '&geometryType=esriGeometryPolygon&inSR=4326' ||
      '&spatialRel=esriSpatialRelIntersects&returnCountOnly=true&f=geojson';
     
  with custom_addresses_query as
  (
  	SELECT ca.principaladdresssiteoid from custom_address ca where ca.principaladdresssiteoid NOT IN
	  (
	  	SELECT pap.principaladdresssiteoid from project_addresspoints pap
	  )
  )
  SELECT string_agg(principaladdresssiteoid::text, ',') FROM custom_addresses_query INTO var_custom_principaladdresssiteoids; 
 

 truncate table project_addresspoints;

 PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_addresspoints_uri, var_spatial_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
  
  	  var_spatial_filter := 'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || '&geometryType=esriGeometryPolygon&inSR=4326' ||
		  '&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||
		  var_addresses_increment || '&f=geojson';
 
	  with addresspoints_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_addresspoints_uri, var_spatial_filter, var_content_type) AS addresspoints_json
	  ),
	  result_addresspoints AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS addresspointoid,
		  feature::json -> 'properties' ->> 'address'::TEXT AS address,
		  feature::json -> 'properties' ->> 'housenumber'::TEXT AS housenumber,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '2' THEN 'Unit/Strata'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '3' THEN 'Building'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '4' THEN 'Homestead'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '5' THEN 'Monument'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '10' THEN 'Other'
		  END AS addresspointtype,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
		  END AS containment,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM addresspoints_query
	  ),

	-- Get addressstrings
	  addresstrings_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
	--     from http_post(var_addressstrings_uri, var_addressstrings_filter, var_content_type) AS addressstrings_json
	   FROM http_post('https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/3/query',
		 'where=' || urlencode('msoid in (' || (SELECT string_agg(addressstringoid::text, ',') FROM result_addresspoints) || ')') || 
		 '&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&f=geojson',
		 'application/x-www-form-urlencoded') AS addressstrings_json
	  ),
	  result_addressstrings AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS addressstringoid,
		  (feature::json -> 'properties' ->> 'addresssitename')::text as addresssitename,
		  (feature::json -> 'properties' ->> 'buildingname')::text as buildingname,
		  (feature::json -> 'properties' ->> 'locationdescription')::text as locationdescription,
		  (feature::json -> 'properties' ->> 'roadname')::text as roadname,
		  (feature::json -> 'properties' ->> 'roadtype')::text as roadtype,
		  (feature::json -> 'properties' ->> 'roadsuffix')::text as roadsuffix,
		  (feature::json -> 'properties' ->> 'suburbname')::text as suburbname,
		  'NSW' as state,
		  (feature::json -> 'properties' ->> 'postcode')::text as postcode,
		  (feature::json -> 'properties' ->> 'council')::text as council,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '1' THEN 'Property Address'
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '2' THEN 'Delivery Address'
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '3' THEN 'Correspondence Address'
		  END AS addresstype,
		  CASE
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '1' then 'Rural'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '2' then 'Urban'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '3' then 'Unknown'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '4' then 'Waterway'
		  END AS ruraladdress,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '1' THEN 'Official Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '2' THEN 'Alias Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '3' THEN 'Unchecked Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '4' THEN 'Verified Address'
		  END AS addressstringtype,  
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
		  END AS roadside,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'officialaddressstringoid')::INT AS officialaddressstringoid,
		  (feature::json -> 'properties' ->> 'deliverypointid')::INT AS deliverypointid,
		  (feature::json -> 'properties' ->> 'routeoid')::INT AS routeoid,
		  (feature::json -> 'properties' ->> 'gnafprimarysiteid')::INT AS gnafprimarysiteid,
		  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
		  (feature::json -> 'properties' ->> 'sppropid')::INT AS sppropid,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '0' THEN 'No other data source matches'
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '1' THEN 'One data source matches'
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '2' THEN 'Two data sources match'
		  END AS addressconfidence,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
		  END AS containment,
		  (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
			  ELSE 'Unknown'
		  END AS contributororigin,  
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '0' THEN 'GURAS != Valnet'
			  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '1' THEN 'GURAS = Valnet'
		  END AS contributoralignment,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate
		FROM addresstrings_query
	  )
	  INSERT INTO project_addresspoints(addresspointoid,addresssitename,buildingname,locationdescription,address,housenumber,
		roadname,roadtype,roadsuffix,suburbname,state,postcode,council,addresstype,ruraladdress,principaladdresstype,addressstringtype,
		roadside,officialaddressstringoid,deliverypointid,routeoid,gnafprimarysiteid,propid,sppropid,addressconfidence,contributorid, 
		contributororigin,contributoralignment,addresspointtype,containment,gurasid,principaladdresssiteoid,addressstringoid,startdate,
		lastupdate,enddate,geom)
	  SELECT rap.addresspointoid,ras.addresssitename,ras.buildingname,ras.locationdescription,rap.address,rap.housenumber,
		ras.roadname,ras.roadtype,ras.roadsuffix,ras.suburbname,ras.state,ras.postcode,ras.council,ras.addresstype,ras.ruraladdress,
		ras.principaladdresstype,ras.addressstringtype,ras.roadside,ras.officialaddressstringoid,ras.deliverypointid,ras.routeoid,
		ras.gnafprimarysiteid,ras.propid,ras.sppropid,ras.addressconfidence,ras.contributorid,ras.contributororigin,
		ras.contributoralignment,rap.addresspointtype,rap.containment,rap.gurasid,rap.principaladdresssiteoid,rap.addressstringoid,rap.startdate,
		rap.lastupdate,rap.enddate,rap.geom 
		FROM result_addresspoints rap left join result_addressstrings ras on rap.addressstringoid = ras.addressstringoid;
	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
  END LOOP;
  
  PERFORM http_reset_curlopt();

  truncate table project_waypoints;

  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_waypoints_uri, var_spatial_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
  
  	  var_spatial_filter := 'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || '&geometryType=esriGeometryPolygon&inSR=4326' ||
		  '&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||
		  var_addresses_increment || '&f=geojson';
 
	  with waypoints_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_waypoints_uri, var_spatial_filter, var_content_type) AS waypoints_json
	  ),
	  result_waypoints AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS waypointoid,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
		  (feature::json -> 'properties' ->> 'roadnameextentoid')::INT AS roadnameextentoid,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
			  ELSE 'Unknown'
		  END AS contributororigin,
		 (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
		  CASE
			when (feature::json -> 'properties' ->> 'derivedby')::text = '1' then 'Urban Calculated'
			when (feature::json -> 'properties' ->> 'derivedby')::text = '2' then 'Rural Calculated'
			when (feature::json -> 'properties' ->> 'derivedby')::text = '3' then 'Rural Derived'
		  END AS derivedby,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM waypoints_query
	  )
	  INSERT INTO project_waypoints(waypointoid,address,housenumber,gurasid,principaladdresssiteoid,addressstringoid,addresspointoid,
		roadnameextentoid,principaladdresstype,contributororigin,contributorid,derivedby,startdate,lastupdate,enddate,geom)
	  SELECT rwp.waypointoid,pap.address,pap.housenumber,rwp.gurasid,rwp.principaladdresssiteoid,rwp.addressstringoid,rwp.addresspointoid,
		rwp.roadnameextentoid,rwp.principaladdresstype,rwp.contributororigin,rwp.contributorid,rwp.derivedby,rwp.startdate,rwp.lastupdate,
		rwp.enddate,rwp.geom 
		FROM result_waypoints rwp left join project_addresspoints pap on rwp.addresspointoid = pap.addresspointoid;  
	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
  END LOOP;
  
  PERFORM http_reset_curlopt();
 
 
  truncate table project_proways;
 
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
 
  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_proways_uri, var_spatial_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
  
  	  var_spatial_filter := 'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || '&geometryType=esriGeometryPolygon&inSR=4326' ||
		  '&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||
		  var_addresses_increment || '&f=geojson';
 
	  with proways_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_proways_uri, var_spatial_filter, var_content_type) AS proways_json
	  ),
	  result_proways AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS prowayoid,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'waypointoid')::INT AS waypointoid,
		  (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
		  END AS roadside,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM proways_query
	  )
	  INSERT INTO project_proways(prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
		lastupdate,enddate,geom)
	  SELECT prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
		lastupdate,enddate,geom 
		FROM result_proways;
	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
  END LOOP;
  
  PERFORM http_reset_curlopt();
 
 
  truncate table project_properties;
 
  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');
  
  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_properties_uri, var_spatial_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
  
  	  var_spatial_filter := 'geometry=' || urlencode('{"rings": ' || var_boundary_rings || '}') || '&geometryType=esriGeometryPolygon&inSR=4326' ||
		  '&spatialRel=esriSpatialRelIntersects&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||
		  var_properties_increment || '&f=geojson';
 
	  with properties_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_properties_uri, var_spatial_filter, var_content_type) AS properties_json
	  ),
	  result_properties AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS propertyoid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '1' THEN 'All property Lots found in VALNET'
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '5' THEN 'One property Lot not found in VALNET'
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '6' THEN 'One or more property Lot not found in VALNET'
		  END AS propertytype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '1' THEN 'CANCELLED'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '2' THEN 'CURRENT'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '3' THEN 'PROFORMA'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '4' THEN 'SKELETON'
		  END AS valnetpropertystatus,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '1' THEN 'Rural'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '2' THEN 'Urban'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '3' THEN 'Unknown'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '4' THEN 'Waterway'
		  END AS valnetpropertytype,
		  (feature::json -> 'properties' ->> 'dissolveparcelcount')::INT AS dissolveparcelcount,
		  (feature::json -> 'properties' ->> 'valnetlotcount')::INT AS valnetlotcount,
		  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
		  (feature::json -> 'properties' ->> 'superlot')::text AS superlot,
		  (feature::json -> 'properties' ->> 'housenumber')::text AS housenumber,
		  (feature::json -> 'properties' ->> 'address')::text AS address,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_Multi(ST_GeomFromGeoJSON(feature::json -> 'geometry'))), 7844) AS geom
		FROM properties_query
	  )
	  INSERT INTO project_properties(propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,
		valnetlotcount,propid,superlot,housenumber,address,principaladdresstype,gurasid,principaladdresssiteoid,
		addressstringoid,startdate,lastupdate,enddate,geom)
	  SELECT propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,valnetlotcount,propid,superlot,housenumber,
				address,principaladdresstype,gurasid,principaladdresssiteoid,addressstringoid,startdate,lastupdate,enddate,geom 
	  FROM result_properties;
	  
	  var_offset_value := var_offset_value + var_properties_increment;
	  
  END LOOP;
  
  PERFORM http_reset_curlopt();


  PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  with custom_addresses_query as
 (
 	SELECT ca.principaladdresssiteoid from custom_address ca where ca.principaladdresssiteoid NOT IN
	  (
	  	SELECT pap.principaladdresssiteoid from project_addresspoints pap
	  )
 )
 SELECT string_agg(principaladdresssiteoid::text, ',') FROM custom_addresses_query INTO var_custom_principaladdresssiteoids; 
 
 var_custom_principaladdresssiteoids_count_filter := 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
  '&returnCountOnly=true&f=geojson';


  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_addresspoints_uri, var_custom_principaladdresssiteoids_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
  
   
	 var_custom_principaladdresssiteoids_filter := 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
	  '&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||var_addresses_increment || '&f=geojson';
  
	  with custom_addresspoints_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_addresspoints_uri, var_custom_principaladdresssiteoids_filter, var_content_type) AS custom_addresspoints_json
	  ),
	  result_custom_addresspoints AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS addresspointoid,
		  feature::json -> 'properties' ->> 'address'::TEXT AS address,
		  feature::json -> 'properties' ->> 'housenumber'::TEXT AS housenumber,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '2' THEN 'Unit/Strata'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '3' THEN 'Building'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '4' THEN 'Homestead'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '5' THEN 'Monument'
			WHEN (feature::json -> 'properties' ->> 'addresspointtype')::TEXT = '10' THEN 'Other'
		  END AS addresspointtype,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
		  END AS containment,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM custom_addresspoints_query
	  ),
	-- Get addressstrings for Custom Addresses 
	  custom_addresstrings_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_addressstrings_uri, var_custom_principaladdresssiteoids_filter, var_content_type) AS custom_addressstrings_json
	  ),
	  result_custom_addressstrings AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS addressstringoid,
		  (feature::json -> 'properties' ->> 'addresssitename')::text as addresssitename,
		  (feature::json -> 'properties' ->> 'buildingname')::text as buildingname,
		  (feature::json -> 'properties' ->> 'locationdescription')::text as locationdescription,
		  (feature::json -> 'properties' ->> 'roadname')::text as roadname,
		  (feature::json -> 'properties' ->> 'roadtype')::text as roadtype,
		  (feature::json -> 'properties' ->> 'roadsuffix')::text as roadsuffix,
		  (feature::json -> 'properties' ->> 'suburbname')::text as suburbname,
		  'NSW' as state,
		  (feature::json -> 'properties' ->> 'postcode')::text as postcode,
		  (feature::json -> 'properties' ->> 'council')::text as council,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '1' THEN 'Property Address'
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '2' THEN 'Delivery Address'
			  WHEN (feature::json -> 'properties' ->> 'addresstype')::text = '3' THEN 'Correspondence Address'
		  END AS addresstype,
		  CASE
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '1' then 'Rural'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '2' then 'Urban'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '3' then 'Unknown'
			when (feature::json -> 'properties' ->> 'ruraladdress')::text = '4' then 'Waterway'
		  END AS ruraladdress,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '1' THEN 'Official Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '2' THEN 'Alias Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '3' THEN 'Unchecked Address'
			  WHEN (feature::json -> 'properties' ->> 'addressstringtype')::text = '4' THEN 'Verified Address'
		  END AS addressstringtype,  
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
		  END AS roadside,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'officialaddressstringoid')::INT AS officialaddressstringoid,
		  (feature::json -> 'properties' ->> 'deliverypointid')::INT AS deliverypointid,
		  (feature::json -> 'properties' ->> 'routeoid')::INT AS routeoid,
		  (feature::json -> 'properties' ->> 'gnafprimarysiteid')::INT AS gnafprimarysiteid,
		  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
		  (feature::json -> 'properties' ->> 'sppropid')::INT AS sppropid,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '0' THEN 'No other data source matches'
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '1' THEN 'One data source matches'
			WHEN (feature::json -> 'properties' ->> 'addressconfidence')::TEXT = '2' THEN 'Two data sources match'
		  END AS addressconfidence,
		  CASE
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '1' THEN 'Property'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '2' THEN 'Outside'
			WHEN (feature::json -> 'properties' ->> 'containment')::TEXT = '3' THEN 'Unknown'
		  END AS containment,
		  (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
			  ELSE 'Unknown'
		  END AS contributororigin,  
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '0' THEN 'GURAS != Valnet'
			  WHEN (feature::json -> 'properties' ->> 'contributoralignment')::text = '1' THEN 'GURAS = Valnet'
		  END AS contributoralignment,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate
		FROM custom_addresstrings_query
	  )
	  INSERT INTO project_addresspoints(addresspointoid,addresssitename,buildingname,locationdescription,address,housenumber,
		roadname,roadtype,roadsuffix,suburbname,state,postcode,council,addresstype,ruraladdress,principaladdresstype,addressstringtype,
		roadside,officialaddressstringoid,deliverypointid,routeoid,gnafprimarysiteid,propid,sppropid,addressconfidence,contributorid, 
		contributororigin,contributoralignment,addresspointtype,containment,gurasid,principaladdresssiteoid,addressstringoid,startdate,
		lastupdate,enddate,geom)
	  SELECT rcap.addresspointoid,rcas.addresssitename,rcas.buildingname,rcas.locationdescription,rcap.address,rcap.housenumber,
		rcas.roadname,rcas.roadtype,rcas.roadsuffix,rcas.suburbname,rcas.state,rcas.postcode,rcas.council,rcas.addresstype,rcas.ruraladdress,
		rcas.principaladdresstype,rcas.addressstringtype,rcas.roadside,rcas.officialaddressstringoid,rcas.deliverypointid,rcas.routeoid,
		rcas.gnafprimarysiteid,rcas.propid,rcas.sppropid,rcas.addressconfidence,rcas.contributorid,rcas.contributororigin,
		rcas.contributoralignment,rcap.addresspointtype,rcap.containment,rcap.gurasid,rcap.principaladdresssiteoid,rcap.addressstringoid,rcap.startdate,
		rcap.lastupdate,rcap.enddate,rcap.geom 
		FROM result_custom_addresspoints rcap left join result_custom_addressstrings rcas on rcap.addressstringoid = rcas.addressstringoid;
	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
  END LOOP;
 
 PERFORM http_reset_curlopt();
 
 
 PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_waypoints_uri, var_custom_principaladdresssiteoids_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
   
	 var_custom_principaladdresssiteoids_filter := 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
	  '&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||var_addresses_increment || '&f=geojson';
  
	 with custom_waypoints_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_waypoints_uri, var_custom_principaladdresssiteoids_filter, var_content_type) AS custom_waypoints_json
	  ),
	  result_custom_waypoints AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS waypointoid,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
		  (feature::json -> 'properties' ->> 'roadnameextentoid')::INT AS roadnameextentoid,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '1' THEN 'Council'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '2' THEN 'VALNET'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '4' THEN 'GNAF'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '6' THEN 'GURAS'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '8' THEN 'Land and Housing Corporation'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '9' THEN 'RAAP'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '10' THEN 'Australia Post'
			  WHEN (feature::json -> 'properties' ->> 'contributororigin')::text = '11' THEN 'GURAS App'
			  ELSE 'Unknown'
		  END AS contributororigin,
		 (feature::json -> 'properties' ->> 'contributorid')::TEXT AS contributorid,
		  CASE
			when (feature::json -> 'properties' ->> 'derivedby')::text = '1' then 'Urban Calculated'
			when (feature::json -> 'properties' ->> 'derivedby')::text = '2' then 'Rural Calculated'
			when (feature::json -> 'properties' ->> 'derivedby')::text = '3' then 'Rural Derived'
		  END AS derivedby,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM custom_waypoints_query
	  )
	  INSERT INTO project_waypoints(waypointoid,address,housenumber,gurasid,principaladdresssiteoid,addressstringoid,addresspointoid,
		roadnameextentoid,principaladdresstype,contributororigin,contributorid,derivedby,startdate,lastupdate,enddate,geom)
	  SELECT rcwp.waypointoid,pap.address,pap.housenumber,rcwp.gurasid,rcwp.principaladdresssiteoid,rcwp.addressstringoid,rcwp.addresspointoid,
		rcwp.roadnameextentoid,rcwp.principaladdresstype,rcwp.contributororigin,rcwp.contributorid,rcwp.derivedby,rcwp.startdate,rcwp.lastupdate,
		rcwp.enddate,rcwp.geom 
		FROM result_custom_waypoints rcwp left join project_addresspoints pap on rcwp.addresspointoid = pap.addresspointoid;  
 	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
 END LOOP;

 PERFORM http_reset_curlopt();
 
 
 PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');


  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_proways_uri, var_custom_principaladdresssiteoids_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
   
	 var_custom_principaladdresssiteoids_filter := 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
	  '&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||var_addresses_increment || '&f=geojson';
  
	  with custom_proways_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_proways_uri, var_custom_principaladdresssiteoids_filter, var_content_type) AS custom_proways_json
	  ),
	  result_custom_proways AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS prowayoid,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'waypointoid')::INT AS waypointoid,
		  (feature::json -> 'properties' ->> 'addresspointoid')::INT AS addresspointoid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '1' THEN 'Left'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '2' THEN 'Right'
			  WHEN (feature::json -> 'properties' ->> 'roadside')::text = '3' THEN 'Unknown'
		  END AS roadside,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_GeomFromGeoJSON(feature::json -> 'geometry')), 7844) AS geom
		FROM custom_proways_query
	  )
	  INSERT INTO project_proways(prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
		lastupdate,enddate,geom)
	  SELECT prowayoid,gurasid,principaladdresssiteoid,waypointoid,addresspointoid,roadside,startdate,
		lastupdate,enddate,geom 
		FROM result_custom_proways;
  	  
	  var_offset_value := var_offset_value + var_addresses_increment;
	  
 END LOOP;
 
 PERFORM http_reset_curlopt();
 
 
 PERFORM http_set_curlopt('CURLOPT_TIMEOUT_MS', '35000');

  
  SELECT (("content"::json -> 'properties' ->> 'count')::text)::int 
  from http_post(var_properties_uri, var_custom_principaladdresssiteoids_count_filter, var_content_type) INTO var_record_count;

  var_offset_value := 0;

  WHILE var_offset_value < var_record_count LOOP
   
	 var_custom_principaladdresssiteoids_filter := 'where=' || urlencode('principaladdresssiteoid in (' || var_custom_principaladdresssiteoids || ')') || 
	  '&outSR=7844&outFields=*&resultOffset=' ||  var_offset_value || '&resultRecordCount=' ||var_properties_increment || '&f=geojson';
  
	  with custom_properties_query AS (
		SELECT json_array_elements_text("content"::json -> 'features') AS feature
		from http_post(var_properties_uri, var_custom_principaladdresssiteoids_filter, var_content_type) AS custom_properties_json
	  ),
	  result_custom_properties AS (
		SELECT
		  (feature::json -> 'properties' ->> 'msoid')::INT AS propertyoid,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '1' THEN 'All property Lots found in VALNET'
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '5' THEN 'One property Lot not found in VALNET'
			  WHEN (feature::json -> 'properties' ->> 'propertytype')::text = '6' THEN 'One or more property Lot not found in VALNET'
		  END AS propertytype,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '1' THEN 'CANCELLED'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '2' THEN 'CURRENT'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '3' THEN 'PROFORMA'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertystatus')::text = '4' THEN 'SKELETON'
		  END AS valnetpropertystatus,
		  CASE
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '1' THEN 'Rural'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '2' THEN 'Urban'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '3' THEN 'Unknown'
			  WHEN (feature::json -> 'properties' ->> 'valnetpropertytype')::text = '4' THEN 'Waterway'
		  END AS valnetpropertytype,
		  (feature::json -> 'properties' ->> 'dissolveparcelcount')::INT AS dissolveparcelcount,
		  (feature::json -> 'properties' ->> 'valnetlotcount')::INT AS valnetlotcount,
		  (feature::json -> 'properties' ->> 'propid')::INT AS propid,
		  (feature::json -> 'properties' ->> 'superlot')::text AS superlot,
		  (feature::json -> 'properties' ->> 'housenumber')::text AS housenumber,
		  (feature::json -> 'properties' ->> 'address')::text AS address,
		  CASE
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '1' then 'Primary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '2' then 'Secondary'
			when (feature::json -> 'properties' ->> 'principaladdresstype')::text = '3' then 'Alternate'
		  END AS principaladdresstype,
		  (feature::json -> 'properties' ->> 'gurasid')::INT AS gurasid,
		  (feature::json -> 'properties' ->> 'principaladdresssiteoid')::INT AS principaladdresssiteoid,
		  (feature::json -> 'properties' ->> 'addressstringoid')::INT AS addressstringoid,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'startdate')::TEXT, '')::NUMERIC / 1000.0) AS startdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'lastupdate')::TEXT, '')::NUMERIC / 1000.0) AS lastupdate,
		  TO_TIMESTAMP(NULLIF((feature::json -> 'properties' ->> 'enddate')::TEXT, '')::NUMERIC / 1000.0) AS enddate,
		  ST_SetSRID(st_force2d(ST_Multi(ST_GeomFromGeoJSON(feature::json -> 'geometry'))), 7844) AS geom
		FROM custom_properties_query
	  )
	  INSERT INTO project_properties(propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,
		valnetlotcount,propid,superlot,housenumber,address,principaladdresstype,gurasid,principaladdresssiteoid,
		addressstringoid,startdate,lastupdate,enddate,geom)
	  SELECT propertyoid,propertytype,valnetpropertystatus,valnetpropertytype,dissolveparcelcount,valnetlotcount,propid,superlot,housenumber,
				address,principaladdresstype,gurasid,principaladdresssiteoid,addressstringoid,startdate,lastupdate,enddate,geom 
	  FROM result_custom_properties;
  	  
	  var_offset_value := var_offset_value + var_properties_increment;
	  
  END LOOP;
 
  PERFORM http_reset_curlopt();
 
END;
$$;


ALTER FUNCTION "public"."process_downloads"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_geoscape_geocoder_response"("address_string" "text", "api_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    api_response jsonb;
    match_codes jsonb;
    first_parcel jsonb;
    formatted_plan text;
    raw_response text;
    match_quality text;
    valid_match boolean;
BEGIN
    -- Validate API key
    IF api_key IS NULL OR api_key = '' THEN
        RAISE EXCEPTION 'API key cannot be null or empty';
    END IF;

    -- Make HTTP request and get response
    BEGIN
        SELECT content, content::text INTO api_response, raw_response
        FROM http((
          'GET',
          'https://api.psma.com.au/v2/addresses/geocoder?address=' || urlencode(address_string) || '&stateFilter=NSW&additionalProperties=parcelBundle',
          ARRAY[http_header('Authorization', api_key)],
          NULL,
          NULL
        )::http_request);
        RAISE LOG 'API Response JSON: %', api_response;
        RAISE LOG 'API Response Raw: %', raw_response;
     EXCEPTION 
        WHEN invalid_text_representation THEN
            RAISE LOG 'MESSAGE process_geoscape_geocoder_response - Invalid JSON response from API';
            RETURN jsonb_build_object(
              'formattedAddress', null,
              'streetNumber1', null,
              'streetNumber2', null,
              'streetName', null,
              'streetType', null,
              'streetTypeDescription', null,
              'localityName', null,
              'postcode', null,
              'stateTerritory', null,
              'attribution', null,
              'addressRecordType', null,
              'aliasPrincipal', null,
              'geoFeature', null,
              'cadastralIdentifier', null,
              'matchType', 'apiError',
              'matchQuality', null,
              'matchScore', null,
              'matchCodes', match_codes
            );
    END;

    -- Handle case where no features are returned
    IF api_response->'features' IS NULL OR jsonb_array_length(api_response->'features') = 0 THEN
        RETURN jsonb_build_object(
            'formattedAddress', null,
            'streetNumber1', null,
            'streetNumber2', null,
            'streetName', null,
            'streetType', null,
            'streetTypeDescription', null,
            'localityName', null,
            'postcode', null,
            'stateTerritory', null,
            'attribution', null,
            'addressRecordType', null,
            'aliasPrincipal', null,
            'geoFeature', null,
            'cadastralIdentifier', null,
            'matchType', 'noMatch',
            'matchQuality', null,
            'matchScore', null,
            'matchCodes', match_codes
        );
    END IF;

    -- Extract match codes and match quality from the first feature
    match_codes := api_response->'features'->0->'matchCode';
    match_quality := api_response->'features'->0->>'matchQuality';
    
    -- Get first parcel from parcelBundle
    first_parcel := api_response->'features'->0->'properties'->'parcelBundle'->0;
    
    -- Only proceed with plan formatting if parcel exists
    IF first_parcel IS NOT NULL THEN
        -- Format the plan string
        formatted_plan := LEFT(first_parcel->>'plan', 2) || '/' || 
                         (first_parcel->>'lot') || '/' ||
                         COALESCE(first_parcel->>'section', '') || '/' ||
                         SUBSTRING(first_parcel->>'plan', 3);
    END IF;

    -- Check if match quality is valid and required match codes meet criteria
    valid_match := 
        match_quality IN ('Exact', 'Confident', 'Good') AND
        match_codes IS NOT NULL AND
        (match_codes->>'streetName' = 'exact' OR match_codes->>'streetName' = 'fuzzy') AND
        match_codes->>'stateTerritory' = 'exact' AND
        match_codes->>'streetType' = 'exact' AND
        match_codes->>'streetNumber1' = 'exact';
        
    -- Build response object
    RETURN jsonb_build_object(
        'formattedAddress', api_response->'features'->0->'properties'->>'formattedAddress',
        'streetNumber1', api_response->'features'->0->'properties'->>'streetNumber1',
        'streetNumber2', api_response->'features'->0->'properties'->>'streetNumber2',
        'streetName', api_response->'features'->0->'properties'->>'streetName',
        'streetType', api_response->'features'->0->'properties'->>'streetType',
        'streetTypeDescription', api_response->'features'->0->'properties'->>'streetTypeDescription',
        'localityName', api_response->'features'->0->'properties'->>'localityName',
        'postcode', api_response->'features'->0->'properties'->>'postcode',
        'stateTerritory', api_response->'features'->0->'properties'->>'stateTerritory',
        'attribution', api_response->>'attribution',
        'addressRecordType', api_response->'features'->0->'properties'->>'addressRecordType',
        'aliasPrincipal', api_response->'features'->0->'properties'->>'aliasPrincipal',
        'geoFeature', api_response->'features'->0->'properties'->>'geoFeature',
        'cadastralIdentifier', formatted_plan,
        'matchType', api_response->'features'->0->>'matchType',
        'matchQuality', match_quality,
        'matchScore', api_response->'features'->0->>'matchScore',
        'matchCodes', match_codes
    );

EXCEPTION
    WHEN others THEN
        -- Log the error and return noMatch
        RAISE WARNING 'Error in process_geoscape_geocoder_response: %', SQLERRM;
        RETURN jsonb_build_object(
            'formattedAddress', null,
            'streetNumber1', null,
            'streetNumber2', null,
            'streetName', null,
            'streetType', null,
            'streetTypeDescription', null,
            'localityName', null,
            'postcode', null,
            'stateTerritory', null,
            'attribution', null,
            'addressRecordType', null,
            'aliasPrincipal', null,
            'geoFeature', null,
            'cadastralIdentifier', null,
            'matchType', 'noMatch',
            'matchQuality', null,
            'matchScore', null,
            'matchCodes', null
        );
END;
$$;


ALTER FUNCTION "public"."process_geoscape_geocoder_response"("address_string" "text", "api_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_kyng_areas"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
  row_record RECORD;
BEGIN
  -- Iterate over each row in kyng_areas table
  FOR row_record IN SELECT kyng, geom FROM kyng_areas LOOP
    -- Generate the table name
    EXECUTE 'CREATE TABLE IF NOT EXISTS addresspoint_' || row_record.kyng || ' AS ' ||
      'WITH boundary AS (' ||
        'SELECT ST_AsGeoJSON(ST_Transform($1, 4326)) AS result' ||
      '),' ||
      'features_query AS (' ||
        'SELECT json_array_elements_text("content"::json -> ''features'') AS feature' ||
        'FROM http_post(''https://portal.spatial.nsw.gov.au/server/rest/services/NSW_Geocoded_Addressing_Theme/FeatureServer/1/query'',' ||
          '''&geometry='' || urlencode(''{"rings": '' || (SELECT result::json -> ''coordinates'' FROM boundary) || ''}'') || ''&geometryType=esriGeometryPolygon&inSR=4326&spatialRel=esriSpatialRelContains&outSR=4326&outFields=*&f=geojson'',' ||
          '''application/x-www-form-urlencoded''' ||
        ') AS response_json' ||
      '),' ||
      'results AS (' ||
        'SELECT' ||
          '(feature::json -> ''properties'' ->> ''principaladdresssiteoid'')::INT AS principaladdresssiteoid,' ||
          '(feature::json -> ''properties'' ->> ''addressstringoid'')::INT AS addressstringoid,' ||
          '(feature::json -> ''properties'' ->> ''gurasid'')::INT AS gurasid,' ||
          'CASE' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''1'' THEN ''Property''' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''2'' THEN ''Unit/Strata''' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''3'' THEN ''Building''' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''4'' THEN ''Homestead''' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''5'' THEN ''Monument''' ||
            'WHEN (feature::json -> ''properties'' -> ''addresspointtype'')::TEXT = ''10'' THEN ''Other''' ||
          'END AS addresspointtype,' ||
          'CASE' ||
            'WHEN (feature::json -> ''properties'' -> ''containment'')::TEXT = ''1'' THEN ''Property''' ||
            'WHEN (feature::json -> ''properties'' -> ''containment'')::TEXT = ''2'' THEN ''Outside''' ||
            'WHEN (feature::json -> ''properties'' -> ''containment'')::TEXT = ''3'' THEN ''Unknown''' ||
          'END AS containment,' ||
          'feature::json -> ''properties'' -> ''urbanity'' AS urbanity,' ||
          'TO_TIMESTAMP(NULLIF((feature::json -> ''properties'' -> ''lastupdate'')::TEXT, '''')::NUMERIC / 1000.0) AS lastupdate,' ||
          'TO_TIMESTAMP(NULLIF((feature::json -> ''properties'' -> ''enddate'')::TEXT, '''')::NUMERIC / 1000.0) AS enddate,' ||
          'feature::json -> ''properties'' -> ''address''::TEXT AS address,' ||
          'feature::json -> ''properties'' -> ''housenumber''::TEXT AS housenumber,' ||
          'ST_SetSRID(ST_GeomFromGeoJSON(feature::json -> ''geometry''), 4326) AS geom' ||
        'FROM features_query' ||
      ')' ||
      'SELECT * FROM results';

    -- Delete previous data from the table
    EXECUTE 'TRUNCATE TABLE addresspoint_' || row_record.kyng;

    -- Insert the query result into the table
    EXECUTE 'INSERT INTO addresspoint_' || row_record.kyng || ' SELECT * FROM results';
  END LOOP;
END;
$_$;


ALTER FUNCTION "public"."process_kyng_areas"() OWNER TO "postgres";


