CREATE OR REPLACE FUNCTION "public"."refresh_spatial_data"("p_regenerate_area" boolean DEFAULT true, "max_retries" integer DEFAULT 3, "initial_backoff" integer DEFAULT 2) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_rings_geometry text;
  v_area_result jsonb;
  v_start_time timestamptz;
  v_counts jsonb;
  v_log_id bigint;

  v_addresspoints_count int := 0;
  v_waypoints_count int := 0;
  v_proways_count int := 0;
  v_properties_count int := 0;
  v_properties_singlepart_count int := 0;

  v_retry_count int;
  v_backoff_seconds int;
BEGIN
  v_start_time := clock_timestamp();

  -------------------------------------------------------------------
  -- Step 1: Regenerate project area (if requested)
  -------------------------------------------------------------------
  IF p_regenerate_area THEN
    RAISE NOTICE 'Step 1: Regenerating project area...';
    v_area_result := regenerate_project_area();

    IF NOT (v_area_result->>'success')::boolean THEN
      INSERT INTO spatial_refresh_log (
        started_at, completed_at, success, error_message,
        triggered_by, duration_seconds
      )
      VALUES (
        v_start_time, clock_timestamp(), false,
        'Failed to regenerate project area: ' || (v_area_result->>'error'),
        CASE WHEN current_setting('request.jwt.claims', true) IS NOT NULL
          THEN 'manual' ELSE 'cron' END,
        EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time))
      );
      RAISE EXCEPTION 'Failed to regenerate project area: %', v_area_result->>'error';
    END IF;
  END IF;

  -- Always read rings_text from the project_area table
  SELECT rings_text INTO v_rings_geometry FROM project_area LIMIT 1;
  IF v_rings_geometry IS NULL THEN
    INSERT INTO spatial_refresh_log (
      started_at, completed_at, success, error_message,
      triggered_by, duration_seconds
    )
    VALUES (
      v_start_time, clock_timestamp(), false,
      'No project area found. Run with p_regenerate_area=true first.',
      CASE WHEN current_setting('request.jwt.claims', true) IS NOT NULL
        THEN 'manual' ELSE 'cron' END,
      EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time))
    );
    RAISE EXCEPTION 'No project area found. Run with p_regenerate_area=true first.';
  END IF;

  -------------------------------------------------------------------
  -- Step 2: Extract addresspoints
  -------------------------------------------------------------------
  v_retry_count := 0;
  v_backoff_seconds := initial_backoff;
  LOOP
    BEGIN
      v_addresspoints_count := extract_addresspoints(v_rings_geometry, max_retries, initial_backoff);
      RAISE NOTICE '✓ Addresspoints extraction completed (% rows)', v_addresspoints_count;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count > max_retries THEN
        RAISE EXCEPTION 'extract_addresspoints failed after % retries: %', max_retries, SQLERRM;
      END IF;
      RAISE WARNING 'Addresspoints extraction error (retry %/%): %', v_retry_count, max_retries, SQLERRM;
      PERFORM pg_sleep(v_backoff_seconds);
      v_backoff_seconds := v_backoff_seconds * 2;
    END;
  END LOOP;

  -------------------------------------------------------------------
  -- Step 3: Extract waypoints
  -------------------------------------------------------------------
  v_retry_count := 0;
  v_backoff_seconds := initial_backoff;
  LOOP
    BEGIN
      v_waypoints_count := extract_waypoints(v_rings_geometry, max_retries, initial_backoff);
      RAISE NOTICE '✓ Waypoints extraction completed (% rows)', v_waypoints_count;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count > max_retries THEN
        RAISE EXCEPTION 'extract_waypoints failed after % retries: %', max_retries, SQLERRM;
      END IF;
      RAISE WARNING 'Waypoints extraction error (retry %/%): %', v_retry_count, max_retries, SQLERRM;
      PERFORM pg_sleep(v_backoff_seconds);
      v_backoff_seconds := v_backoff_seconds * 2;
    END;
  END LOOP;

  -------------------------------------------------------------------
  -- Step 4: Extract proways
  -------------------------------------------------------------------
  v_retry_count := 0;
  v_backoff_seconds := initial_backoff;
  LOOP
    BEGIN
      v_proways_count := extract_proways(v_rings_geometry, max_retries, initial_backoff);
      RAISE NOTICE '✓ Proways extraction completed (% rows)', v_proways_count;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count > max_retries THEN
        RAISE EXCEPTION 'extract_proways failed after % retries: %', max_retries, SQLERRM;
      END IF;
      RAISE WARNING 'Proways extraction error (retry %/%): %', v_retry_count, max_retries, SQLERRM;
      PERFORM pg_sleep(v_backoff_seconds);
      v_backoff_seconds := v_backoff_seconds * 2;
    END;
  END LOOP;

  -------------------------------------------------------------------
  -- Step 5: Extract properties
  -------------------------------------------------------------------
  v_retry_count := 0;
  v_backoff_seconds := initial_backoff;
  LOOP
    BEGIN
      v_properties_count := extract_properties(v_rings_geometry, max_retries, initial_backoff);
      RAISE NOTICE '✓ Properties extraction completed (% rows)', v_properties_count;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count > max_retries THEN
        RAISE EXCEPTION 'extract_properties failed after % retries: %', max_retries, SQLERRM;
      END IF;
      RAISE WARNING 'Properties extraction error (retry %/%): %', v_retry_count, max_retries, SQLERRM;
      PERFORM pg_sleep(v_backoff_seconds);
      v_backoff_seconds := v_backoff_seconds * 2;
    END;
  END LOOP;

  -------------------------------------------------------------------
  -- Step 6: Extract properties (singlepart)
  -------------------------------------------------------------------
  v_retry_count := 0;
  v_backoff_seconds := initial_backoff;
  LOOP
    BEGIN
      v_properties_singlepart_count := extract_properties_singlepart(v_rings_geometry, max_retries, initial_backoff);
      RAISE NOTICE '✓ Properties (singlepart) extraction completed (% rows)', v_properties_singlepart_count;
      EXIT;
    EXCEPTION WHEN OTHERS THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count > max_retries THEN
        RAISE EXCEPTION 'extract_properties_singlepart failed after % retries: %', max_retries, SQLERRM;
      END IF;
      RAISE WARNING 'Properties (singlepart) extraction error (retry %/%): %', v_retry_count, max_retries, SQLERRM;
      PERFORM pg_sleep(v_backoff_seconds);
      v_backoff_seconds := v_backoff_seconds * 2;
    END;
  END LOOP;

  -------------------------------------------------------------------
  -- Final counts and logging
  -------------------------------------------------------------------
  v_counts := jsonb_build_object(
    'addresspoints', v_addresspoints_count,
    'waypoints', v_waypoints_count,
    'proways', v_proways_count,
    'properties', v_properties_count,
    'properties_singlepart', v_properties_singlepart_count
  );

  INSERT INTO spatial_refresh_log (
    started_at, completed_at, success, result,
    triggered_by, duration_seconds, record_counts
  )
  VALUES (
    v_start_time, clock_timestamp(), true,
    jsonb_build_object(
      'area_regenerated', p_regenerate_area,
      'area_info', v_area_result
    ),
    CASE WHEN current_setting('request.jwt.claims', true) IS NOT NULL
      THEN 'manual' ELSE 'cron' END,
    EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time)),
    v_counts
  )
  RETURNING id INTO v_log_id;

  RETURN jsonb_build_object(
    'success', true,
    'log_id', v_log_id,
    'area_regenerated', p_regenerate_area,
    'area_info', v_area_result,
    'record_counts', v_counts,
    'duration_seconds', EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time)),
    'completed_at', clock_timestamp()
  );

EXCEPTION WHEN OTHERS THEN
  INSERT INTO spatial_refresh_log (
    started_at, completed_at, success, error_message,
    triggered_by, duration_seconds
  )
  VALUES (
    v_start_time, clock_timestamp(), false, SQLERRM,
    CASE WHEN current_setting('request.jwt.claims', true) IS NOT NULL
      THEN 'manual' ELSE 'cron' END,
    EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time))
  );

  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'error_detail', SQLSTATE,
    'failed_at', clock_timestamp(),
    'duration_seconds', EXTRACT(EPOCH FROM (clock_timestamp() - v_start_time))
  );
END;
$$;


ALTER FUNCTION "public"."refresh_spatial_data"("p_regenerate_area" boolean, "max_retries" integer, "initial_backoff" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."regenerate_project_area"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions', 'pg_catalog'
    AS $$
DECLARE
  v_area_count int;
  v_project_geom geometry;
  v_rings_text text;
  v_area_sqkm numeric;
  v_row_exists boolean;
BEGIN
  -- Authorization check for authenticated users
  IF current_setting('request.jwt.claims', true) IS NOT NULL THEN
    IF NOT has_permission('admin.site.data.spatial') THEN
      RAISE EXCEPTION 'Insufficient permissions. Requires admin.site.data.spatial';
    END IF;
  END IF;

  -- Count KYNG areas
  SELECT COUNT(*) INTO v_area_count FROM kyng_areas;
  IF v_area_count = 0 THEN
    RAISE EXCEPTION 'No KYNG areas found. Cannot generate project area.';
  END IF;

  -- Create unified project boundary
  SELECT 
    ST_Multi(
      ST_Buffer(
        ST_Buffer(
          ST_Collect(
            ST_MakePolygon(
              ST_ExteriorRing((dump).geom)
            )
          ),
          0.00001
        ),
        -0.00001
      )
    )
  INTO v_project_geom
  FROM (
    SELECT ST_Dump(ST_Union(geom)) AS dump
    FROM kyng_areas
  ) AS subquery;

  IF v_project_geom IS NULL THEN
    RAISE EXCEPTION 'Project geometry could not be generated from kyng_areas';
  END IF;

  -- Flatten multipolygon into polygons and extract rings
	SELECT
	  CASE
		WHEN ST_GeometryType(ST_Union(geom)) = 'ST_MultiPolygon' THEN
		  -- For MultiPolygon, extract all polygon exterior rings into a single array
		  (
			SELECT json_agg(
			  (ST_AsGeoJSON(ST_ExteriorRing((dump).geom))::json -> 'coordinates')
			)
			FROM ST_Dump(ST_Transform(ST_Union(geom), 4326)) as dump
		  )
		ELSE
		  -- For single Polygon, just get the coordinates
		  (ST_AsGeoJSON(ST_Transform(ST_Union(geom), 4326)))::json -> 'coordinates'
	  END
	INTO v_rings_text
	FROM kyng_areas;

  -- Calculate area
  v_area_sqkm := ST_Area(v_project_geom::geography) / 1000000;

  -- Update or insert into project_area
  SELECT EXISTS(SELECT 1 FROM project_area) INTO v_row_exists;
  IF v_row_exists THEN
    UPDATE project_area
    SET 
      geom = v_project_geom,
      rings_text = v_rings_text,
      kyng_count = v_area_count,
      last_generated = now(),
      area_sqkm = v_area_sqkm;
  ELSE
    INSERT INTO project_area (
      geom, rings_text, kyng_count, last_generated, area_sqkm
    )
    VALUES (
      v_project_geom, v_rings_text, v_area_count, now(), v_area_sqkm
    );
  END IF;

  -- Log success
  INSERT INTO project_area_log(success, kyng_areas_count, area_sqkm, rings_geometry, error, error_detail)
  VALUES (true, v_area_count, v_area_sqkm, v_rings_text, NULL, NULL);

  RETURN jsonb_build_object(
    'success', true,
    'kyng_areas_count', v_area_count,
    'area_sqkm', v_area_sqkm,
    'rings_geometry', v_rings_text,
    'row_exists', v_row_exists,
    'generated_at', now()
  );

EXCEPTION WHEN OTHERS THEN
  INSERT INTO project_area_log(success, kyng_areas_count, area_sqkm, rings_geometry, error, error_detail)
  VALUES (false, NULL, NULL, NULL, SQLERRM, SQLSTATE);

  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'error_detail', SQLSTATE
  );
END;
$$;


ALTER FUNCTION "public"."regenerate_project_area"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."regenerate_project_area"() IS 'Regenerates the project_area boundary from the union of all kyng_areas. Requires admin.site.data.spatial permission.';



