CREATE OR REPLACE FUNCTION "public"."save_first_function"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  rings_geometry TEXT;
BEGIN
	-- Get the boundary rings text
	SELECT '' || '{"rings": ' ||  ((ST_AsGeoJSON(ST_SetSRID(ST_Extent(geom), 4326)))::json -> 'coordinates')  || '}' || ''
	INTO rings_geometry FROM kyng_areas;

    -- Call the addresspoint extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_addresspoints(rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_addresspoints() completed successfully.';

    -- Call the waypoint extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_waypoints(rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_waypoints() completed successfully.';

    -- Call the proway extraction function in a loop until it completes successfully
    LOOP
        BEGIN
            PERFORM extract_proways(rings_geometry);            
            -- If no error occurs, exit the loop
            EXIT;
        EXCEPTION
            WHEN OTHERS THEN
                -- If an error occurs, log the error or take any other necessary action
                RAISE NOTICE 'Error occurred: %', SQLERRM;
                
                -- Add a delay between each retry to prevent overwhelming the system
                PERFORM pg_sleep(1); -- This will add a 1-second delay before the next retry
        END;
    END LOOP;    
    RAISE NOTICE 'extract_proways() completed successfully.';
END;
$$;


ALTER FUNCTION "public"."save_first_function"() OWNER TO "postgres";


