CREATE OR REPLACE FUNCTION "public"."trim_address_suburb"("given_suburb" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
declare
	var_test_suburb text;
	var_address_len int;
begin
	select upper(replace(btrim(given_suburb), '  ', ' ')) into var_test_suburb;
	if position( 'NSW' in var_test_suburb ) <> 0 then
		select btrim(replace(var_test_suburb, 'NSW', '')) into var_test_suburb;
	end if;
	select length(var_test_suburb) into var_address_len;
	if position( '2424' in var_test_suburb ) = (var_address_len - 3) then
		select btrim(replace(var_test_suburb, '2424', '')) into var_test_suburb;
	elsif position( '2429' in var_test_suburb ) = (var_address_len - 3) then
		select btrim(replace(var_test_suburb, '2429', '')) into var_test_suburb;
	end if;
	return upper(replace(btrim(var_test_suburb), '  ', ' '));
end;
$$;


