CREATE OR REPLACE FUNCTION "public"."update_kyng_area_user"("p_user_id" "uuid", "p_user_name" "text", "p_phone_number" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
    -- Update all records for the given user_id
    UPDATE public.kyng_area_users_join
    SET 
        user_name = p_user_name,
        phone_number = p_phone_number
    WHERE 
        user_id = p_user_id;

    -- If no rows were updated, raise an exception
    IF NOT FOUND THEN
        RAISE EXCEPTION 'No records found for the specified user_id';
    END IF;
END;
$$;


