CREATE OR REPLACE FUNCTION "public"."update_mailchimp_tags"("email_address" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  md5_hash text;
  server_prefix text := 'us20';
  api_key text := 'REPLACE_WITH_MAILCHIMP_API_KEY';
  list_id text := 'f2eeb1ee80';
  auth_header text := format('Basic %s',api_key);
  response json;
BEGIN
  -- Generate MD5 hash of the email field
 md5_hash := md5(email_address);

  -- Using the 'PUT' request takes care of all testing if the values exist on the Mailchimp server
SELECT content::json into response
FROM http((
  'PUT', format('https://%s.api.mailchimp.com/3.0/lists/%s/members/%s', server_prefix, list_id, md5_hash),
  ARRAY[ http_header('Authorization', format('Basic %s', api_key)) ],
  'application/json',
  json_build_object(
    'email_address', email_address,
    'status_if_new', 'subscribed',
    'skip_merge_validation', true,
    'tags', json_build_array('SOC')
  )::text
)::http_request);
END;
$$;


