CREATE OR REPLACE FUNCTION "public"."upsert_feature_attributes"("p_attributes" json[]) RETURNS SETOF "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_attr JSON;
    v_attr_id UUID;
BEGIN
    FOR v_attr IN SELECT json_array_elements(array_to_json(p_attributes))
    LOOP
        INSERT INTO feature_attributes (
            id,
            feature_id,
            field_id,
            value
        ) VALUES (
            COALESCE((v_attr->>'id')::UUID, uuid_generate_v4()),
            (v_attr->>'feature_id')::UUID,
            (v_attr->>'field_id')::UUID,
            v_attr->>'value'
        )
        ON CONFLICT (feature_id, field_id) DO UPDATE 
        SET value = EXCLUDED.value,
            last_edited = CURRENT_TIMESTAMP
        RETURNING id INTO v_attr_id;
        
        RETURN NEXT v_attr_id;
    END LOOP;
END;
$$;


ALTER FUNCTION "public"."upsert_feature_attributes"("p_attributes" json[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_spatial_feature"("p_feature_id" "uuid", "p_user_id" "uuid", "p_property_id" "uuid", "p_template_id" "uuid", "p_geom" "extensions"."geometry") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
    v_feature_id UUID;
    v_field_id UUID;
BEGIN
    -- Insert or update the spatial feature
    INSERT INTO spatial_features (id, user_id, property_id, template_id, geom)
    VALUES (
        COALESCE(p_feature_id, uuid_generate_v4()),
        p_user_id,
        p_property_id,
        p_template_id,
        p_geom
    )
    ON CONFLICT (id) DO UPDATE 
    SET geom = EXCLUDED.geom,
        last_edited = CURRENT_TIMESTAMP
    RETURNING id INTO v_feature_id;
    
    -- Ensure all template fields have corresponding attributes
    FOR v_field_id IN SELECT field_id FROM get_template_fields(p_template_id)
    LOOP
        INSERT INTO feature_attributes (feature_id, field_id, value)
        VALUES (v_feature_id, v_field_id, NULL)
        ON CONFLICT (feature_id, field_id) DO NOTHING;
    END LOOP;
    
    RETURN v_feature_id;
END;
$$;


