CREATE OR REPLACE FUNCTION "public"."validate_street_address"("input_address" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $_$
DECLARE
    formatted_address text;
    validation_errors text[] := '{}';
    number_part text;
    street_name_part text;
    street_type_part text;
    last_word text;
    last_part text;
    word_count int;
BEGIN
    -- Apply formatting rules: Uppercase and trim whitespace
    formatted_address := UPPER(TRIM(input_address));
    formatted_address := REGEXP_REPLACE(formatted_address, '[^A-Z0-9\s]', '', 'g');
    -- Split the address into parts
    number_part := SPLIT_PART(formatted_address, ' ', 1);
    word_count := REGEXP_COUNT(formatted_address, '\s') + 1;
    last_word := REVERSE(SPLIT_PART(REVERSE(formatted_address), ' ', 1));
    -- Extract the remaining part as street_name_part
    street_name_part := substring(formatted_address FROM '\w+\s+(.*)\s+\w+');
    -- If the last word is a directional term, adjust the street type part
    IF last_word IN ('EAST', 'WEST', 'NORTH', 'SOUTH') THEN
        street_type_part := TRIM(TRAILING last_word FROM TRIM(SPLIT_PART(formatted_address, ' ', word_count - 1)));
		street_name_part := substring(street_name_part FROM '^(.*)\s+\w+$');
    ELSE
        street_type_part := TRIM(SPLIT_PART(formatted_address, ' ', 3));
		last_word := '';
    END IF;
    -- Validate <number> part
    IF NOT (number_part ~ '^\d+[A-F]?$') THEN
        validation_errors := array_append(validation_errors, 'Invalid <number> part.');
    END IF;
    -- Validate <streetName> part
    IF NOT (street_name_part ~ '^[A-Z\s]+$') THEN
        validation_errors := array_append(validation_errors, 'Invalid <streetName> part.');
    END IF;
    -- Validate <streetType> part
    IF street_type_part IS NULL THEN
        validation_errors := array_append(validation_errors, 'Missing <streetType> part.');
	ELSIF street_type_part NOT IN (SELECT DISTINCT UPPER(abbreviation) FROM street_type_aliases) 
		AND street_type_part NOT IN (SELECT DISTINCT UPPER(street_type) FROM street_type_aliases) THEN
		validation_errors := array_append(validation_errors, 'Unknown <streetType> part. - ' || street_type_part);
	ELSIF street_type_part IN (SELECT DISTINCT UPPER(abbreviation) FROM street_type_aliases) THEN
		SELECT DISTINCT UPPER(street_type) INTO street_type_part
		FROM street_type_aliases WHERE UPPER(abbreviation) = street_type_part;
    END IF;
    -- Construct validation error message
    IF array_length(validation_errors, 1) > 0 THEN
         RETURN array_to_string(validation_errors, ', ');
    ELSE
		last_part := TRIM(street_type_part || ' ' || last_word);
        RETURN number_part || ' ' || street_name_part || ' ' || last_part;
    END IF;
END;
$_$;


ALTER FUNCTION "public"."validate_street_address"("input_address" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."x_get_addresspoint_from_address"("address_text" "text", "given_suburb" "text", "out_srid_value" integer, "api_key" "text") RETURNS TABLE("status" integer, "searchaddressstreet" "text", "searchaddresssuburb" "text", "validaddressstreet" "text", "validaddresssuburb" "text", "validaddresspostcode" "text", "principaladdresssiteoid" integer, "community" "text", "kyng" "text", "geojson" "jsonb")
    LANGUAGE "plpgsql"
    AS $$
declare
    var_search_address text;
    var_where_clause text;
    address_exists boolean;
    geocoder_result jsonb;
    site_oid_value integer;
    address_point_details jsonb;
begin
    select upper(address_text) || ' ' ||  upper(given_suburb) into var_search_address;
    RAISE LOG 'var_search_address: %', var_search_address || ' NSW';

    select public.get_query_address(upper(address_text), upper(given_suburb)) into var_where_clause;

    -- Get and log geocoder response
    SELECT process_geoscape_geocoder_response(var_search_address || ' NSW', api_key) INTO geocoder_result;
    RAISE LOG 'geocoder_response: %', geocoder_result;

    -- Get and log site_oid
    IF geocoder_result->>'matchType' != 'noMatch' THEN
        SELECT get_principaladdresssiteoid_from_cadastralidentifier(
            geocoder_result->>'cadastralIdentifier'
        ) INTO site_oid_value;
        RAISE LOG 'site_oid: %', site_oid_value;

        -- Get and log address point details
        IF site_oid_value IS NOT NULL THEN
            SELECT get_addresspoint_from_principaladdresssiteoid(site_oid_value) INTO address_point_details;
            RAISE LOG 'address_point: %', address_point_details;
        END IF;
    END IF;

    RETURN QUERY
    WITH custom_address_results AS (
        select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
            trim(both trim(trailing ca.suburb from ca.address)) as validaddressstreet, ca.suburb as validaddresssuburb, 
            ca.postcode as validaddresspostcode, ca.principaladdresssiteoid::int4 as principaladdresssiteoid, 
            ca.community as community, ca.kyng as kyng,
            ST_AsGeoJSON(ST_Transform(ST_SetSRID(ST_Point(0, 0), 7844), 4326))::jsonb as geojson
        from public.custom_address ca
        where ca.address in (select regexp_split_to_table(var_where_clause, ','))
    ),
    project_address_results AS (
        select 200 as status, address_text as searchaddressstreet, given_suburb as searchaddresssuburb, 
            trim(both trim(trailing pa.suburbname from pa.address)) as validaddressstreet, pa.suburbname as validaddresssuburb, 
            pa.postcode as validaddresspostcode, pa.principaladdresssiteoid as principaladdresssiteoid, 
            cas.community as community, ka.kyng as kyng,
            ST_AsGeoJSON(ST_Transform(pa.geom, 4326))::jsonb as geojson
        from public.project_addresspoints pa
        inner join community_areas cas on ST_Intersects(pa.geom, cas.geom) 
        inner join kyng_areas ka on ST_Intersects(pa.geom, ka.geom) 
        where pa.address in (select regexp_split_to_table(var_where_clause, ','))
    ),
    final_results AS (
        SELECT * FROM custom_address_results
        UNION ALL
        SELECT * FROM project_address_results
        WHERE NOT EXISTS (SELECT 1 FROM custom_address_results)
        UNION ALL
        SELECT 
            CASE 
                WHEN address_point_details IS NOT NULL 
                     AND (address_point_details->>'validaddressstreet' IS NOT NULL AND address_point_details->>'validaddressstreet' != '')
                     AND (address_point_details->>'validaddresssuburb' IS NOT NULL AND address_point_details->>'validaddresssuburb' != '')
                     AND (address_point_details->>'validaddresspostcode' IS NOT NULL AND address_point_details->>'validaddresspostcode' != '')
                     AND (address_point_details->>'principaladdresssiteoid' IS NOT NULL)
                     AND (address_point_details->>'community' IS NOT NULL AND address_point_details->>'community' != '')
                     AND (address_point_details->>'kyng' IS NOT NULL AND address_point_details->>'kyng' != '')
                THEN 200
                WHEN address_point_details IS NOT NULL 
                     AND (address_point_details->>'validaddressstreet' IS NOT NULL AND address_point_details->>'validaddressstreet' != '')
                     AND (address_point_details->>'validaddresssuburb' IS NOT NULL AND address_point_details->>'validaddresssuburb' != '')
                     AND (address_point_details->>'validaddresspostcode' IS NOT NULL AND address_point_details->>'validaddresspostcode' != '')
                     AND (address_point_details->>'principaladdresssiteoid' IS NOT NULL)
                THEN 404
                ELSE 403
            END AS status,
            address_text AS searchaddressstreet,
            given_suburb AS searchaddresssuburb,
            COALESCE((address_point_details->>'validaddressstreet')::text, '') AS validaddressstreet,
            COALESCE((address_point_details->>'validaddresssuburb')::text, '') AS validaddresssuburb,
            COALESCE((address_point_details->>'validaddresspostcode')::text, '') AS validaddresspostcode,
            COALESCE((address_point_details->>'principaladdresssiteoid')::integer, -1) AS principaladdresssiteoid,
            COALESCE((address_point_details->>'community')::text, '') AS community,
            COALESCE((address_point_details->>'kyng')::text, '') AS kyng,
            COALESCE(
                (address_point_details->>'geom')::jsonb,
                ST_AsGeoJSON(ST_Transform(ST_SetSRID(ST_Point(0, 0), 7844), 4326))::jsonb
            ) as geojson
        WHERE NOT EXISTS (SELECT 1 FROM custom_address_results)
        AND NOT EXISTS (SELECT 1 FROM project_address_results)
    )
    SELECT * FROM final_results LIMIT 1;
end
$$;


