CREATE OR REPLACE VIEW "public"."_kyng_edge_classification" AS
 WITH "bnd" AS (
         SELECT "kyng_areas"."kyng",
            ("extensions"."st_dump"("extensions"."st_boundary"("kyng_areas"."geom")))."geom" AS "line"
           FROM "public"."kyng_areas"
        ), "cad" AS (
         SELECT "extensions"."st_union"("extensions"."st_boundary"("project_properties"."geom")) AS "line"
           FROM "public"."project_properties"
        )
 SELECT "b"."kyng",
    "round"(("extensions"."st_length"(("b"."line")::"extensions"."geography"))::numeric, 1) AS "edge_len_m",
    "round"(("extensions"."st_length"(("extensions"."st_intersection"(("extensions"."st_buffer"(("c"."line")::"extensions"."geography", (0.5)::double precision))::"extensions"."geometry", "b"."line"))::"extensions"."geography"))::numeric, 1) AS "along_cadastre_m"
   FROM ("bnd" "b"
     CROSS JOIN "cad" "c");


ALTER VIEW "public"."_kyng_edge_classification" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."_kyng_snap_review_cases" AS
 WITH "pp" AS (
         SELECT "project_properties"."id",
            "project_properties"."address",
            "project_properties"."geom"
           FROM "public"."project_properties"
        ), "ka" AS (
         SELECT "kyng_areas"."kyng",
            "kyng_areas"."geom"
           FROM "public"."kyng_areas"
        ), "splits" AS (
         SELECT "p"."id",
            "p"."address",
            "k"."kyng",
            "extensions"."st_area"(("extensions"."st_intersection"("p"."geom", "k"."geom"))::"extensions"."geography") AS "m2_in"
           FROM ("pp" "p"
             JOIN "ka" "k" ON ("extensions"."st_intersects"("p"."geom", "k"."geom")))
        )
 SELECT "id",
    "address",
    "array_agg"("kyng" ORDER BY "m2_in" DESC) AS "kyngs_touched",
    "array_agg"("round"(("m2_in")::numeric, 1) ORDER BY "m2_in" DESC) AS "m2_per_kyng"
   FROM "splits"
  GROUP BY "id", "address"
 HAVING ("count"(*) FILTER (WHERE ("m2_in" > (100)::double precision)) >= 2)
  ORDER BY ( SELECT "max"("s"."m2_in") AS "max"
           FROM "splits" "s"
          WHERE ("s"."id" = "splits"."id")) DESC;


ALTER VIEW "public"."_kyng_snap_review_cases" OWNER TO "postgres";


