CREATE OR REPLACE VIEW "public"."kyng_bootawa_dam_road_property_fragment_view" AS
 WITH "this_kyng" AS MATERIALIZED (
         SELECT "extensions"."st_union"("kyng_areas"."geom") AS "geom"
           FROM "public"."kyng_areas"
          WHERE ("kyng_areas"."kyng" = 'Bootawa Dam Road'::"text")
        ), "primary_props" AS (
         SELECT DISTINCT ON ("project_properties"."gurasid") "project_properties"."gurasid",
            "project_properties"."address" AS "primary_address",
            "project_properties"."valnetpropertystatus",
            "project_properties"."valnetpropertytype",
            "project_properties"."geom"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Primary'::"text")
        ), "parts" AS (
         SELECT "pp"."gurasid",
            "pp"."primary_address",
            "pp"."valnetpropertystatus",
            "pp"."valnetpropertytype",
            ("extensions"."st_dump"("pp"."geom"))."geom" AS "part_geom"
           FROM "primary_props" "pp"
        ), "parts_in_this_kyng" AS (
         SELECT "pt"."gurasid",
            "pt"."primary_address",
            "pt"."valnetpropertystatus",
            "pt"."valnetpropertytype",
            "pt"."part_geom"
           FROM "parts" "pt"
          WHERE "extensions"."st_covers"(( SELECT "this_kyng"."geom"
                   FROM "this_kyng"), "extensions"."st_pointonsurface"("pt"."part_geom"))
        ), "parent_kyng_for_property" AS (
         SELECT "pp"."gurasid",
            "ka"."kyng" AS "parent_kyng"
           FROM ("primary_props" "pp"
             LEFT JOIN "public"."kyng_areas" "ka" ON ("extensions"."st_covers"("ka"."geom", "extensions"."st_pointonsurface"("pp"."geom"))))
        ), "secondary_aggr" AS (
         SELECT "project_properties"."gurasid",
            "string_agg"(DISTINCT "project_properties"."address", '
'::"text" ORDER BY "project_properties"."address") AS "secondary_addresses"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Secondary'::"text")
          GROUP BY "project_properties"."gurasid"
        ), "alternate_aggr" AS (
         SELECT "project_properties"."gurasid",
            "string_agg"(DISTINCT "project_properties"."address", '
'::"text" ORDER BY "project_properties"."address") AS "alternate_addresses"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Alternate'::"text")
          GROUP BY "project_properties"."gurasid"
        ), "collected" AS (
         SELECT "pit"."gurasid",
            "pit"."primary_address",
            "pit"."valnetpropertystatus",
            "pit"."valnetpropertytype",
            "extensions"."st_multi"("extensions"."st_collect"("pit"."part_geom")) AS "geom",
            ("sum"("extensions"."st_area"("extensions"."st_transform"("pit"."part_geom", 3577))))::integer AS "fragments_area_m2",
            ("count"(*))::integer AS "part_count"
           FROM "parts_in_this_kyng" "pit"
          GROUP BY "pit"."gurasid", "pit"."primary_address", "pit"."valnetpropertystatus", "pit"."valnetpropertytype"
        )
 SELECT ("row_number"() OVER (ORDER BY "c"."gurasid"))::integer AS "rowid",
    "c"."gurasid",
    "c"."part_count",
    "c"."primary_address" AS "parent_primary_address",
    "pk"."parent_kyng",
    COALESCE("sa"."secondary_addresses", ''::"text") AS "secondary_addresses",
    COALESCE("aa"."alternate_addresses", ''::"text") AS "alternate_addresses",
    "c"."valnetpropertystatus",
    "c"."valnetpropertytype",
    "c"."fragments_area_m2",
    "c"."geom"
   FROM ((("collected" "c"
     JOIN "parent_kyng_for_property" "pk" USING ("gurasid"))
