CREATE OR REPLACE VIEW "public"."kyng_bootawa_dam_road_property_view" AS
 WITH "this_kyng" AS MATERIALIZED (
         SELECT "extensions"."st_union"("kyng_areas"."geom") AS "geom"
           FROM "public"."kyng_areas"
          WHERE ("kyng_areas"."kyng" = 'Bootawa Dam Road'::"text")
        ), "other_kyngs" AS MATERIALIZED (
         SELECT "extensions"."st_union"("kyng_areas"."geom") AS "geom"
           FROM "public"."kyng_areas"
          WHERE ("kyng_areas"."kyng" <> 'Bootawa Dam Road'::"text")
        ), "unique_gurasid" AS (
         SELECT DISTINCT ON ("project_properties"."gurasid") "project_properties"."gurasid",
            "project_properties"."address",
            "project_properties"."valnetpropertystatus",
            "project_properties"."valnetpropertytype",
            "project_properties"."geom"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Primary'::"text")
        )
 SELECT ("row_number"() OVER ())::integer AS "rowid",
    "ug"."gurasid",
    "ug"."address",
    "count"("ug"."address") OVER (PARTITION BY "ug"."address") AS "address_count",
    "ug"."valnetpropertystatus",
    "ug"."valnetpropertytype",
    'Primary'::"text" AS "principaladdresstype",
    COALESCE("string_agg"(DISTINCT "alternate_subquery"."alternate_address", '
'::"text"), ''::"text") AS "alternate_addresses",
    COALESCE("string_agg"(DISTINCT "secondary_subquery"."secondary_address", '
'::"text"), ''::"text") AS "secondary_addresses",
    "ug"."geom",
    ("extensions"."st_area"(("extensions"."st_intersection"("extensions"."st_difference"("ug"."geom", ( SELECT "this_kyng"."geom"
           FROM "this_kyng")), ( SELECT "other_kyngs"."geom"
           FROM "other_kyngs")))::"extensions"."geography") > (100)::double precision) AS "crosses_boundary"
   FROM ((("unique_gurasid" "ug"
     LEFT JOIN ( SELECT "project_properties"."gurasid",
            "project_properties"."address" AS "alternate_address"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Alternate'::"text")) "alternate_subquery" ON (("ug"."gurasid" = "alternate_subquery"."gurasid")))
     LEFT JOIN ( SELECT "project_properties"."gurasid",
            "project_properties"."address" AS "secondary_address"
           FROM "public"."project_properties"
          WHERE ("project_properties"."principaladdresstype" = 'Secondary'::"text")) "secondary_subquery" ON (("ug"."gurasid" = "secondary_subquery"."gurasid")))
     CROSS JOIN LATERAL ( SELECT DISTINCT ON ("p"."gurasid") "p"."id",
            "p"."propertyoid",
            "p"."propertytype",
            "p"."valnetpropertystatus",
            "p"."valnetpropertytype",
            "p"."dissolveparcelcount",
