           FROM "public"."project_properties" "p"
          WHERE "extensions"."st_covers"(''::"extensions"."geometry", "extensions"."st_pointonsurface"("p"."geom"))) "filtered")
  WHERE ("ug"."gurasid" = "filtered"."gurasid")
